INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cb5e3c98b0941765a8e', '交通很方便，楼下就有地铁，叫车也很方便，酒店服务员很多，都很热情。记得不要错过瀑布花园，漫步一下很漂亮，小朋友可以带点面包或饼干喂鱼哦！', '["https://dimg04.c-ctrip.com/images/0230d12000d92nq1n97AF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233m12000d939xa4E414_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-20', '花园双床房', '双床房', '家庭亲子', 68, 4.23410650459726, 0, 0.0, 4, 1.6094379124341005, 8, '["交通便利性", "周边配套", "前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务', '未知酒店', '未知地点', '匿名', '交通很方便，楼下就有地铁，叫车也很方便，酒店服务员很多，都很热情。记得不要错过瀑', '交通很方便，楼下就有地铁，叫车也很方便，酒店服务员很多，都很热情。记得不要错过瀑布花园，漫步一下很漂亮，小朋友可以带点面包或饼干喂鱼哦！', '2024-02-20', 5, '交通便利性');
