INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cb5e3c98b0941765a90', '有回家的感觉，休息得很好', '["https://dimg04.c-ctrip.com/images/0236r324x8v34es8951A8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02309324x8v34es8aC377_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-06-03', '花园大床房', '大床房', '商务出差', 12, 2.5649493574615367, 0, 0.0, 16, 2.833213344056216, 4, '["整体满意度", "安静程度"]'::jsonb, '整体满意度', '安静程度', NULL, '未知酒店', '未知地点', '匿名', '有回家的感觉，休息得很好', '有回家的感觉，休息得很好', '2024-06-03', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cb5e3c98b0941765a91', '总体来说有达到期望 甚至超乎想象 花园酒店经久不衰  地铁就在门口 这点非常重要 广州酒家也在马路对面 但花园酒店的桃园馆更胜一筹（如果不考虑价格） 房间不大 我原来定的花园大床房 前台为了让我及时入住换成新装修的低楼层房间 会看到修路工地 这点比较失望 还有浴室设计偏小 私密性较不足 其实浴缸可以不要设置 对两人入住的不中用 洗脸盆就在离床头不远 无遮拦 如果一人先起床 还是会影响 可以忽略 早餐很丰盛 服务很好', '["https://dimg04.c-ctrip.com/images/0231x12000cusxhg2E850_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235812000cusuka67DE2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000cusw4kn6AE0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000cusuib750FD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h12000cusvy2c20F1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232z12000cusyeve948E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230v12000cusubjyE907_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230j12000cuslwhrF849_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232512000custti9850C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-03', '花园大床房', '大床房', '家庭亲子', 209, 5.3471075307174685, 0, 0.0, 11, 2.4849066497880004, 8, '["交通便利性", "周边配套", "房间设施"]'::jsonb, '交通便利性', '周边配套', '房间设施', '未知酒店', '未知地点', '匿名', '总体来说有达到期望 甚至超乎想象 花园酒店经久不衰  地铁就在门口 这点非常重要', '总体来说有达到期望 甚至超乎想象 花园酒店经久不衰  地铁就在门口 这点非常重要 广州酒家也在马路对面 但花园酒店的桃园馆更胜一筹（如果不考虑价格） 房间不大 我原来定的花园大床房 前台为了让我及时入住换成新装修的低楼层房间 会看到修路工地 这点比较失望 还有浴室设计偏小 私密性较不足 其实浴缸可以不要设置 对两人入住的不中用 洗脸盆就在离床头不远 无遮拦 如果一人先起床 还是会影响 可以忽略 早餐很丰盛 服务很好', '2024-01-03', 5, '交通便利性');
