，酒店大厅有颗大大得圣诞树小朋友很喜欢，外面有个后花园。
低层楼电视机无法投屏，房间里灯不是很亮，浴缸很大，外出一天可以给孩子泡澡', '2024-01-01', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cb5e3c98b0941765a93', '老牌五星酒店，设施确实有些老旧了，房间小也确实小，有些日式的设计感。门口迎宾服务素质参差不齐，有一个歪果仁迎宾似乎不太主动，看着我们抱着娃拎着箱子和小推车上台阶，也不会主动过来帮我们。其他服务员都非常热情，非常友好且主动。有个做气球的服务生非常会逗小朋友开心。
瀑布花园设计很值得一看，池子里的锦鲤令人心情愉悦，希望好运加持。', '["https://dimg04.c-ctrip.com/images/0235c12000cv78xpj6EA9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233z12000cv766ee36BA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236j12000cv7p7c3FB6D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233z12000cv7mfm1F910_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000cv7j91qCC89_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000cv7lbvmA709_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000cv7gonyDC60_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000cv7ik5mE1A6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-01-05', '花园大床房', '大床房', '家庭亲子', 163, 5.099866427824199, 0, 0.0, 7, 2.079441541679836, 8, '["房间设施", "前台服务", "整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '老牌五星酒店，设施确实有些老旧了，房间小也确实小，有些日式的设计感。门口迎宾服务', '老牌五星酒店，设施确实有些老旧了，房间小也确实小，有些日式的设计感。门口迎宾服务素质参差不齐，有一个歪果仁迎宾似乎不太主动，看着我们抱着娃拎着箱子和小推车上台阶，也不会主动过来帮我们。其他服务员都非常热情，非常友好且主动。有个做气球的服务生非常会逗小朋友开心。
瀑布花园设计很值得一看，池子里的锦鲤令人心情愉悦，希望好运加持。', '2024-01-05', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cc0e3c98b0941765a94', '套房非常满意，酒店很有文化底蕴。服务也很好。送入住点心和水果。还送了小羊。就是瀑布的自助餐实在是一般，大年三十588的自助实在是没啥好吃的。', '["https://dimg04.c-ctrip.com/images/0230o12000d6fji8qE318_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000d6fh3b3A55B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231712000d6fh3b58849_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-11', '羊羊得意主题大床房', '主题房', '家庭亲子', 70, 4.262679877041316, 0, 0.0, 35, 3.58351893845611, 7, '["餐饮设施", "整体满意度", "客房服务"]'::jsonb, '餐饮设施', '整体满意度', '客房服务', '未知酒店', '未知地点', '匿名', '套房非常满意，酒店很有文化底蕴。服务也很好。送入住点心和水果。还送了小羊。就是瀑', '套房非常满意，酒店很有文化底蕴。服务也很好。送入住点心和水果。还送了小羊。就是瀑布的自助餐实在是一般，大年三十588的自助实在是没啥好吃的。', '2024-02-11', 5, '餐饮设施');
