INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cc0e3c98b0941765a96', '刚入住就发现瓜子皮，根本没有服务。空调是坏的。刚进房间就发现马桶也没说。不想评价了。要是想体验服务和环境的建议别定，不值一千多。唯一亮点可能就是瀑布餐厅。', '["https://dimg04.c-ctrip.com/images/0234b12000d2ylkxtA8CA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236312000d2y6i2g725D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2024-01-30', '花园双床房', '双床房', '商务出差', 77, 4.356708826689592, 0, 0.0, 3, 1.3862943611198906, 6, '["房间设施", "卫生状况", "性价比"]'::jsonb, '房间设施', '卫生状况', '性价比', '未知酒店', '未知地点', '匿名', '刚入住就发现瓜子皮，根本没有服务。空调是坏的。刚进房间就发现马桶也没说。不想评价', '刚入住就发现瓜子皮，根本没有服务。空调是坏的。刚进房间就发现马桶也没说。不想评价了。要是想体验服务和环境的建议别定，不值一千多。唯一亮点可能就是瀑布餐厅。', '2024-01-30', 3, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cc0e3c98b0941765a97', '设施：不愧是白金五星级酒店，酒店大堂非常富力堂皇且浪漫??，设计感超赞。
服务：老牌的星级酒店服务专业到位，上上下下没一位工作人员都耐心细致，过来庆祝结婚38年纪念的，酒店给升级了房间，前台给了鲜花，房间做了漂亮布置，送了蛋糕，真是惊喜到了，在此感谢每一位用心的工作人员。', '["https://dimg04.c-ctrip.com/images/0230q12000ctz1s6o0101_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000ctz3u881A54_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-30', '花园双床房', '双床房', '情侣出游', 137, 4.927253685157205, 0, 0.0, 24, 3.218875824868201, 9, '["前台服务", "整体满意度", "房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '设施：不愧是白金五星级酒店，酒店大堂非常富力堂皇且浪漫??，设计感超赞。', '设施：不愧是白金五星级酒店，酒店大堂非常富力堂皇且浪漫??，设计感超赞。
服务：老牌的星级酒店服务专业到位，上上下下没一位工作人员都耐心细致，过来庆祝结婚38年纪念的，酒店给升级了房间，前台给了鲜花，房间做了漂亮布置，送了蛋糕，真是惊喜到了，在此感谢每一位用心的工作人员。', '2023-12-30', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cc0e3c98b0941765a98', '公共区域设计标准高、用材好，结合了国内传统文化，很前沿，相信多年后也不会落伍。
酒店内米其林3家，美食很棒！
