INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cc0e3c98b0941765a99', '不愧是第一个白金五星酒店，装潢和服务都很棒，适合喜欢探索一下岭南文化的旅行者。唯一美中不足就是房间里面充电的地方不够多，以及吹风机真的很难用，应该提升一下设备便利度，才不愧这么好的环境和服务。', '["https://dimg04.c-ctrip.com/images/0235k12000cvtcgkz4D33_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234y12000cvth3ua123E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000cvtdslyCEE7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231l12000cvtf5vg1EC4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-01-07', '红棉双床套房', '套房', '朋友出游', 96, 4.574710978503383, 0, 0.0, 9, 2.302585092994046, 8, '["房间设施", "整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '不愧是第一个白金五星酒店，装潢和服务都很棒，适合喜欢探索一下岭南文化的旅行者。唯', '不愧是第一个白金五星酒店，装潢和服务都很棒，适合喜欢探索一下岭南文化的旅行者。唯一美中不足就是房间里面充电的地方不够多，以及吹风机真的很难用，应该提升一下设备便利度，才不愧这么好的环境和服务。', '2024-01-07', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cc0e3c98b0941765a9a', '酒店大堂背景很震撼，房间重新装修过，外面花园也很精致；台前巴基斯坦小哥DASTAAN人很nice，普通话流利，有求必应，值得推荐！', '["https://dimg04.c-ctrip.com/images/0230512000d8uce936FE9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231k12000d8ucybo2CEA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-19', '花园双床房', '双床房', '朋友出游', 65, 4.189654742026425, 0, 0.0, 6, 1.9459101490553128, 8, '["前台服务", "整体满意度", "房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '酒店大堂背景很震撼，房间重新装修过，外面花园也很精致；台前巴基斯坦小哥DASTA', '酒店大堂背景很震撼，房间重新装修过，外面花园也很精致；台前巴基斯坦小哥DASTAAN人很nice，普通话流利，有求必应，值得推荐！', '2024-02-19', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cc0e3c98b0941765a9b', '白金级酒店真没选错。虽然设施是旧了点，可是老牌星级酒店的服务真是不错，很专业的。很喜欢酒店的大厅，红楼梦巨型背景墙好有感觉，酒店的下午茶还行，最好看的就是瀑布背景，设计感超赞。酒店的位置也很好，出门右边就是地铁站，出行非常方便。', '["https://dimg04.c-ctrip.com/images/0235712000ctroyzrBA55_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235j12000ctrq5oo0F6D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000ctrg2q454D8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-29', '花园双床房', '双床房', '朋友出游', 114, 4.74493212836325, 0, 0.0, 17, 2.8903717578961645, 8, '["交通便利性", "整体满意度", "前台服务"]'::jsonb, '交通便利性', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '白金级酒店真没选错。虽然设施是旧了点，可是老牌星级酒店的服务真是不错，很专业的。', '白金级酒店真没选错。虽然设施是旧了点，可是老牌星级酒店的服务真是不错，很专业的。很喜欢酒店的大厅，红楼梦巨型背景墙好有感觉，酒店的下午茶还行，最好看的就是瀑布背景，设计感超赞。酒店的位置也很好，出门右边就是地铁站，出行非常方便。', '2023-12-29', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cc0e3c98b0941765a9c', '又体验了另外的一种房型，虽然老，感觉比新装修的更好，空间高舒适些。各个餐厅也各有特色，瀑布餐厅偏西式，精致粤菜料理在桃园馆。老牌米其林的荔湾亭特别怀旧，西关风情浓，菜品精致，不渗假水。4楼的博物馆更是值得看看，珍藏有邓爷爷的墨宝…', '["https://dimg04.c-ctrip.com/images/0230l12000chi0nafC7B3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233m12000chhyp7iBCA1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231i12000chi6fvn7380_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o12000chhuu37D223_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000chhvp97A2C6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231l12000chhy418132B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234i12000chi3el176FF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235j12000chi5gz3CC85_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000chi5iev32D2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-31', '红棉大床套房', '套房', '情侣出游', 115, 4.7535901911063645, 0, 0.0, 114, 4.74493212836325, 9, '["餐饮设施", "整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '又体验了另外的一种房型，虽然老，感觉比新装修的更好，空间高舒适些。各个餐厅也各有', '又体验了另外的一种房型，虽然老，感觉比新装修的更好，空间高舒适些。各个餐厅也各有特色，瀑布餐厅偏西式，精致粤菜料理在桃园馆。老牌米其林的荔湾亭特别怀旧，西关风情浓，菜品精致，不渗假水。4楼的博物馆更是值得看看，珍藏有邓爷爷的墨宝…', '2023-10-31', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cc0e3c98b0941765a9d', '最大的问题是房间面积小有点旧，服务非常好，大堂金碧辉煌很是气派，后花园的瀑布和环境是其他广州酒店不能比的，整个酒店到处洋溢着浓浓的春节气氛。', '["https://dimg04.c-ctrip.com/images/0235z12000d60ug776CC7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232j12000d60sundDFC5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234e12000d60tq4uEB8C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230k12000d60thpj5963_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-02-09', '城央绿意双床房', '双床房', '家庭亲子', 70, 4.262679877041316, 0, 0.0, 6, 1.9459101490553128, 8, '["房间设施", "整体满意度", "公共设施"]'::jsonb, '房间设施', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '最大的问题是房间面积小有点旧，服务非常好，大堂金碧辉煌很是气派，后花园的瀑布和环', '最大的问题是房间面积小有点旧，服务非常好，大堂金碧辉煌很是气派，后花园的瀑布和环境是其他广州酒店不能比的，整个酒店到处洋溢着浓浓的春节气氛。', '2024-02-09', 4, '房间设施');
