INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ccde3c98b0941765aa0', '五星级酒店。竞然没有夜床服务、太奇怪了??3天没有一次夜床服务。花园酒店生意太好省下了。第一天入住。2010房、洗澡间的水浸入到卫生间没法使用。换房间后。18 08。从服务员到主管没人对此说一声对不起。哈哈花园酒店牛。????????。', '["https://dimg04.c-ctrip.com/images/0233312000ctwbhvmC4EE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000ctwa7i3799A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235r12000ctwa0th7A48_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-12-30', '花园大床房', '大床房', '独自旅行', 118, 4.77912349311153, 2, 1.0986122886681098, 5, 1.791759469228055, 6, '["客房服务", "房间设施", "前台服务"]'::jsonb, '客房服务', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '五星级酒店。竞然没有夜床服务、太奇怪了??3天没有一次夜床服务。花园酒店生意太好', '五星级酒店。竞然没有夜床服务、太奇怪了??3天没有一次夜床服务。花园酒店生意太好省下了。第一天入住。2010房、洗澡间的水浸入到卫生间没法使用。换房间后。18 08。从服务员到主管没人对此说一声对不起。哈哈花园酒店牛。????????。', '2023-12-30', 4, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ccde3c98b0941765aa1', '老牌5星，感受最深的是，花园想做文创酒店，有自己的博物馆，有古仔讲。床品舒适，早餐建议桃园厅或者荔湾亭，一楼瀑布厅适合外国人的口味，主厨好像是西班牙的，中式茶点比2，3楼差好远。西点OK。', '["https://dimg04.c-ctrip.com/images/0230z12000cx64iy65988_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231s12000cx5dj6635FE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-12', '粤韵双床套房', '套房', '家庭亲子', 94, 4.553876891600541, 0, 0.0, 18, 2.9444389791664403, 8, '["餐饮设施", "整体满意度", "房间设施"]'::jsonb, '餐饮设施', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '老牌5星，感受最深的是，花园想做文创酒店，有自己的博物馆，有古仔讲。床品舒适，早', '老牌5星，感受最深的是，花园想做文创酒店，有自己的博物馆，有古仔讲。床品舒适，早餐建议桃园厅或者荔湾亭，一楼瀑布厅适合外国人的口味，主厨好像是西班牙的，中式茶点比2，3楼差好远。西点OK。', '2024-01-12', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ccde3c98b0941765aa2', '早就久闻花园酒店大名，这次来广州终于有机会入住。酒店到处摆满了鲜花，萦绕在鲜花中心情很好。最近适逢广交会，办理入住的人稍多，工作人员会准备小饼干和饮料给客人排队间隙等待时享用。感谢前台给我们升级了房型，入住的是粤韵客房。来得匆忙忘带手机充电线了，跟工作人员一说很快就送到了。本来担心浴缸会不干净但是发现自己想多了，卫生搞得还是很不错的。还去了酒店内的博物馆参观，这是一家讲述有关住宿业的博物馆，挺有新意的。酒店环境令人舒适满意，下次来广州还要入住！', '["https://dimg04.c-ctrip.com/images/0231l12000chmyeza85BC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000chmsk0nDA8A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c12000chn1ig39658_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000chmsk0pBA5F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000chmzent4F62_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231d12000chmtp29FD02_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235212000chn4mteBE61_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234812000chn1ig5D012_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000chmwy3f9CCA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-31', '红棉大床套房', '套房', '家庭亲子', 224, 5.41610040220442, 1, 0.6931471805599453, 3, 1.3862943611198906, 9, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '早就久闻花园酒店大名，这次来广州终于有机会入住。酒店到处摆满了鲜花，萦绕在鲜花中', '早就久闻花园酒店大名，这次来广州终于有机会入住。酒店到处摆满了鲜花，萦绕在鲜花中心情很好。最近适逢广交会，办理入住的人稍多，工作人员会准备小饼干和饮料给客人排队间隙等待时享用。感谢前台给我们升级了房型，入住的是粤韵客房。来得匆忙忘带手机充电线了，跟工作人员一说很快就送到了。本来担心浴缸会不干净但是发现自己想多了，卫生搞得还是很不错的。还去了酒店内的博物馆参观，这是一家讲述有关住宿业的博物馆，挺有新意的。酒店环境令人舒适满意，下次来广州还要入住！', '2023-10-31', 5, '整体满意度');
