INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ccde3c98b0941765aa4', '酒店位置在市区，位置很好，去附近的景点都很方便。 酒店房间干净，整洁，床品舒服柔软， 入住体验非常棒。重点表扬酒店的服务，因为飞机晚点到店时间特别晚，前台小姐姐帮忙升级了房型还延迟了退房； 另外LiVen 热情细致的协助我们解决各种在酒店遇到的问题，真的超贴心。', '["https://dimg04.c-ctrip.com/images/0237412000jqv5xek8E04_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232e12000jqvxz6b345C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235b12000jqwi2aeB014_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234i12000jqvuddv4996_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230112000jqv5xemDFF8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-12', '花园大床房', '大床房', '独自旅行', 131, 4.882801922586371, 0, 0.0, 25, 3.258096538021482, 9, '["前台服务", "整体满意度", "交通便利性"]'::jsonb, '前台服务', '整体满意度', '交通便利性', '未知酒店', '未知地点', '匿名', '酒店位置在市区，位置很好，去附近的景点都很方便。 酒店房间干净，整洁，床品舒服柔', '酒店位置在市区，位置很好，去附近的景点都很方便。 酒店房间干净，整洁，床品舒服柔软， 入住体验非常棒。重点表扬酒店的服务，因为飞机晚点到店时间特别晚，前台小姐姐帮忙升级了房型还延迟了退房； 另外LiVen 热情细致的协助我们解决各种在酒店遇到的问题，真的超贴心。', '2025-04-12', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ccde3c98b0941765aa5', '很不错 每位服务人员都非常热情 房型也很好 带上妈妈爸爸和小朋友一起 每个人都很开心 小朋友可以喂鱼 爸爸妈妈觉得酒店也很好 准备以后去广州都住这里', '["https://dimg04.c-ctrip.com/images/0232112000d4gbwxaE78E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000d4gpgq14A99_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-04', '花园双床房', '双床房', '家庭亲子', 74, 4.31748811353631, 0, 0.0, 4, 1.6094379124341005, 6, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '很不错 每位服务人员都非常热情 房型也很好 带上妈妈爸爸和小朋友一起 每个人都很', '很不错 每位服务人员都非常热情 房型也很好 带上妈妈爸爸和小朋友一起 每个人都很开心 小朋友可以喂鱼 爸爸妈妈觉得酒店也很好 准备以后去广州都住这里', '2024-02-04', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ccde3c98b0941765aa6', '第二次住花园了，整体环境还是很好的，就是这次行政酒廊搬到了楼上旋转餐厅分出来的一块地方，感觉还是一楼原来酒吧的位置更舒服还有室外位环境也好，楼上除了晚上能看到一点点广州塔没有什么风景，地方小也显得很局促，不知道是不是心理作用现在下午茶和happyhour没有在楼下时候丰富了，早餐也纯自助了以前在楼下还可以点单的，和一楼的瀑布早餐就没啥差别了。房间还是比较满意的岭客金卡给升了级，
服务：有一天牙疼在休息中午楼上不知道哪里在装修电钻声特别吵，打电话让前台沟通下等我们退房再钻，就这一件事反复打了四五个电话等了半小时才得到解决，本来想待到12点走不得不提前走了，这点让人不是很愉快', '["https://dimg04.c-ctrip.com/images/0236d12000cugpn1c1664_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230c12000cugou3t74F8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000cugl0t01831_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-01', '花园双床房', '双床房', '情侣出游', 289, 5.66988092298052, 0, 0.0, 4, 1.6094379124341005, 8, '["餐饮设施", "安静程度", "前台服务"]'::jsonb, '餐饮设施', '安静程度', '前台服务', '未知酒店', '未知地点', '匿名', '第二次住花园了，整体环境还是很好的，就是这次行政酒廊搬到了楼上旋转餐厅分出来的一', '第二次住花园了，整体环境还是很好的，就是这次行政酒廊搬到了楼上旋转餐厅分出来的一块地方，感觉还是一楼原来酒吧的位置更舒服还有室外位环境也好，楼上除了晚上能看到一点点广州塔没有什么风景，地方小也显得很局促，不知道是不是心理作用现在下午茶和happyhour没有在楼下时候丰富了，早餐也纯自助了以前在楼下还可以点单的，和一楼的瀑布早餐就没啥差别了。房间还是比较满意的岭客金卡给升了级，
服务：有一天牙疼在休息中午楼上不知道哪里在装修电钻声特别吵，打电话让前台沟通下等我们退房再钻，就这一件事反复打了四五个电话等了半小时才得到解决，本来想待到12点走不得不提前走了，这点让人不是很愉快', '2024-01-01', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ccde3c98b0941765aa7', '酒店很高大上，入住正是圣诞节，一棵大大的圣诞树??装饰的很华丽。酒店的早餐环境非常有特色，大大的玻璃窗可以看到室外的瀑布，在这里就餐心情愉悦，早餐品种丰富多样，口味也不错??，连住两晚，第二天体验了三十层旋转餐厅的早餐，相比较而言更喜欢一口的环境。只可惜原本的下午茶??，2点退房后不可以享用，白白的浪费掉了，不然，正好吃完下午茶赶往机场都有时间，要是办理入住时提醒一下就好了，算是小小的遗憾吧。', '["https://dimg04.c-ctrip.com/images/0232712000cwc3agu50AE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233h12000cwc34tcF0CE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230j12000cwc22e27529_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230h12000cwc38qyEFD3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-09', '花园双床房', '双床房', '情侣出游', 198, 5.293304824724492, 1, 0.6931471805599453, 1, 0.6931471805599453, 9, '["餐饮设施", "整体满意度", "前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '酒店很高大上，入住正是圣诞节，一棵大大的圣诞树??装饰的很华丽。酒店的早餐环境非', '酒店很高大上，入住正是圣诞节，一棵大大的圣诞树??装饰的很华丽。酒店的早餐环境非常有特色，大大的玻璃窗可以看到室外的瀑布，在这里就餐心情愉悦，早餐品种丰富多样，口味也不错??，连住两晚，第二天体验了三十层旋转餐厅的早餐，相比较而言更喜欢一口的环境。只可惜原本的下午茶??，2点退房后不可以享用，白白的浪费掉了，不然，正好吃完下午茶赶往机场都有时间，要是办理入住时提醒一下就好了，算是小小的遗憾吧。', '2024-01-09', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cd7e3c98b0941765aa8', '我们这次是带孩子去广州感受圣诞氛围的，酒店布置很漂亮，孩子也拍了很多美照！带着孩子去逛了酒店的博物馆，博物馆比较小，但酒店历史都浓缩在其中了！这次过去酒店最不好的体验是旁边在修地铁站，吵到没办法好好休息，晚上吵到十点多，早上不到八点就开工，这是这次出行最最不好的体验了！', '["https://dimg04.c-ctrip.com/images/0235c12000czs2u1e664A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233s12000czs5e17033C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234a12000czsjoez1074_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233u12000czs5fn86B65_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235912000czscavf7D00_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-01-21', '红棉大床套房', '套房', '家庭亲子', 135, 4.912654885736052, 0, 0.0, 5, 1.791759469228055, 8, '["安静程度", "周边配套", "整体满意度"]'::jsonb, '安静程度', '周边配套', '整体满意度', '未知酒店', '未知地点', '匿名', '我们这次是带孩子去广州感受圣诞氛围的，酒店布置很漂亮，孩子也拍了很多美照！带着孩', '我们这次是带孩子去广州感受圣诞氛围的，酒店布置很漂亮，孩子也拍了很多美照！带着孩子去逛了酒店的博物馆，博物馆比较小，但酒店历史都浓缩在其中了！这次过去酒店最不好的体验是旁边在修地铁站，吵到没办法好好休息，晚上吵到十点多，早上不到八点就开工，这是这次出行最最不好的体验了！', '2024-01-21', 4, '安静程度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cd7e3c98b0941765aa9', '非常满意的一次住宿，带着爸妈和孩子奔着老牌酒店去的，住了四晚，我们定了两间房，赶上广州降温，还特意给我们升级了套房，服务一级棒超五星体验，谁住谁知道????????', '["https://dimg04.c-ctrip.com/images/0236412000d2aq2b9EF0A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-28', '花园双床房', '双床房', '家庭亲子', 82, 4.418840607796598, 0, 0.0, 15, 2.772588722239781, 8, '["整体满意度", "前台服务"]'::jsonb, '整体满意度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '非常满意的一次住宿，带着爸妈和孩子奔着老牌酒店去的，住了四晚，我们定了两间房，赶', '非常满意的一次住宿，带着爸妈和孩子奔着老牌酒店去的，住了四晚，我们定了两间房，赶上广州降温，还特意给我们升级了套房，服务一级棒超五星体验，谁住谁知道????????', '2024-01-28', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cd7e3c98b0941765aaa', '春节旅程结束最后住花园酒店，体验很好，加钱升级了亲子房房间，小朋友很开心。整体服务都不错，唯一不好的是办理入住和早餐需要排队。', '["https://dimg04.c-ctrip.com/images/0233y12000d7zi4tgA279_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000d7zhr2199DF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000d7zgb160A9C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236n12000d7zi4u066C7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-16', '花园大床房', '大床房', '家庭亲子', 63, 4.158883083359672, 0, 0.0, 10, 2.3978952727983707, 7, '["整体满意度", "退房/入住效率", "餐饮设施"]'::jsonb, '整体满意度', '退房/入住效率', '餐饮设施', '未知酒店', '未知地点', '匿名', '春节旅程结束最后住花园酒店，体验很好，加钱升级了亲子房房间，小朋友很开心。整体服', '春节旅程结束最后住花园酒店，体验很好，加钱升级了亲子房房间，小朋友很开心。整体服务都不错，唯一不好的是办理入住和早餐需要排队。', '2024-02-16', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cd7e3c98b0941765aab', '干净、周到、环境优美，到处飘着花香，卫生间，床单茶具都非常干净。早餐美味，用餐环境好，安静。服务到位。', '["https://dimg04.c-ctrip.com/images/0230312000dd32ts690EE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232512000dd2by4d1CEE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000dd2yh64DC04_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x12000dd312ioAF13_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236w12000dd2xsb874A5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-07', '花园双床房', '双床房', '朋友出游', 51, 3.951243718581428, 0, 0.0, 4, 1.6094379124341005, 7, '["卫生状况", "餐饮设施", "安静程度"]'::jsonb, '卫生状况', '餐饮设施', '安静程度', '未知酒店', '未知地点', '匿名', '干净、周到、环境优美，到处飘着花香，卫生间，床单茶具都非常干净。早餐美味，用餐环', '干净、周到、环境优美，到处飘着花香，卫生间，床单茶具都非常干净。早餐美味，用餐环境好，安静。服务到位。', '2024-03-07', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cd7e3c98b0941765aac', '房间整洁，服务态度好！因为订房时比实际入住房价高赠送了早餐！早餐非常美味！酒店花园是真漂亮，花团锦簇，锦鲤小桥瀑布美不胜收。', '["https://dimg04.c-ctrip.com/images/0230z12000da2ymzbEE4E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000da2y9oeC912_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234s12000da2xyld5E48_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000da2yeoeD904_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234m12000da2xgq5FF40_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-24', '花园双床房', '双床房', '家庭亲子', 62, 4.143134726391533, 0, 0.0, 6, 1.9459101490553128, 8, '["整体满意度", "餐饮设施", "卫生状况"]'::jsonb, '整体满意度', '餐饮设施', '卫生状况', '未知酒店', '未知地点', '匿名', '房间整洁，服务态度好！因为订房时比实际入住房价高赠送了早餐！早餐非常美味！酒店花', '房间整洁，服务态度好！因为订房时比实际入住房价高赠送了早餐！早餐非常美味！酒店花园是真漂亮，花团锦簇，锦鲤小桥瀑布美不胜收。', '2024-02-24', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cd7e3c98b0941765aad', '因为觉得住的还挺好所以续房一天，酒店正好重新装修一部分房间，让我们搬到粤韵房了，这个房间更新一些，床也更舒适，瀑布餐厅酒店早餐还不错，还赠送了水果，对酒店其他服务还都是很满意的，酒店的博物馆也很值得一看。', '["https://dimg04.c-ctrip.com/images/0204r12000csf2ks81475_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0231i12000csf03so7D2A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000cset8ly26F0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233212000csewtkd9F80_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-24', '城央绿意大床房', '大床房', '家庭亲子', 102, 4.634728988229636, 0, 0.0, 79, 4.382026634673881, 7, '["房间设施", "整体满意度", "餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '因为觉得住的还挺好所以续房一天，酒店正好重新装修一部分房间，让我们搬到粤韵房了，', '因为觉得住的还挺好所以续房一天，酒店正好重新装修一部分房间，让我们搬到粤韵房了，这个房间更新一些，床也更舒适，瀑布餐厅酒店早餐还不错，还赠送了水果，对酒店其他服务还都是很满意的，酒店的博物馆也很值得一看。', '2023-12-24', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cd7e3c98b0941765aae', '酒店位置很好，服务热情周到，春节期间布置的也是非常喜庆，活动很多，还送了鲜花~房间干净整洁，床品舒适。早餐在旋转餐厅，还是比较丰富哒', '["https://dimg04.c-ctrip.com/images/0234o12000d91cgkm1725_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000d91bhwf13D3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-20', '花园双床房', '双床房', '家庭亲子', 66, 4.204692619390966, 0, 0.0, 14, 2.70805020110221, 7, '["整体满意度", "房间设施", "餐饮设施"]'::jsonb, '整体满意度', '房间设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店位置很好，服务热情周到，春节期间布置的也是非常喜庆，活动很多，还送了鲜花~房', '酒店位置很好，服务热情周到，春节期间布置的也是非常喜庆，活动很多，还送了鲜花~房间干净整洁，床品舒适。早餐在旋转餐厅，还是比较丰富哒', '2024-02-20', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cd7e3c98b0941765aaf', '交通便利，地铁站上来就是北门口。服务人员众多，随时随地都能得到有效的帮助。客房整洁干净，布草，洗漱用品，洗澡水压等都令人满意。冲着官方白金五星来的，发现名不虚传。上午到达，前台的南希快速高效的办理了加床加餐的入住，入住后才发现还帮我升级了房型，感谢。客房服务无论是加床，还是我们几次要求送水送用品，其反应速度都是我入住各类高奢酒店以来最快的。早餐的出品可以，员工翻台也是高效。酒店博物馆也值得一观。最后感谢客房服务员拾金不昧，在我自己都没发觉时，值班经理已经联系我，让我的黄金手串失而复得。感谢！', '["https://dimg04.c-ctrip.com/images/0231p12000d07p7pi3376_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230w12000d07p2xv9DB0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231e12000d07or8m01D3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234d12000d07p7po6B38_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231s12000d07p2xx7602_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a12000d07or8o5B7D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237112000d07p7pu7537_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232o12000d07p2xzC43A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000d07or8s7406_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-22', '红棉大床套房', '套房', '家庭亲子', 248, 5.517452896464707, 0, 0.0, 32, 3.49650756146648, 9, '["前台服务", "客房服务", "交通便利性"]'::jsonb, '前台服务', '客房服务', '交通便利性', '未知酒店', '未知地点', '匿名', '交通便利，地铁站上来就是北门口。服务人员众多，随时随地都能得到有效的帮助。客房整', '交通便利，地铁站上来就是北门口。服务人员众多，随时随地都能得到有效的帮助。客房整洁干净，布草，洗漱用品，洗澡水压等都令人满意。冲着官方白金五星来的，发现名不虚传。上午到达，前台的南希快速高效的办理了加床加餐的入住，入住后才发现还帮我升级了房型，感谢。客房服务无论是加床，还是我们几次要求送水送用品，其反应速度都是我入住各类高奢酒店以来最快的。早餐的出品可以，员工翻台也是高效。酒店博物馆也值得一观。最后感谢客房服务员拾金不昧，在我自己都没发觉时，值班经理已经联系我，让我的黄金手串失而复得。感谢！', '2024-01-22', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cd7e3c98b0941765ab0', '过年来玩 之前住过一次 这次带爸妈来 这个房型有一个客厅可以加床还蛮适合家庭出行的 瀑布餐厅服务很好 年夜饭提前预定的桃园馆也很好吃', '["https://dimg04.c-ctrip.com/images/0231212000d677jva130D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232e12000d66urw692C5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236r12000d674bfw299D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-10', '红棉双床套房', '套房', '家庭亲子', 66, 4.204692619390966, 0, 0.0, 18, 2.9444389791664403, 7, '["房间设施", "餐饮设施", "整体满意度"]'::jsonb, '房间设施', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '过年来玩 之前住过一次 这次带爸妈来 这个房型有一个客厅可以加床还蛮适合家庭出行', '过年来玩 之前住过一次 这次带爸妈来 这个房型有一个客厅可以加床还蛮适合家庭出行的 瀑布餐厅服务很好 年夜饭提前预定的桃园馆也很好吃', '2024-02-10', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cd7e3c98b0941765ab1', '时光荏苒，转眼间已是三年之隔，当我再次踏入广州花园酒店的大门，那份熟悉与温馨感油然而生，仿佛时间在这里悄然静止。酒店的服务依旧保持着那份一如既往的高水准，让人丝毫感觉不到岁月的流转。此次入住，我有幸遇到了前台的Niki小姐。她以花园酒店那标志性的热情笑容和细致入微的服务，瞬间驱散了我旅途的疲惫。在得知我是3年前入住过的客人后，Niki更是主动为我升级了房间至粤韵大床房，并贴心地赠送了两份早餐券。这份意外的惊喜，让我对酒店的好感倍增。另外值得一提的是，客房管家LiLi还特意准备了月饼和阳光玫瑰葡萄作为小礼物。这份意外的关怀，让我感受到了家的温暖。三年的时光并未改变花园酒店的品质与魅力，反而让它在我心中更加熠熠生辉。在未来的日子里，我还会再次选择这里，作为我旅途中的温馨港湾。', '["https://dimg04.c-ctrip.com/images/0234b12000eyimxt99FA6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000eyijk3c2551_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232k12000eyitdkz060C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234m12000eyivnhr670D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236q12000eyimk1vC170_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236j12000eyirguz1918_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-31', '花园大床房', '大床房', '商务出差', 340, 5.831882477283517, 0, 0.0, 10, 2.3978952727983707, 9, '["前台服务", "整体满意度", "客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务', '未知酒店', '未知地点', '匿名', '时光荏苒，转眼间已是三年之隔，当我再次踏入广州花园酒店的大门，那份熟悉与温馨感油', '时光荏苒，转眼间已是三年之隔，当我再次踏入广州花园酒店的大门，那份熟悉与温馨感油然而生，仿佛时间在这里悄然静止。酒店的服务依旧保持着那份一如既往的高水准，让人丝毫感觉不到岁月的流转。此次入住，我有幸遇到了前台的Niki小姐。她以花园酒店那标志性的热情笑容和细致入微的服务，瞬间驱散了我旅途的疲惫。在得知我是3年前入住过的客人后，Niki更是主动为我升级了房间至粤韵大床房，并贴心地赠送了两份早餐券。这份意外的惊喜，让我对酒店的好感倍增。另外值得一提的是，客房管家LiLi还特意准备了月饼和阳光玫瑰葡萄作为小礼物。这份意外的关怀，让我感受到了家的温暖。三年的时光并未改变花园酒店的品质与魅力，反而让它在我心中更加熠熠生辉。在未来的日子里，我还会再次选择这里，作为我旅途中的温馨港湾。', '2024-07-31', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ce2e3c98b0941765ab2', '酒店很漂亮 餐厅也多 服务还特别好 不愧是老牌酒店 下次还来', '["https://dimg04.c-ctrip.com/images/0235h12000dohjzdk737B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-15', '城央绿意大床房', '大床房', '商务出差', 30, 3.4339872044851463, 0, 0.0, 20, 3.044522437723423, 5, '["整体满意度", "餐饮设施", "前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '酒店很漂亮 餐厅也多 服务还特别好 不愧是老牌酒店 下次还来', '酒店很漂亮 餐厅也多 服务还特别好 不愧是老牌酒店 下次还来', '2024-04-15', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ce2e3c98b0941765ab3', '房间很大，不过没有浴缸，淋浴和洗漱区有点小，到不影响房间舒适和整洁
早餐区域是瀑布餐厅，吃早饭看美景很不错
酒店没有和瀑布，可以去逛逛，没人，景色很美', '["https://dimg04.c-ctrip.com/images/0230712000d2c65tc2C4F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234b12000d2c9m1n2A75_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000d2c6yopE381_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231m12000d2cadla8220_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-28', '花园双床房', '双床房', '家庭亲子', 75, 4.330733340286331, 0, 0.0, 11, 2.4849066497880004, 6, '["房间设施", "餐饮设施", "周边配套"]'::jsonb, '房间设施', '餐饮设施', '周边配套', '未知酒店', '未知地点', '匿名', '房间很大，不过没有浴缸，淋浴和洗漱区有点小，到不影响房间舒适和整洁', '房间很大，不过没有浴缸，淋浴和洗漱区有点小，到不影响房间舒适和整洁
早餐区域是瀑布餐厅，吃早饭看美景很不错
酒店没有和瀑布，可以去逛逛，没人，景色很美', '2024-01-28', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ce2e3c98b0941765ab4', '花园酒店，名副其实，酒店后花园的瀑布庭院还是蛮有气势的。不过酒店确实老了点，客房洗手台、淋浴房、卫生间布局感觉很不好，双人房半开放结构有干扰。', '["https://dimg04.c-ctrip.com/images/0230a12000dbzqsch8F1E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234912000dbzrjti79F1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000dbzrvsh7E86_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230w12000dbzr70e2570_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-03-03', '花园双床房', '双床房', '商务出差', 71, 4.276666119016055, 0, 0.0, 17, 2.8903717578961645, 7, '["房间设施", "景观/朝向"]'::jsonb, '房间设施', '景观/朝向', NULL, '未知酒店', '未知地点', '匿名', '花园酒店，名副其实，酒店后花园的瀑布庭院还是蛮有气势的。不过酒店确实老了点，客房', '花园酒店，名副其实，酒店后花园的瀑布庭院还是蛮有气势的。不过酒店确实老了点，客房洗手台、淋浴房、卫生间布局感觉很不好，双人房半开放结构有干扰。', '2024-03-03', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ce2e3c98b0941765ab5', '久违了，花园酒店，20几年前曾经住过，已经渐渐的淡忘了，此次来广州，查到花园酒店已经重新装修与改动了一些房型，便毫不犹豫的订了两晚。
花园酒店绝对的五星酒店中的翘楚，尽管是近40年前的产品，却是生机勃勃，老当益壮。
??论是房间的设施与硬件，都是超五星轻奢酒店标准，二楼的中餐厅环境也是一流的，特别是独特的的岭南风格的后花园（园林），那是人间仙境，白天迷人，夜晚诱人。
美中不足的是，大堂里飘散的香水味，也许选的不对我们的味觉，似乎??点澡堂子的味道，刺鼻而欠舒服。
若能下点功夫，调一下大堂香水味，让更多的客人喜欢，那么，来广州，花园酒店就是第一选择。', '["https://dimg04.c-ctrip.com/images/0204i12000crfm68t5395_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0231w12000crflcx1F60E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234k12000crfm9ca2B74_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000crflaqt3AA7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232l12000crfllao4868_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233n12000crflqvr6298_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234712000crflew11929_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235r12000crfm3otC819_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000crflxao9043_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f12000crfldvyC360_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-19', '红棉大床套房', '套房', '情侣出游', 278, 5.631211781821365, 0, 0.0, 66, 4.204692619390966, 9, '["房间设施", "整体满意度", "公共设施"]'::jsonb, '房间设施', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '久违了，花园酒店，20几年前曾经住过，已经渐渐的淡忘了，此次来广州，查到花园酒店', '久违了，花园酒店，20几年前曾经住过，已经渐渐的淡忘了，此次来广州，查到花园酒店已经重新装修与改动了一些房型，便毫不犹豫的订了两晚。
花园酒店绝对的五星酒店中的翘楚，尽管是近40年前的产品，却是生机勃勃，老当益壮。
??论是房间的设施与硬件，都是超五星轻奢酒店标准，二楼的中餐厅环境也是一流的，特别是独特的的岭南风格的后花园（园林），那是人间仙境，白天迷人，夜晚诱人。
美中不足的是，大堂里飘散的香水味，也许选的不对我们的味觉，似乎??点澡堂子的味道，刺鼻而欠舒服。
若能下点功夫，调一下大堂香水味，让更多的客人喜欢，那么，来广州，花园酒店就是第一选择。', '2023-12-19', 5, '房间设施');
