INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ce2e3c98b0941765ab8', '广州三家白金五星级酒店之一，博物馆详细介绍酒店历史，几乎所有的美女服务人员笑容满面，到处都是，不知为何，上上下下找不到免费入座的地方，连办理入住的地方有没有，老年人长时间站着吃不消。携程网套餐，免费升级到套房，下午茶升级到包含晚上的欢乐时光，非常享受，谢谢！瀑布餐厅自助早餐在上午9点左右竟然排队等候多时，可以学习海花岛酒店分时段就餐方法。花园不是很大，人工瀑布气势磅礴。老外很多，还有外籍服务生。', '["https://dimg04.c-ctrip.com/images/0234e12000cr8khar016B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000cr8b73pF9ED_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d12000cr8fr6rA484_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000cr8gpac2CDE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000cr8cfxv1B5D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234a12000cr89l4z75FF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000cr8c1vh0785_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-18', '花园双床房', '双床房', '家庭亲子', 199, 5.298317366548036, 1, 0.6931471805599453, 105, 4.663439094112067, 8, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '广州三家白金五星级酒店之一，博物馆详细介绍酒店历史，几乎所有的美女服务人员笑容满', '广州三家白金五星级酒店之一，博物馆详细介绍酒店历史，几乎所有的美女服务人员笑容满面，到处都是，不知为何，上上下下找不到免费入座的地方，连办理入住的地方有没有，老年人长时间站着吃不消。携程网套餐，免费升级到套房，下午茶升级到包含晚上的欢乐时光，非常享受，谢谢！瀑布餐厅自助早餐在上午9点左右竟然排队等候多时，可以学习海花岛酒店分时段就餐方法。花园不是很大，人工瀑布气势磅礴。老外很多，还有外籍服务生。', '2023-12-18', 5, '前台服务');
