INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ce2e3c98b0941765aba', '广州花园酒店给我的入住体验特别好，走入大堂，映入眼帘是以红楼梦为主题的金碧辉煌的壁画，回眸又见岭南水乡人民生活的生动画面，由于入住的时间离圣诞节很近，节日气氛非常浓郁，入住的客人也特别多，美丽的服务员和蔼可亲，而且心特别细，远远看到客人乘电梯，都会主动为你按好，真正做到客人至上，让人感觉特别舒服。至于它的后花园，绝对有特色，两条18米高的大瀑布从天而降，大气磅礴。因为喜欢，故1月份带着家人再游广州，又订了4晚。', '["https://dimg04.c-ctrip.com/images/0236112000csrkwdhF0BE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000csrlic6A19E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235v12000csran5a5880_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235n12000csrlzor9562_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-25', '花园大床房', '大床房', '家庭亲子', 207, 5.337538079701318, 0, 0.0, 5, 1.791759469228055, 9, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '广州花园酒店给我的入住体验特别好，走入大堂，映入眼帘是以红楼梦为主题的金碧辉煌的', '广州花园酒店给我的入住体验特别好，走入大堂，映入眼帘是以红楼梦为主题的金碧辉煌的壁画，回眸又见岭南水乡人民生活的生动画面，由于入住的时间离圣诞节很近，节日气氛非常浓郁，入住的客人也特别多，美丽的服务员和蔼可亲，而且心特别细，远远看到客人乘电梯，都会主动为你按好，真正做到客人至上，让人感觉特别舒服。至于它的后花园，绝对有特色，两条18米高的大瀑布从天而降，大气磅礴。因为喜欢，故1月份带着家人再游广州，又订了4晚。', '2023-12-25', 5, '整体满意度');
