INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ceee3c98b0941765ac0', '酒店地理位置不错，离北京路挺近的，早餐非常好吃，连吃两天，非常的满意，下次来广州还会继续打卡，花园酒店的花园确实像花园一般，景美鱼肥！', '["https://dimg04.c-ctrip.com/images/0231312000d3w2j72A1D0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000d3w2i5h2907_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233e12000d3w4k8lBFCB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-02', '花园双床房', '双床房', '家庭亲子', 67, 4.219507705176107, 0, 0.0, 17, 2.8903717578961645, 7, '["周边配套", "餐饮设施", "整体满意度"]'::jsonb, '周边配套', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店地理位置不错，离北京路挺近的，早餐非常好吃，连吃两天，非常的满意，下次来广州', '酒店地理位置不错，离北京路挺近的，早餐非常好吃，连吃两天，非常的满意，下次来广州还会继续打卡，花园酒店的花园确实像花园一般，景美鱼肥！', '2024-02-02', 5, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ceee3c98b0941765ac1', '广州老牌酒店，环境很不错，有瀑布花园。服务很好要给赞。早餐很丰富。出门就是地铁站。唯一不足就是酒店房间有点陈旧。', '["https://dimg04.c-ctrip.com/images/0230412000d9466fo9DCE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o12000d94gs7a24C6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231c12000d94in1oF718_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-02-20', '花园双床房', '双床房', '家庭亲子', 56, 4.04305126783455, 0, 0.0, 6, 1.9459101490553128, 7, '["交通便利性", "餐饮设施", "整体满意度"]'::jsonb, '交通便利性', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '广州老牌酒店，环境很不错，有瀑布花园。服务很好要给赞。早餐很丰富。出门就是地铁站', '广州老牌酒店，环境很不错，有瀑布花园。服务很好要给赞。早餐很丰富。出门就是地铁站。唯一不足就是酒店房间有点陈旧。', '2024-02-20', 4, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ceee3c98b0941765ac2', '比预期的好很多，老牌的酒店，原以为设施会老旧，但房间维护的很好，很干净，很温馨，很有岭南特色。地下停车场有3层，充分满足了停车需求，就是停车场的电梯跟酒店是分开的，要绕过一节路，室外的，刚好下点小雨，自己拖着行李箱带着几个小朋友有点不方便。办入住的时候等的时间有点久，可能人太多的缘故，大堂真的是人来人往，古色古香的感觉，吃饭的、参观的、拍照的、络绎不绝……办入住的时候房间没打扫好，去3楼桃园馆吃了顿饭，正宗的粤菜，摆盘正、味道正，除了价格贵没别的缺点了，推荐大家可以尝试一下。酒店后花园很漂亮，有水池和鲤鱼，还有瀑布，景色怡人，另外还享受了30层的行政酒廊，服务员Ken和Zocy非常热情有礼貌，会主动询问和帮忙，非常感谢他们高水准的服务，总之，花园酒店可以让你更直观的了解广州的一些地方特色和风土人情，值得一住。', '["https://dimg04.c-ctrip.com/images/0231312000d2gdevyF7CD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c12000d2gd0mfA96A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000d2fn5r689A2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o12000d2fuqpt4FF9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000d2g6fsa74FB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230m12000d2g23q9E9D0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231i12000d2g23qbCF9B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234612000d2g4dy68129_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237112000d2g2tsbAEAD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-29', '粤韵大床套房', '套房', '家庭亲子', 359, 5.886104031450156, 0, 0.0, 41, 3.737669618283368, 9, '["整体满意度", "房间设施", "公共设施"]'::jsonb, '整体满意度', '房间设施', '公共设施', '未知酒店', '未知地点', '匿名', '比预期的好很多，老牌的酒店，原以为设施会老旧，但房间维护的很好，很干净，很温馨，', '比预期的好很多，老牌的酒店，原以为设施会老旧，但房间维护的很好，很干净，很温馨，很有岭南特色。地下停车场有3层，充分满足了停车需求，就是停车场的电梯跟酒店是分开的，要绕过一节路，室外的，刚好下点小雨，自己拖着行李箱带着几个小朋友有点不方便。办入住的时候等的时间有点久，可能人太多的缘故，大堂真的是人来人往，古色古香的感觉，吃饭的、参观的、拍照的、络绎不绝……办入住的时候房间没打扫好，去3楼桃园馆吃了顿饭，正宗的粤菜，摆盘正、味道正，除了价格贵没别的缺点了，推荐大家可以尝试一下。酒店后花园很漂亮，有水池和鲤鱼，还有瀑布，景色怡人，另外还享受了30层的行政酒廊，服务员Ken和Zocy非常热情有礼貌，会主动询问和帮忙，非常感谢他们高水准的服务，总之，花园酒店可以让你更直观的了解广州的一些地方特色和风土人情，值得一住。', '2024-01-29', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ceee3c98b0941765ac3', '大堂很豪华漂亮，也有过年的氛围，房间稍微小了点。总之很好的住宿体验。到处都很漂亮，而且很有年味，感觉像在自己家过年一样。', '["https://dimg04.c-ctrip.com/images/0231812000d6gsuwuF313_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231p12000d6gt3wy00F5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000d6gtd8z57C7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-11', '城央绿意双床房', '双床房', '家庭亲子', 60, 4.110873864173311, 0, 0.0, 15, 2.772588722239781, 5, '["整体满意度", "公共设施"]'::jsonb, '整体满意度', '公共设施', NULL, '未知酒店', '未知地点', '匿名', '大堂很豪华漂亮，也有过年的氛围，房间稍微小了点。总之很好的住宿体验。到处都很漂亮', '大堂很豪华漂亮，也有过年的氛围，房间稍微小了点。总之很好的住宿体验。到处都很漂亮，而且很有年味，感觉像在自己家过年一样。', '2024-02-11', 5, '整体满意度');
