INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027ceee3c98b0941765ac5', '老城区的老牌酒店，去哪里都很方便。过年期间有很多活动，工作服务人员也很多。美中不足的是早餐一般，品种很少，亲子设施少。', '["https://dimg04.c-ctrip.com/images/0234212000d6orjs24828_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232u12000d6p9ajx207D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234b12000d6p3dbaF9DB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-12', '花园大床房', '大床房', '家庭亲子', 59, 4.0943445622221, 0, 0.0, 11, 2.4849066497880004, 6, '["交通便利性", "周边配套", "餐饮设施"]'::jsonb, '交通便利性', '周边配套', '餐饮设施', '未知酒店', '未知地点', '匿名', '老城区的老牌酒店，去哪里都很方便。过年期间有很多活动，工作服务人员也很多。美中不', '老城区的老牌酒店，去哪里都很方便。过年期间有很多活动，工作服务人员也很多。美中不足的是早餐一般，品种很少，亲子设施少。', '2024-02-12', 4, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cf8e3c98b0941765ac6', '续住豪华白金五星花园酒店，环境优美，房间舒适，凌璇阁旋转餐厅非常棒！早餐品种丰盛，360゜全景欣赏广州风景。', '["https://dimg04.c-ctrip.com/images/0237112000d8xo2z3A6C8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000d8xxw43AC7C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235o12000d8xylimA27E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-20', '花园双床房', '双床房', '朋友出游', 54, 4.007333185232471, 0, 0.0, 103, 4.6443908991413725, 8, '["餐饮设施", "整体满意度", "景观/朝向"]'::jsonb, '餐饮设施', '整体满意度', '景观/朝向', '未知酒店', '未知地点', '匿名', '续住豪华白金五星花园酒店，环境优美，房间舒适，凌璇阁旋转餐厅非常棒！早餐品种丰盛', '续住豪华白金五星花园酒店，环境优美，房间舒适，凌璇阁旋转餐厅非常棒！早餐品种丰盛，360゜全景欣赏广州风景。', '2024-02-20', 4, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cf8e3c98b0941765ac7', '花园酒店具有广州特色，尤其大堂非常富丽堂皇，还有花园瀑布小桥流水。酒店周边热闹，地铁淘金站就在旁边，购物方便。酒店二楼的中餐厅早茶好吃。毕竟是1985年开业的酒店，房间内部如果重新装修就更好了。', '["https://dimg04.c-ctrip.com/images/0236h12000cn85oznFE03_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000cn8b7odCF03_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000cn89e51D30F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232j12000cn88tmc12AC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235812000cn84e570FDA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235012000cn87w60519D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236d12000cn8aerc7C05_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233k12000cn86tzqD3E6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234u12000cn8ctpa07AF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-11-27', '红棉双床套房', '套房', '家庭亲子', 97, 4.584967478670572, 0, 0.0, 80, 4.394449154672439, 8, '["周边配套", "交通便利性", "餐饮设施"]'::jsonb, '周边配套', '交通便利性', '餐饮设施', '未知酒店', '未知地点', '匿名', '花园酒店具有广州特色，尤其大堂非常富丽堂皇，还有花园瀑布小桥流水。酒店周边热闹，', '花园酒店具有广州特色，尤其大堂非常富丽堂皇，还有花园瀑布小桥流水。酒店周边热闹，地铁淘金站就在旁边，购物方便。酒店二楼的中餐厅早茶好吃。毕竟是1985年开业的酒店，房间内部如果重新装修就更好了。', '2023-11-27', 4, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cf8e3c98b0941765ac8', '老牌五星酒店，服务、餐饮、卫生、环境都很赞，距离5号线淘金站，几乎零距离，特别适合家庭出游选择，会推荐给朋友。', '["https://dimg04.c-ctrip.com/images/0236t12000d8sb8h42693_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000d8seu0j1534_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000d8sfece6243_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-19', '粤韵双床套房', '套房', '家庭亲子', 55, 4.02535169073515, 0, 0.0, 6, 1.9459101490553128, 7, '["整体满意度", "交通便利性", "餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施', '未知酒店', '未知地点', '匿名', '老牌五星酒店，服务、餐饮、卫生、环境都很赞，距离5号线淘金站，几乎零距离，特别适', '老牌五星酒店，服务、餐饮、卫生、环境都很赞，距离5号线淘金站，几乎零距离，特别适合家庭出游选择，会推荐给朋友。', '2024-02-19', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cf8e3c98b0941765ac9', '交通便利，就在地铁口。前台服务周到，房间有缺什么也是第一时间送到，5星服务很到位。还有自己的博物馆和后花园，入住体验感很好，下次还来，推荐', '["https://dimg04.c-ctrip.com/images/0232p12000db9x3tr8274_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235k12000db9pz7k818C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235u12000db9ysha4010_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-29', '粤韵双床套房', '套房', '家庭亲子', 69, 4.248495242049359, 0, 0.0, 1, 0.6931471805599453, 8, '["交通便利性", "前台服务", "整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '交通便利，就在地铁口。前台服务周到，房间有缺什么也是第一时间送到，5星服务很到位', '交通便利，就在地铁口。前台服务周到，房间有缺什么也是第一时间送到，5星服务很到位。还有自己的博物馆和后花园，入住体验感很好，下次还来，推荐', '2024-02-29', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cf8e3c98b0941765aca', '酒店环境很美，前台给升级了套房，房间很大也很干净，很满意，春节氛围感很足，一直到初五都有年俗活动，服务态度很好。', '["https://dimg04.c-ctrip.com/images/0231q12000d7xgxuq1EE5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-16', '花园大床房', '大床房', '家庭亲子', 56, 4.04305126783455, 0, 0.0, 17, 2.8903717578961645, 8, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '酒店环境很美，前台给升级了套房，房间很大也很干净，很满意，春节氛围感很足，一直到', '酒店环境很美，前台给升级了套房，房间很大也很干净，很满意，春节氛围感很足，一直到初五都有年俗活动，服务态度很好。', '2024-02-16', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cf8e3c98b0941765acb', '酒店连住三晚，满意酒店位置，地铁公交打车都方便。酒店还有瀑布花园，博物馆，非常有特色。除了附近有工地，半夜时有噪音，其他都赞。', '["https://dimg04.c-ctrip.com/images/0231512000d40kdimC1F7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-02', '花园双床房', '双床房', '家庭亲子', 63, 4.158883083359672, 0, 0.0, 17, 2.8903717578961645, 8, '["交通便利性", "周边配套", "安静程度"]'::jsonb, '交通便利性', '周边配套', '安静程度', '未知酒店', '未知地点', '匿名', '酒店连住三晚，满意酒店位置，地铁公交打车都方便。酒店还有瀑布花园，博物馆，非常有', '酒店连住三晚，满意酒店位置，地铁公交打车都方便。酒店还有瀑布花园，博物馆，非常有特色。除了附近有工地，半夜时有噪音，其他都赞。', '2024-02-02', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cf8e3c98b0941765acc', '第一次入住花园酒店，高大上的感觉，特别四楼的【博物馆】相当的不错，赞????????！瀑布餐厅的自助晚餐品种丰富，三文鱼柳，厚切的口感很过瘾！其他食材也不错，开启增肥的节奏！最感动的是，餐厅知道我生日，由经理携同祝贺团队一边唱着生日歌，一边送来了生日蛋糕和一支玫瑰花，暖暖的！可惜，客服后续服务跟不上！我在订房时已经明确需要加床，办理入住时再次重申要马上加床，一路颠簸很累！结果等了一个多小时，电话催了几次，才过来装上。感觉五星酒店不应该是这样的！', '["https://dimg04.c-ctrip.com/images/0232k12000cpn8brr74F4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a12000cpn8ayu9624_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000cpn84egB670_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234812000cpn84eu3121_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235812000cpn93k3A5F2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233m12000cpn94qpDDF0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-12-10', '羊羊得意主题大床房', '主题房', '家庭亲子', 224, 5.41610040220442, 0, 0.0, 10, 2.3978952727983707, 8, '["餐饮设施", "客房服务", "整体满意度"]'::jsonb, '餐饮设施', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '第一次入住花园酒店，高大上的感觉，特别四楼的【博物馆】相当的不错，赞??????', '第一次入住花园酒店，高大上的感觉，特别四楼的【博物馆】相当的不错，赞????????！瀑布餐厅的自助晚餐品种丰富，三文鱼柳，厚切的口感很过瘾！其他食材也不错，开启增肥的节奏！最感动的是，餐厅知道我生日，由经理携同祝贺团队一边唱着生日歌，一边送来了生日蛋糕和一支玫瑰花，暖暖的！可惜，客服后续服务跟不上！我在订房时已经明确需要加床，办理入住时再次重申要马上加床，一路颠簸很累！结果等了一个多小时，电话催了几次，才过来装上。感觉五星酒店不应该是这样的！', '2023-12-10', 4, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cf8e3c98b0941765acd', '完全出乎意料的好！无论是设施服务还是饮食酒店文化都做的非常棒，新年入住气氛也很浓郁，体验很好，会再来。非常适合带孩子。', '["https://dimg04.c-ctrip.com/images/0235512000d7l6aaf7B0F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237012000d7l8ce0D436_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000d7l2r763D93_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-15', '红棉大床套房', '套房', '家庭亲子', 59, 4.0943445622221, 0, 0.0, 8, 2.19722457733622, 6, '["整体满意度", "餐饮设施", "前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '完全出乎意料的好！无论是设施服务还是饮食酒店文化都做的非常棒，新年入住气氛也很浓', '完全出乎意料的好！无论是设施服务还是饮食酒店文化都做的非常棒，新年入住气氛也很浓郁，体验很好，会再来。非常适合带孩子。', '2024-02-15', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cf8e3c98b0941765ace', '来广州首选花园酒店，入住时告诉接待员我们已是第三次入住，那位帅哥Kasas非常专业和热情：“欢迎回家”，贴心地为我们升级了房间，赠送早餐和下午茶，太开心了，谢谢他。酒店的博物馆和老家俱展示都非常有特色，房间布置很漂亮，床品床单很高级的提花面料很舒服，也找服务员要了决明子枕头；打扫非常干净整洁；很慷慨的赠送饮用水；在酒店吃了荔湾亭和日料餐厅非常不错。', '["https://dimg04.c-ctrip.com/images/0232912000hmibx023195_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237112000hmi1sjsC2B1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233j12000hmidujy1316_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a12000hmhscvy5759_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000hmhimcg8BBB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232612000hmhbvew7C70_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-01-06', '城央绿意大床房', '大床房', '其他', 175, 5.170483995038151, 0, 0.0, 5, 1.791759469228055, 9, '["前台服务", "整体满意度", "客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务', '未知酒店', '未知地点', '匿名', '来广州首选花园酒店，入住时告诉接待员我们已是第三次入住，那位帅哥Kasas非常专', '来广州首选花园酒店，入住时告诉接待员我们已是第三次入住，那位帅哥Kasas非常专业和热情：“欢迎回家”，贴心地为我们升级了房间，赠送早餐和下午茶，太开心了，谢谢他。酒店的博物馆和老家俱展示都非常有特色，房间布置很漂亮，床品床单很高级的提花面料很舒服，也找服务员要了决明子枕头；打扫非常干净整洁；很慷慨的赠送饮用水；在酒店吃了荔湾亭和日料餐厅非常不错。', '2025-01-06', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027cf8e3c98b0941765acf', '不愧是白金五星酒店，出入方便，在越秀区中心位置，环境优美，是酒店花园，家人都觉得满意，下次还会考虑入住哦。', '["https://dimg04.c-ctrip.com/images/0233l12000d8hgl6z2E0B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235d12000d8hgu4492B8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236c12000d8hbdzz4D84_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233q12000d8h6n3y5AD1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000d8hfcxx4F52_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f12000d8h4nag394D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236x12000d8hb52i1408_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000d8hbk52C85E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000d8hg42c8DEF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-18', '红棉双床套房', '套房', '家庭亲子', 53, 3.9889840465642745, 0, 0.0, 27, 3.332204510175204, 6, '["整体满意度", "交通便利性", "周边配套"]'::jsonb, '整体满意度', '交通便利性', '周边配套', '未知酒店', '未知地点', '匿名', '不愧是白金五星酒店，出入方便，在越秀区中心位置，环境优美，是酒店花园，家人都觉得', '不愧是白金五星酒店，出入方便，在越秀区中心位置，环境优美，是酒店花园，家人都觉得满意，下次还会考虑入住哦。', '2024-02-18', 5, '整体满意度');
