INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d03e3c98b0941765ad1', '服务非常热情，楼层都有管家，微笑服务。房间打扫及时，干净，有欢迎水果送想得很周到。桃园餐厅的菜品不错，没有低消。酒店出行很方便门口就是地铁。', '["https://dimg04.c-ctrip.com/images/0233612000d258rbdE31B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000d258qd27027_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000d258rxqDB80_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232f12000d258ryh35AF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-27', '红棉双床套房', '套房', '家庭亲子', 70, 4.262679877041316, 0, 0.0, 7, 2.079441541679836, 7, '["前台服务", "客房服务", "交通便利性"]'::jsonb, '前台服务', '客房服务', '交通便利性', '未知酒店', '未知地点', '匿名', '服务非常热情，楼层都有管家，微笑服务。房间打扫及时，干净，有欢迎水果送想得很周到', '服务非常热情，楼层都有管家，微笑服务。房间打扫及时，干净，有欢迎水果送想得很周到。桃园餐厅的菜品不错，没有低消。酒店出行很方便门口就是地铁。', '2024-01-27', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d03e3c98b0941765ad2', '每间夜含2位行政礼遇（含下午茶及欢乐时光）：非常满意！服务很贴心，因为是一个人入住所以都是邀请朋友来happy hour，有一天多了一个朋友过来坐也能理解。下午茶点心很精致，只是晚了就会没有太多选择。
早餐: 早餐西餐种类较多，中餐选择相对较少，希望可以多一些本地早茶点心。', '["https://dimg04.c-ctrip.com/images/0231v324x8tlm7dwqBD8E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y324x8tlg9l7y7998_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-22', '花园大床房', '大床房', '独自旅行', 137, 4.927253685157205, 0, 0.0, 1, 0.6931471805599453, 8, '["餐饮设施", "整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '每间夜含2位行政礼遇（含下午茶及欢乐时光）：非常满意！服务很贴心，因为是一个人入', '每间夜含2位行政礼遇（含下午茶及欢乐时光）：非常满意！服务很贴心，因为是一个人入住所以都是邀请朋友来happy hour，有一天多了一个朋友过来坐也能理解。下午茶点心很精致，只是晚了就会没有太多选择。
早餐: 早餐西餐种类较多，中餐选择相对较少，希望可以多一些本地早茶点心。', '2023-12-22', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d03e3c98b0941765ad3', '酒店服务、环境真的很棒，感谢行政走廊Tina、Echo、Kitty的优质服务，感谢客房整理员陶美芳的细心服务。只要客房设施陈旧了些，期待早日修缮，期待下次再来住??', '["https://dimg04.c-ctrip.com/images/0232i12000fbdo6vgCC6B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000fbdymp5F869_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232212000fbdnw81EB21_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000fbdxyp70692_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233112000fbdu60e3ED3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-08-30', '花园双床房', '双床房', '家庭亲子', 82, 4.418840607796598, 0, 0.0, 2, 1.0986122886681098, 7, '["前台服务", "客房服务", "房间设施"]'::jsonb, '前台服务', '客房服务', '房间设施', '未知酒店', '未知地点', '匿名', '酒店服务、环境真的很棒，感谢行政走廊Tina、Echo、Kitty的优质服务，感', '酒店服务、环境真的很棒，感谢行政走廊Tina、Echo、Kitty的优质服务，感谢客房整理员陶美芳的细心服务。只要客房设施陈旧了些，期待早日修缮，期待下次再来住??', '2024-08-30', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d03e3c98b0941765ad4', '入住办理太费劲，人员效率慢，服务态度比较一般，对不起花园酒店这个名字，希望有待改善，毕竟花园酒店是广州人的美好记忆。', '["https://dimg04.c-ctrip.com/images/0231k12000d60sluvE081_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234t12000d60f51qB6A6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230z12000d60mhrrEE7B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-02-09', '红棉大床套房', '套房', '家庭亲子', 58, 4.07753744390572, 0, 0.0, 24, 3.218875824868201, 6, '["前台服务", "退房/入住效率"]'::jsonb, '前台服务', '退房/入住效率', NULL, '未知酒店', '未知地点', '匿名', '入住办理太费劲，人员效率慢，服务态度比较一般，对不起花园酒店这个名字，希望有待改', '入住办理太费劲，人员效率慢，服务态度比较一般，对不起花园酒店这个名字，希望有待改善，毕竟花园酒店是广州人的美好记忆。', '2024-02-09', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d03e3c98b0941765ad5', '位置好、规模大，是一家非常有文化底蕴的酒店，但设施设备很有年代感了，服务还是不错的  春节期间大厅集市很有特色。', '["https://dimg04.c-ctrip.com/images/0231712000d6v8xht7366_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230s12000d6v7lhx6AB4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000d6uihbeB31D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236q12000d6v4wx14788_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000d6ufjk6C43A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-02-13', '花园双床房', '双床房', '家庭亲子', 56, 4.04305126783455, 0, 0.0, 19, 2.995732273553991, 6, '["整体满意度", "周边配套", "房间设施"]'::jsonb, '整体满意度', '周边配套', '房间设施', '未知酒店', '未知地点', '匿名', '位置好、规模大，是一家非常有文化底蕴的酒店，但设施设备很有年代感了，服务还是不错', '位置好、规模大，是一家非常有文化底蕴的酒店，但设施设备很有年代感了，服务还是不错的  春节期间大厅集市很有特色。', '2024-02-13', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d03e3c98b0941765ad6', '房间挺好的，环境不错，服务也好，酒店大气，有花园，花园里有许多锦鲤鱼，还有人造瀑布，循环水溪，花园溜达也很惬意。不愧为花园酒店。值得推荐。', '["https://dimg04.c-ctrip.com/images/0231112000dncp6dhE422_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233b12000dncoz8g9882_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236v12000dncoz8o2ADB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235r12000dncp0e15574_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000dncpal878CF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-11', '花园双床房', '双床房', '其他', 69, 4.248495242049359, 0, 0.0, 1, 0.6931471805599453, 8, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '房间挺好的，环境不错，服务也好，酒店大气，有花园，花园里有许多锦鲤鱼，还有人造瀑', '房间挺好的，环境不错，服务也好，酒店大气，有花园，花园里有许多锦鲤鱼，还有人造瀑布，循环水溪，花园溜达也很惬意。不愧为花园酒店。值得推荐。', '2024-04-11', 5, '整体满意度');
