INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d03e3c98b0941765ad8', '酒店很美，瀑布餐厅可以看锦鲤小朋友超喜欢，酒店服务也很好，给前台betty点个赞??态度耐心，看我们两个小朋友给不了连在一起的房间，还给我们升了房。住的很舒心，早餐也好吃。房间打扫的超干净。唯一不足就是可能外国人多，酒店房间太冷了，空调调高也没用，后面把空调关了挺好。总体说非常非常值得一住。', '["https://dimg04.c-ctrip.com/images/0231012000go853zn150D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232b12000go85f6w4C39_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235t12000go7onr41E4C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237112000go7yvxr0AF5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-14', '花园大床房', '大床房', '家庭亲子', 146, 4.990432586778736, 0, 0.0, 3, 1.3862943611198906, 9, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '酒店很美，瀑布餐厅可以看锦鲤小朋友超喜欢，酒店服务也很好，给前台betty点个赞', '酒店很美，瀑布餐厅可以看锦鲤小朋友超喜欢，酒店服务也很好，给前台betty点个赞??态度耐心，看我们两个小朋友给不了连在一起的房间，还给我们升了房。住的很舒心，早餐也好吃。房间打扫的超干净。唯一不足就是可能外国人多，酒店房间太冷了，空调调高也没用，后面把空调关了挺好。总体说非常非常值得一住。', '2024-11-14', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d03e3c98b0941765ad9', '不愧是老牌的白金级五星级酒店，从下车到达开始见到的每一个服务人员都非常热情，特别是行政酒廊的 Carrie 和 Jaismine 为我们的下午茶和欢乐时光都提供了细致周到的服务，给全家包括老人和小孩都留下了难忘的回忆，谢谢。', '["https://dimg04.c-ctrip.com/images/0232p12000d3b8ksi7986_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230812000d3bawq8F675_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235u12000d3bbsic4A48_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230j12000d3bbsig24C5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232e12000d3bbjgo3670_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235r12000d3bbmrb5F00_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-31', '花园双床房', '双床房', '家庭亲子', 112, 4.727387818712341, 0, 0.0, 3, 1.3862943611198906, 9, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '不愧是老牌的白金级五星级酒店，从下车到达开始见到的每一个服务人员都非常热情，特别', '不愧是老牌的白金级五星级酒店，从下车到达开始见到的每一个服务人员都非常热情，特别是行政酒廊的 Carrie 和 Jaismine 为我们的下午茶和欢乐时光都提供了细致周到的服务，给全家包括老人和小孩都留下了难忘的回忆，谢谢。', '2024-01-31', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d10e3c98b0941765ada', '酒店位置方便，硬件条件好，前台免费升级房型，非常感谢！下次来广州还会选择入住', '["https://dimg04.c-ctrip.com/images/0236u12000dfhj7gi8626_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-16', '花园大床房', '大床房', '商务出差', 38, 3.6635616461296463, 0, 0.0, 30, 3.4339872044851463, 6, '["整体满意度", "交通便利性", "前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务', '未知酒店', '未知地点', '匿名', '酒店位置方便，硬件条件好，前台免费升级房型，非常感谢！下次来广州还会选择入住', '酒店位置方便，硬件条件好，前台免费升级房型，非常感谢！下次来广州还会选择入住', '2024-03-16', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d10e3c98b0941765adb', '房间干净卫生整齐，大堂富丽堂皇，像一座艺术殿堂，服务态度好。瀑布餐厅漂亮值得打卡，四楼博物馆讲述了中国酒店发展史。', '["https://dimg04.c-ctrip.com/images/0231m12000d6u36505CFA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230p12000d6toprk0444_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235z12000d6u0hkf84E0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-13', '花园双床房', '双床房', '家庭亲子', 57, 4.060443010546419, 0, 0.0, 19, 2.995732273553991, 8, '["卫生状况", "整体满意度", "餐饮设施"]'::jsonb, '卫生状况', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '房间干净卫生整齐，大堂富丽堂皇，像一座艺术殿堂，服务态度好。瀑布餐厅漂亮值得打卡', '房间干净卫生整齐，大堂富丽堂皇，像一座艺术殿堂，服务态度好。瀑布餐厅漂亮值得打卡，四楼博物馆讲述了中国酒店发展史。', '2024-02-13', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d10e3c98b0941765adc', '位置方便，房间虽然老旧，但面积很大，宽敞舒适，大厅恢宏气派，服务态度很好，窗外有瀑布景观，酒店有博物馆文化底蕴深厚', '["https://dimg04.c-ctrip.com/images/0235d12000drp5ry8E480_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231312000drp4xau020B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230x12000drp5pkv0AD4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-04-24', '花园双床房', '双床房', '商务出差', 57, 4.060443010546419, 0, 0.0, 2, 1.0986122886681098, 8, '["景观/朝向", "周边配套", "整体满意度"]'::jsonb, '景观/朝向', '周边配套', '整体满意度', '未知酒店', '未知地点', '匿名', '位置方便，房间虽然老旧，但面积很大，宽敞舒适，大厅恢宏气派，服务态度很好，窗外有', '位置方便，房间虽然老旧，但面积很大，宽敞舒适，大厅恢宏气派，服务态度很好，窗外有瀑布景观，酒店有博物馆文化底蕴深厚', '2024-04-24', 4, '景观/朝向');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d10e3c98b0941765add', '考虑到要自由行动，所以选了交通便利的酒店，酒店边上就是地铁入口超级方便。过年期间酒店里也装饰的非常喜庆！', '["https://dimg04.c-ctrip.com/images/0236712000d91d0431DC4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231i12000d91dqm3861E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000d91djnmBE8C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-20', '城央绿意大床房', '大床房', '家庭亲子', 52, 3.970291913552122, 0, 0.0, 2, 1.0986122886681098, 6, '["交通便利性", "整体满意度"]'::jsonb, '交通便利性', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '考虑到要自由行动，所以选了交通便利的酒店，酒店边上就是地铁入口超级方便。过年期间', '考虑到要自由行动，所以选了交通便利的酒店，酒店边上就是地铁入口超级方便。过年期间酒店里也装饰的非常喜庆！', '2024-02-20', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d10e3c98b0941765ade', '房间干净，整洁，酒店的服务人员服务态度非常好。行政酒廊的工作人员服务周到，热情，Kanchan和Deepa笑容满面，相关酒店服务需求都会马上回应及解决，客房服务的小天也是服务周到，房间服务人员尽心尽力，还特意写了小卡片进行跟进，这个酒店要给个大大的赞??', '["https://dimg04.c-ctrip.com/images/0234g12000f5kasxlE4F5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000f5kgce758B6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000f5kk4kd096F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-17', '花园大床房', '大床房', '家庭亲子', 127, 4.852030263919617, 0, 0.0, 9, 2.302585092994046, 9, '["客房服务", "前台服务", "卫生状况"]'::jsonb, '客房服务', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '房间干净，整洁，酒店的服务人员服务态度非常好。行政酒廊的工作人员服务周到，热情，', '房间干净，整洁，酒店的服务人员服务态度非常好。行政酒廊的工作人员服务周到，热情，Kanchan和Deepa笑容满面，相关酒店服务需求都会马上回应及解决，客房服务的小天也是服务周到，房间服务人员尽心尽力，还特意写了小卡片进行跟进，这个酒店要给个大大的赞??', '2024-08-17', 5, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d10e3c98b0941765adf', '不愧是老牌五星酒店的品牌，环境优美，房间也不错，服务态度非常好，有求必应，特别是酒店后花园的环境真的是太漂亮啦，下次来广州还会住花园酒店。', '["https://dimg04.c-ctrip.com/images/0203k12000cz9qumqC8D4_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0232812000cz9arcgBAC2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231h12000cz98pli70DC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c12000cz98smiD338_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-19', '粤韵双床套房', '套房', '家庭亲子', 69, 4.248495242049359, 0, 0.0, 1, 0.6931471805599453, 7, '["整体满意度", "前台服务", "景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向', '未知酒店', '未知地点', '匿名', '不愧是老牌五星酒店的品牌，环境优美，房间也不错，服务态度非常好，有求必应，特别是', '不愧是老牌五星酒店的品牌，环境优美，房间也不错，服务态度非常好，有求必应，特别是酒店后花园的环境真的是太漂亮啦，下次来广州还会住花园酒店。', '2024-01-19', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d10e3c98b0941765ae0', '五星级酒店，三星的水准，入住体验最差的一次，壮观的门面，不如在入住的房间内多下工夫，金玉其外，败絮其中。', '["https://dimg04.c-ctrip.com/images/0236j12000d7pg0yoBD69_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n12000d7p4asqACC3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234412000d7p8o15D8F3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.7, 1, '2024-02-15', '城央绿意双床房', '双床房', '其他', 52, 3.970291913552122, 6, 1.9459101490553128, 8, 2.19722457733622, 7, '["整体满意度", "房间设施"]'::jsonb, '整体满意度', '房间设施', NULL, '未知酒店', '未知地点', '匿名', '五星级酒店，三星的水准，入住体验最差的一次，壮观的门面，不如在入住的房间内多下工', '五星级酒店，三星的水准，入住体验最差的一次，壮观的门面，不如在入住的房间内多下工夫，金玉其外，败絮其中。', '2024-02-15', 1, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d10e3c98b0941765ae1', '地理位置好，就在大街上容易看见。
房间重新装修了，喜欢这个格调，也喜欢大浴缸。
我住在701，我的小伙伴住在1949，他订的房间有行政酒廊，我们俩一起去了好几回，Cherry,Ken,Yuki,Carrie他们给了我们俩很好的服务。非常感恩。', '["https://dimg04.c-ctrip.com/images/0206p12000coekvutF903_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0236y12000coekh9kFA7E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232w12000coec38v526C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-04', '花园大床房', '大床房', '商务出差', 121, 4.804021044733257, 1, 0.6931471805599453, 3, 1.3862943611198906, 8, '[]'::jsonb, NULL, NULL, NULL, '未知酒店', '未知地点', '匿名', '地理位置好，就在大街上容易看见。', '地理位置好，就在大街上容易看见。
房间重新装修了，喜欢这个格调，也喜欢大浴缸。
我住在701，我的小伙伴住在1949，他订的房间有行政酒廊，我们俩一起去了好几回，Cherry,Ken,Yuki,Carrie他们给了我们俩很好的服务。非常感恩。', '2023-12-04', 5, '商务出差');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d10e3c98b0941765ae2', '花园酒店的历史悠久，大堂的圣诞气氛很浓厚，房间也还是蛮大的，有大圆桌和沙发，床上用品比较舒服，上30楼餐厅的电梯不太人性化，如果不是4部直达电梯的话就要往下坐到一楼再转；因为需要小朋友的拖鞋和浴衣，礼宾部的电话打了几次才有人接；因为在房间里面看到游泳池在布置婚礼，特意打电话问前台游泳池是不是关闭了，前台在没有确定的情况下就说没有关闭，就带着小孩穿着泳衣下去了，泳池的前台又说游泳池今天有活动不开放了，这么冷的天，又带小孩回房间了，行政酒廊的食物种类特别少，基本上是住过的五星酒店里最少的，欢乐时光的食品还没有希尔顿的下午茶种类丰富，估计是花园酒店不是国际连锁，不需要维护会员的忠诚度吧，但是味道还是不错的，行政酒廊的工作人员Carrie,Ken,Yuki也是特别的热情和专业。退房的时候开车出车库，显示要交144元停车费，可是刚刚才在礼宾部报备了车牌号啊，后面还有一堆车在等，比较狼狈。', '["https://dimg04.c-ctrip.com/images/0236512000co9ho9k42F1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230a12000co9jn4y8CDD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000co9h9qu2851_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-12-03', '花园大床房', '大床房', '家庭亲子', 394, 5.978885764901122, 1, 0.6931471805599453, 2, 1.0986122886681098, 9, '["前台服务", "公共设施", "餐饮设施"]'::jsonb, '前台服务', '公共设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '花园酒店的历史悠久，大堂的圣诞气氛很浓厚，房间也还是蛮大的，有大圆桌和沙发，床上', '花园酒店的历史悠久，大堂的圣诞气氛很浓厚，房间也还是蛮大的，有大圆桌和沙发，床上用品比较舒服，上30楼餐厅的电梯不太人性化，如果不是4部直达电梯的话就要往下坐到一楼再转；因为需要小朋友的拖鞋和浴衣，礼宾部的电话打了几次才有人接；因为在房间里面看到游泳池在布置婚礼，特意打电话问前台游泳池是不是关闭了，前台在没有确定的情况下就说没有关闭，就带着小孩穿着泳衣下去了，泳池的前台又说游泳池今天有活动不开放了，这么冷的天，又带小孩回房间了，行政酒廊的食物种类特别少，基本上是住过的五星酒店里最少的，欢乐时光的食品还没有希尔顿的下午茶种类丰富，估计是花园酒店不是国际连锁，不需要维护会员的忠诚度吧，但是味道还是不错的，行政酒廊的工作人员Carrie,Ken,Yuki也是特别的热情和专业。退房的时候开车出车库，显示要交144元停车费，可是刚刚才在礼宾部报备了车牌号啊，后面还有一堆车在等，比较狼狈。', '2023-12-03', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d10e3c98b0941765ae3', '房间和服务都不错。桃园馆中餐厅环境优雅。只是位于30楼的下午茶太差了，无论是出品还是格局都与酒店的档次极不相称，体验感太差，实在可惜了！', '["https://dimg04.c-ctrip.com/images/0232v12000czdax510AC2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000czdax5988D5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000czdb0dh8504_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236o12000czdb0djF5ED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-20', '粤韵双床套房', '套房', '其他', 68, 4.23410650459726, 0, 0.0, 8, 2.19722457733622, 8, '["餐饮设施", "整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '房间和服务都不错。桃园馆中餐厅环境优雅。只是位于30楼的下午茶太差了，无论是出品', '房间和服务都不错。桃园馆中餐厅环境优雅。只是位于30楼的下午茶太差了，无论是出品还是格局都与酒店的档次极不相称，体验感太差，实在可惜了！', '2024-01-20', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d20e3c98b0941765ae4', '下午三点多办理入住的，人不多，等一两个就可以，不过办理过程稍微慢了一点点，花了十几分钟.小姐姐也一直在说不好意思，最后对房间还是满意的，应该是房间没清洁好临时给升了一个房型，然后比较安静没有受到附近施工??噪音的困扰.
 外观大堂都是老牌酒店的样子，内部重修装修过所以特别舒适大方.', '["https://dimg04.c-ctrip.com/images/0232y12000cou1lzm0BF5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000cou3irf3641_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230p12000cotxq9xE068_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-06', '红棉双床套房', '套房', '朋友出游', 142, 4.962844630259907, 0, 0.0, 1, 0.6931471805599453, 8, '["退房/入住效率", "安静程度", "整体满意度"]'::jsonb, '退房/入住效率', '安静程度', '整体满意度', '未知酒店', '未知地点', '匿名', '下午三点多办理入住的，人不多，等一两个就可以，不过办理过程稍微慢了一点点，花了十', '下午三点多办理入住的，人不多，等一两个就可以，不过办理过程稍微慢了一点点，花了十几分钟.小姐姐也一直在说不好意思，最后对房间还是满意的，应该是房间没清洁好临时给升了一个房型，然后比较安静没有受到附近施工??噪音的困扰.
 外观大堂都是老牌酒店的样子，内部重修装修过所以特别舒适大方.', '2023-12-06', 5, '退房/入住效率');
