第二次在过年期间入住了，氛围感满满。春节期间酒店还有各种规定，大人小孩都玩得很开心…', '2024-02-11', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d20e3c98b0941765ae6', '酒店服务态度很好，周边交通很便利，出门就是地铁站，离点都德也很近，酒店春节期间各种活动，很喜庆，人气旺！', '["https://dimg04.c-ctrip.com/images/0233312000d6f95yu98D3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235v12000d6fobupC833_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233712000d6fp8k93EF2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-11', '城央绿意双床房', '双床房', '家庭亲子', 52, 3.970291913552122, 0, 0.0, 1, 0.6931471805599453, 7, '["交通便利性", "周边配套", "前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务', '未知酒店', '未知地点', '匿名', '酒店服务态度很好，周边交通很便利，出门就是地铁站，离点都德也很近，酒店春节期间各', '酒店服务态度很好，周边交通很便利，出门就是地铁站，离点都德也很近，酒店春节期间各种活动，很喜庆，人气旺！', '2024-02-11', 5, '交通便利性');
