INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d20e3c98b0941765aec', '酒店大堂装扮的非常喜庆，有舞龙舞狮表演，房间还有水果小吃赠送，服务员都非常热情，就是酒店实在太老旧了。', '["https://dimg04.c-ctrip.com/images/0236012000d6hme8xD28B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000d6i0jgz1D03_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237012000d6hyesv807F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000d6i1s9c8433_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-11', '花园双床房', '双床房', '家庭亲子', 51, 3.951243718581428, 0, 0.0, 6, 1.9459101490553128, 7, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '酒店大堂装扮的非常喜庆，有舞龙舞狮表演，房间还有水果小吃赠送，服务员都非常热情，', '酒店大堂装扮的非常喜庆，有舞龙舞狮表演，房间还有水果小吃赠送，服务员都非常热情，就是酒店实在太老旧了。', '2024-02-11', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d20e3c98b0941765aed', '今后四十年的历史发展，酒店经历过一次客房升级但时至今日过去些年日客房室内还是稍显老态，由于全地毯铺设的原因一开始进屋有些许霉味，空调开了一会会好一点。虽是老酒店但酒店的床垫非常舒适支撑性很好，柔软度也高这个一点非常棒。选择入住这家酒店不单单只是客房的体验，更是为了来见证感受这家富有传奇色彩的酒店，邓公的题字，建筑设计大师贝老参与的酒店设计将结构美学与实用性应用到了极致，Y型建筑设计 使空间得到了极大的使用同时兼顾了每个房间的采光和视野 是一个了不起的设计。这趟酒店之旅不需此行，值得体验。', '["https://dimg04.c-ctrip.com/images/0235d12000ckmqlpy8B1A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236012000ckmqehlC273_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234m12000ckmrjgzF77D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000ckmvk1h2AB9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000ckmrmp6CCCF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000ckmuvsf3328_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231z12000ckmru10A045_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000ckmvk1j017D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f12000ckmloy3CBC6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-11-14', '花园大床房', '大床房', '家庭亲子', 246, 5.5093883366279774, 0, 0.0, 11, 2.4849066497880004, 9, '["房间设施", "整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '今后四十年的历史发展，酒店经历过一次客房升级但时至今日过去些年日客房室内还是稍显', '今后四十年的历史发展，酒店经历过一次客房升级但时至今日过去些年日客房室内还是稍显老态，由于全地毯铺设的原因一开始进屋有些许霉味，空调开了一会会好一点。虽是老酒店但酒店的床垫非常舒适支撑性很好，柔软度也高这个一点非常棒。选择入住这家酒店不单单只是客房的体验，更是为了来见证感受这家富有传奇色彩的酒店，邓公的题字，建筑设计大师贝老参与的酒店设计将结构美学与实用性应用到了极致，Y型建筑设计 使空间得到了极大的使用同时兼顾了每个房间的采光和视野 是一个了不起的设计。这趟酒店之旅不需此行，值得体验。', '2023-11-14', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d2ae3c98b0941765aee', '一家酒店可以看到改革开放的发展史，贝律铭的设计初稿，邓小平的题字，***的奠基，***的进口设备申请。酒店38年的历程里记录了太多的历史瞬间。
      原本冲着酒店的人文氛围去的，果然一到就发现值得打卡的地方甚多，自带的博物馆和mini画展也可以去看看。沁春园的锦鲤仿佛通灵一般，能与人亲热互动。
      由于抵达当天已近半夜，前台办理入住很慢，提前电话预约的房间预留完全没有作用（酒店热线的接线人员一问三不知，提出的合理要求都很勉强记录），安排在5楼完全不是协议中写的18到21层。房间设备也比较老旧，体验感比较差。第2天再三要求下换到19楼，可惜订的双床房变大床房，孩子爸爸睡不下了。房间安排上的混乱与拖延，这一点真的是让人无语。
      总体来说，酒店服务人员都是礼貌热情的，虽然业务能力不强，但还是给人宾至如归的感觉。由于正值中秋节，酒店也很应景地给客人准备了一盒??。除却客房安排和房间老旧有所欠缺外，还是值得入住的。', '["https://dimg04.c-ctrip.com/images/0230u12000cbvjwj01B30_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000cbvgtwaD7C5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000cbvbnujE9A0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000cbvdy5e3BC2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236y12000cbvccceA3A1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235k12000cbveox748CB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235x12000cbvfhd366B8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233s12000cbvjy4oEC00_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235212000cbvd22vCD45_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-10-05', '花园双床房', '双床房', '家庭亲子', 420, 6.042632833682381, 0, 0.0, 19, 2.995732273553991, 9, '["前台服务", "房间设施", "整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '一家酒店可以看到改革开放的发展史，贝律铭的设计初稿，邓小平的题字，***的奠基，', '一家酒店可以看到改革开放的发展史，贝律铭的设计初稿，邓小平的题字，***的奠基，***的进口设备申请。酒店38年的历程里记录了太多的历史瞬间。
      原本冲着酒店的人文氛围去的，果然一到就发现值得打卡的地方甚多，自带的博物馆和mini画展也可以去看看。沁春园的锦鲤仿佛通灵一般，能与人亲热互动。
      由于抵达当天已近半夜，前台办理入住很慢，提前电话预约的房间预留完全没有作用（酒店热线的接线人员一问三不知，提出的合理要求都很勉强记录），安排在5楼完全不是协议中写的18到21层。房间设备也比较老旧，体验感比较差。第2天再三要求下换到19楼，可惜订的双床房变大床房，孩子爸爸睡不下了。房间安排上的混乱与拖延，这一点真的是让人无语。
      总体来说，酒店服务人员都是礼貌热情的，虽然业务能力不强，但还是给人宾至如归的感觉。由于正值中秋节，酒店也很应景地给客人准备了一盒??。除却客房安排和房间老旧有所欠缺外，还是值得入住的。', '2023-10-05', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d2ae3c98b0941765aef', '住店很舒服，很喜欢接待我们的前台小姐姐，说话温柔，给我们很温暖的感觉。酒店的后花园也很棒，景色优美，如果能登小瀑布就更好了。', '["https://dimg04.c-ctrip.com/images/0230512000d36ri9d7966_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-31', '红棉大床套房', '套房', '家庭亲子', 62, 4.143134726391533, 0, 0.0, 10, 2.3978952727983707, 7, '["前台服务", "景观/朝向", "整体满意度"]'::jsonb, '前台服务', '景观/朝向', '整体满意度', '未知酒店', '未知地点', '匿名', '住店很舒服，很喜欢接待我们的前台小姐姐，说话温柔，给我们很温暖的感觉。酒店的后花', '住店很舒服，很喜欢接待我们的前台小姐姐，说话温柔，给我们很温暖的感觉。酒店的后花园也很棒，景色优美，如果能登小瀑布就更好了。', '2024-01-31', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d2ae3c98b0941765af0', '酒店大堂富丽堂皇，后花园也非常漂亮，服务态度好，卫生干净，唯一不足就是房间稍微小了一点，总体感受还是不错，值得入住', '["https://dimg04.c-ctrip.com/images/0233812000d6vdxyq9609_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000d6v5fr34138_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233m12000d6vf1dc4EF3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000d6vft6e42CB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000d6ve54sAE2F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-13', '花园双床房', '双床房', '家庭亲子', 57, 4.060443010546419, 0, 0.0, 14, 2.70805020110221, 7, '["整体满意度", "卫生状况", "房间设施"]'::jsonb, '整体满意度', '卫生状况', '房间设施', '未知酒店', '未知地点', '匿名', '酒店大堂富丽堂皇，后花园也非常漂亮，服务态度好，卫生干净，唯一不足就是房间稍微小', '酒店大堂富丽堂皇，后花园也非常漂亮，服务态度好，卫生干净，唯一不足就是房间稍微小了一点，总体感受还是不错，值得入住', '2024-02-13', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d2ae3c98b0941765af1', '作为携程的铂金会员升级了岭客汇的金卡，入住时升级了粤韵大床，因为才刚装修完没几年，环境自然是可以，且楼层服务员打扫房间很及时。但是花园大床房就不建议入住了，一进去房间就一股异味。早餐是在30楼用餐，品种较少，行政酒廊下午茶点心选择性也较少。游泳池是常温的，现在这个季节下水还是有点冷的。', '["https://dimg04.c-ctrip.com/images/0232512000cndbbpq628B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235o12000cndb99kF74A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231c12000cnddi9k28CA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230g12000cndbgzqCD8C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230712000cndl40d5F0C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-11-28', '花园大床房', '大床房', '家庭亲子', 143, 4.969813299576001, 0, 0.0, 8, 2.19722457733622, 8, '["房间设施", "餐饮设施", "公共设施"]'::jsonb, '房间设施', '餐饮设施', '公共设施', '未知酒店', '未知地点', '匿名', '作为携程的铂金会员升级了岭客汇的金卡，入住时升级了粤韵大床，因为才刚装修完没几年', '作为携程的铂金会员升级了岭客汇的金卡，入住时升级了粤韵大床，因为才刚装修完没几年，环境自然是可以，且楼层服务员打扫房间很及时。但是花园大床房就不建议入住了，一进去房间就一股异味。早餐是在30楼用餐，品种较少，行政酒廊下午茶点心选择性也较少。游泳池是常温的，现在这个季节下水还是有点冷的。', '2023-11-28', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d2ae3c98b0941765af2', '真不愧是中国首批5星酒店之一，房间非常舒适，服务一流！虽然中间出了点小插曲，但是非常及时和妥善的处理，令我感受到这酒店对客人那贴心的照顾。', '["https://dimg04.c-ctrip.com/images/0236x224x8tov0vzcAB94_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02350224x8tov6qxg7CC2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230c224x8tov307r7D17_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236a224x8tov4k991849_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02348224x8tov5tge6281_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f224x8tov5x4w48C3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236j224x8touz97q9044_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02341224x8touz97r45B1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231f224x8tov2lqpA209_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-04', '花园大床房', '大床房', '情侣出游', 69, 4.248495242049359, 0, 0.0, 7, 2.079441541679836, 8, '["整体满意度", "前台服务", "客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '真不愧是中国首批5星酒店之一，房间非常舒适，服务一流！虽然中间出了点小插曲，但是', '真不愧是中国首批5星酒店之一，房间非常舒适，服务一流！虽然中间出了点小插曲，但是非常及时和妥善的处理，令我感受到这酒店对客人那贴心的照顾。', '2024-01-04', 5, '整体满意度');
