INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d2ae3c98b0941765af5', '房间整体很不错，圣诞节装扮很漂亮。订的红棉大床，升级了粤韵大床。入住送了两只康乃馨。早餐好吃，瀑布餐厅漂亮。买了纪念品给家人和孩子。除了一楼大厅香味过浓，床太软，其他都挺好。', '["https://dimg04.c-ctrip.com/images/0235q12000cqggj5k4758_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233812000cqgfo21B2B6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000cqgffs30305_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232712000cqggjesBEB1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236r12000cqgg919B0A3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v12000cqggpxbF60B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230312000cqgglhj3AF2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-14', '红棉大床套房', '套房', '家庭亲子', 87, 4.477336814478207, 0, 0.0, 9, 2.302585092994046, 8, '["整体满意度", "餐饮设施", "房间设施"]'::jsonb, '整体满意度', '餐饮设施', '房间设施', '未知酒店', '未知地点', '匿名', '房间整体很不错，圣诞节装扮很漂亮。订的红棉大床，升级了粤韵大床。入住送了两只康乃', '房间整体很不错，圣诞节装扮很漂亮。订的红棉大床，升级了粤韵大床。入住送了两只康乃馨。早餐好吃，瀑布餐厅漂亮。买了纪念品给家人和孩子。除了一楼大厅香味过浓，床太软，其他都挺好。', '2023-12-14', 5, '整体满意度');
