INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d36e3c98b0941765aff', '房间比较干净，环境很好，设施比较齐全，服务态度非常好', '["https://dimg04.c-ctrip.com/images/0235412000dhyhjfx7BA7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000dhyi7f7ED70_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236w12000dhyhjg157B3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-25', '花园大床房', '大床房', '家庭亲子', 26, 3.295836866004329, 0, 0.0, 1, 0.6931471805599453, 6, '["卫生状况", "整体满意度", "前台服务"]'::jsonb, '卫生状况', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '房间比较干净，环境很好，设施比较齐全，服务态度非常好', '房间比较干净，环境很好，设施比较齐全，服务态度非常好', '2024-03-25', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d36e3c98b0941765b00', '上年中秋来攞月饼就觉得好靓，今次终于有机会来住几日好开心。不愧系老字号酒店，装修风格特别有香港新加波D feel，出去逛圈成条环市东路都好有历史沉淀。花花草草同埋锦鲤都好靓，仲喺花店看到蓝Vanda。服务亦都唔错，话间房出边好吵就即刻同我换左去楼上。至于餐饮，食左酒店入边间日本料理同早餐只能够话无功无过，最开心系去对面友谊商店大快活食个咖喱鸡扒，隔离台个细路仔一直bie住我，仲攞支手枪biubiu下，哈哈见到佢地两仔爷钩起塞我d童年回忆，我细个时同老豆都系咁一起去食大快活，宜家霖起真系感概万千啊。', '["https://dimg04.c-ctrip.com/images/0233t2215gzzly9q84F3D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p2234d6py47hcB231_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231k2224x3cs1o1c970A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235i2224x3csso9d248C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234c2234d6pz05681069_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023152215gzzmv2a8FF98_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235p2224x3csy15s86F4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a2234d6pz17r4AF88_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230t2215gzznbzuo513C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-11-12', '花园大床房', '大床房', '商务出差', 251, 5.529429087511423, 0, 0.0, 5, 1.791759469228055, 9, '["整体满意度", "安静程度", "周边配套"]'::jsonb, '整体满意度', '安静程度', '周边配套', '未知酒店', '未知地点', '匿名', '上年中秋来攞月饼就觉得好靓，今次终于有机会来住几日好开心。不愧系老字号酒店，装修', '上年中秋来攞月饼就觉得好靓，今次终于有机会来住几日好开心。不愧系老字号酒店，装修风格特别有香港新加波D feel，出去逛圈成条环市东路都好有历史沉淀。花花草草同埋锦鲤都好靓，仲喺花店看到蓝Vanda。服务亦都唔错，话间房出边好吵就即刻同我换左去楼上。至于餐饮，食左酒店入边间日本料理同早餐只能够话无功无过，最开心系去对面友谊商店大快活食个咖喱鸡扒，隔离台个细路仔一直bie住我，仲攞支手枪biubiu下，哈哈见到佢地两仔爷钩起塞我d童年回忆，我细个时同老豆都系咁一起去食大快活，宜家霖起真系感概万千啊。', '2023-11-12', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d36e3c98b0941765b01', '走进酒店大堂就看见一个超大的漂亮圣诞??，即刻让人产生喜悦的心情。办理入住的客服经理非常耐心热情还送了欢迎入住的康乃馨。酒店房间很大，干净整洁。瀑布餐厅的自助早餐管理有序环境好，酒店的地理位置优越，出门散步享受美味都很方便，入住体验非常好', '["https://dimg04.c-ctrip.com/images/0235a12000cp9cplm3787_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000cp9b6u35D25_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000cp9cl6mA62F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p12000cp9dwoy712C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-08', '红棉双床套房', '套房', '家庭亲子', 119, 4.787491742782046, 0, 0.0, 7, 2.079441541679836, 8, '["整体满意度", "前台服务", "周边配套"]'::jsonb, '整体满意度', '前台服务', '周边配套', '未知酒店', '未知地点', '匿名', '走进酒店大堂就看见一个超大的漂亮圣诞??，即刻让人产生喜悦的心情。办理入住的客服', '走进酒店大堂就看见一个超大的漂亮圣诞??，即刻让人产生喜悦的心情。办理入住的客服经理非常耐心热情还送了欢迎入住的康乃馨。酒店房间很大，干净整洁。瀑布餐厅的自助早餐管理有序环境好，酒店的地理位置优越，出门散步享受美味都很方便，入住体验非常好', '2023-12-08', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d41e3c98b0941765b02', '第一次入住花园酒店，进门第一感觉就很吃惊，环境，服务都很好，荔湾亭早茶味道很棒，小朋友对蛋挞赞不绝口，下次来会继续选择', '["https://dimg04.c-ctrip.com/images/0235y12000d110rqr174C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000d10ryecD2EE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000d10ukcu81E6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000d118slzF64D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231l12000d10yvvlBE97_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000d114b4c56D5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000d10uwi07A44_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-24', '花园双床房', '双床房', '家庭亲子', 59, 4.0943445622221, 0, 0.0, 10, 2.3978952727983707, 7, '["餐饮设施", "整体满意度", "前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '第一次入住花园酒店，进门第一感觉就很吃惊，环境，服务都很好，荔湾亭早茶味道很棒，', '第一次入住花园酒店，进门第一感觉就很吃惊，环境，服务都很好，荔湾亭早茶味道很棒，小朋友对蛋挞赞不绝口，下次来会继续选择', '2024-01-24', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d41e3c98b0941765b03', '作为一名花园酒店三十年前的老员工，对花园有一种说不出的情感 这里是我梦想开始的地方，打开了我认识世界的第一道大门，那时候就觉得自己工作在这样豪华的酒店很不真实，丰富而美味的员工餐让我每天工作心情愉快，现在成为酒店的客人，从另一个角度用更成熟的心智带着更饱满的酒店业认知更加体会到酒店业的传承和花园的经久不衰，的确有它的无可代替的魅力，房间升级了，床品非常讲究，让每一个客人都拥有好的睡眠，隔音效果非常好，这也是与其它新酒店不同之处，以前的酒店建造真的真材实料。米其林餐厅各个出品精湛，口感和卖相都精益求精。酒店入住客人很多，但也稳中不乱。花园小径深处，流水潺潺，锦鲤酒店，锦鲤人生。感谢花园。', '["https://dimg04.c-ctrip.com/images/0234s12000chhi8e004FE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000chhmgnz6616_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000chhmmjc954D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236e12000chhlzis57B8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235h12000chhii9r2548_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236012000chhj0pc4946_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231l12000chhj6100EF3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236312000chhl0oh07CD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o12000chhi8je5844_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-31', '红棉大床套房', '套房', '家庭亲子', 296, 5.6937321388027, 3, 1.3862943611198906, 48, 3.8918202981106265, 9, '["整体满意度", "房间设施", "餐饮设施"]'::jsonb, '整体满意度', '房间设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '作为一名花园酒店三十年前的老员工，对花园有一种说不出的情感 这里是我梦想开始的地', '作为一名花园酒店三十年前的老员工，对花园有一种说不出的情感 这里是我梦想开始的地方，打开了我认识世界的第一道大门，那时候就觉得自己工作在这样豪华的酒店很不真实，丰富而美味的员工餐让我每天工作心情愉快，现在成为酒店的客人，从另一个角度用更成熟的心智带着更饱满的酒店业认知更加体会到酒店业的传承和花园的经久不衰，的确有它的无可代替的魅力，房间升级了，床品非常讲究，让每一个客人都拥有好的睡眠，隔音效果非常好，这也是与其它新酒店不同之处，以前的酒店建造真的真材实料。米其林餐厅各个出品精湛，口感和卖相都精益求精。酒店入住客人很多，但也稳中不乱。花园小径深处，流水潺潺，锦鲤酒店，锦鲤人生。感谢花园。', '2023-10-31', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d41e3c98b0941765b04', '酒店服务周到，酒店各处都洋溢着节日气氛，后花园景色很美！环境不错，工作人员服务热情，一次很好的入住体验！', '["https://dimg04.c-ctrip.com/images/0234f12000d6bb6r35677_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000d6bboanC65E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233b12000d6b8jmj1027_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234312000d6bay1o52CF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230m12000d6bbkgt43EF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233112000d6b8u8h7BA0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-11', '羊羊得意主题大床房', '主题房', '家庭亲子', 52, 3.970291913552122, 0, 0.0, 2, 1.0986122886681098, 6, '["整体满意度", "前台服务", "景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向', '未知酒店', '未知地点', '匿名', '酒店服务周到，酒店各处都洋溢着节日气氛，后花园景色很美！环境不错，工作人员服务热', '酒店服务周到，酒店各处都洋溢着节日气氛，后花园景色很美！环境不错，工作人员服务热情，一次很好的入住体验！', '2024-02-11', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d41e3c98b0941765b05', '房间翻新过，房间很新，服务很好，老牌底蕴，早餐很丰富有瀑布餐厅和30楼酒廊旋转餐厅，由于之前单间房间面积比较小，红棉双床房是两张1.1米的单人床带浴缸，最新翻新的粤韵双床房是1.3米的单人床，就没有浴缸空间了，粤韵大床房带浴缸。冬季泳池旁开了恒温按摩浴缸。酒店内有多家餐厅，这次在荔湾亭用餐，出品很棒！', '["https://dimg04.c-ctrip.com/images/0201r12000cmia0ey8C19_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0206r12000cmia57dC07E_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0235q12000cmhzsdsE7AD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230o12000cmi3blxAB7B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232h12000cmi3f12EDFB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236y12000cmi43b6C2B6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-23', '红棉双床套房', '套房', '朋友出游', 151, 5.0238805208462765, 1, 0.6931471805599453, 2, 1.0986122886681098, 9, '["房间设施", "餐饮设施", "公共设施"]'::jsonb, '房间设施', '餐饮设施', '公共设施', '未知酒店', '未知地点', '匿名', '房间翻新过，房间很新，服务很好，老牌底蕴，早餐很丰富有瀑布餐厅和30楼酒廊旋转餐', '房间翻新过，房间很新，服务很好，老牌底蕴，早餐很丰富有瀑布餐厅和30楼酒廊旋转餐厅，由于之前单间房间面积比较小，红棉双床房是两张1.1米的单人床带浴缸，最新翻新的粤韵双床房是1.3米的单人床，就没有浴缸空间了，粤韵大床房带浴缸。冬季泳池旁开了恒温按摩浴缸。酒店内有多家餐厅，这次在荔湾亭用餐，出品很棒！', '2023-11-23', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d41e3c98b0941765b06', '从服务到房间都很满意。酒店的装潢我定义为中式摩登，古典和现代相容并立，沉稳且桀骜，优雅且时尚。下次还会再来', '["https://dimg04.c-ctrip.com/images/0230v12000d49pbj3D3D1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-03', '花园双床房', '双床房', '家庭亲子', 53, 3.9889840465642745, 0, 0.0, 15, 2.772588722239781, 7, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '从服务到房间都很满意。酒店的装潢我定义为中式摩登，古典和现代相容并立，沉稳且桀骜', '从服务到房间都很满意。酒店的装潢我定义为中式摩登，古典和现代相容并立，沉稳且桀骜，优雅且时尚。下次还会再来', '2024-02-03', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d41e3c98b0941765b07', '一如既往的喜欢，虽然是老牌的酒店，管理很到位，服务很好，早餐也很丰盛', '["https://dimg04.c-ctrip.com/images/0231g12000dg93dks5DC4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000dg9jt2zB2BE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-19', '城央绿意大床房', '大床房', '商务出差', 34, 3.555348061489413, 0, 0.0, 33, 3.5263605246161616, 6, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '一如既往的喜欢，虽然是老牌的酒店，管理很到位，服务很好，早餐也很丰盛', '一如既往的喜欢，虽然是老牌的酒店，管理很到位，服务很好，早餐也很丰盛', '2024-03-19', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d41e3c98b0941765b08', '酒店外观很大气，很漂亮，房间都挺好的，干净清静，就是比较小，洗漱台也比较狭窄，卫生间的门和洗澡的门不能同时关上，这点不太方便！酒店的甜品很不错，有点小贵，早餐要早点去，人多会需要排队！', '["https://dimg04.c-ctrip.com/images/0235k12000colj5dz479A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230i12000colpojeC9FA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232w12000colf7nz7341_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-05', '花园双床房', '双床房', '家庭亲子', 92, 4.532599493153256, 1, 0.6931471805599453, 18, 2.9444389791664403, 7, '["房间设施", "卫生状况", "餐饮设施"]'::jsonb, '房间设施', '卫生状况', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店外观很大气，很漂亮，房间都挺好的，干净清静，就是比较小，洗漱台也比较狭窄，卫', '酒店外观很大气，很漂亮，房间都挺好的，干净清静，就是比较小，洗漱台也比较狭窄，卫生间的门和洗澡的门不能同时关上，这点不太方便！酒店的甜品很不错，有点小贵，早餐要早点去，人多会需要排队！', '2023-12-05', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d41e3c98b0941765b09', '入住体验不错。酒店大堂富丽堂皇，很气派，办理入住手续快捷，前台美女安排了一间相对安静的房间，如果酒店外围没施工入住体验会更好。房间布局合理设计风格很喜欢，有小会客室，看电视和房间休息互不干扰。最赞的就是酒店的服务质量，只要在公共区域停留或者疑惑的瞬间，都会有服务员询问是否需要帮助。不管是早餐还是午餐等服务接待都很彬彬有礼，温文尔雅，让人感到心情愉悦，以后到广州就首选花园酒店！', '["https://dimg04.c-ctrip.com/images/0230s12000cmp8mxuF12C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000cmp9v4xC9E8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235y12000cmpagy38C5B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-24', '红棉大床套房', '套房', '情侣出游', 189, 5.247024072160486, 0, 0.0, 5, 1.791759469228055, 8, '["整体满意度", "前台服务", "安静程度"]'::jsonb, '整体满意度', '前台服务', '安静程度', '未知酒店', '未知地点', '匿名', '入住体验不错。酒店大堂富丽堂皇，很气派，办理入住手续快捷，前台美女安排了一间相对', '入住体验不错。酒店大堂富丽堂皇，很气派，办理入住手续快捷，前台美女安排了一间相对安静的房间，如果酒店外围没施工入住体验会更好。房间布局合理设计风格很喜欢，有小会客室，看电视和房间休息互不干扰。最赞的就是酒店的服务质量，只要在公共区域停留或者疑惑的瞬间，都会有服务员询问是否需要帮助。不管是早餐还是午餐等服务接待都很彬彬有礼，温文尔雅，让人感到心情愉悦，以后到广州就首选花园酒店！', '2023-11-24', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d41e3c98b0941765b0a', '入住酒店时出乎意料地给我们升级成了套房，酒店服务很好，酒店的景致真是出乎意料的美丽，岭南风格的绿植及壁画互相映衬，市中心的酒店能有这么大的花园真的不容易。我们还参观了酒店博物馆。看到了酒店的发展史。下次去广州还想住这里', '["https://dimg04.c-ctrip.com/images/0232e12000cmao2j31B0C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c12000cmatzyz156E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000cmans9p14C4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-22', '花园双床房', '双床房', '商务出差', 109, 4.700480365792417, 0, 0.0, 11, 2.4849066497880004, 8, '["整体满意度", "景观/朝向", "前台服务"]'::jsonb, '整体满意度', '景观/朝向', '前台服务', '未知酒店', '未知地点', '匿名', '入住酒店时出乎意料地给我们升级成了套房，酒店服务很好，酒店的景致真是出乎意料的美', '入住酒店时出乎意料地给我们升级成了套房，酒店服务很好，酒店的景致真是出乎意料的美丽，岭南风格的绿植及壁画互相映衬，市中心的酒店能有这么大的花园真的不容易。我们还参观了酒店博物馆。看到了酒店的发展史。下次去广州还想住这里', '2023-11-22', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d41e3c98b0941765b0b', '酒店有文化沉淀，有独到设计，有中西交融，有优质服务，将花园特色融入每个角落，漂亮大气。值得一提的是服务人员都热情、礼貌、细心，前台靓女Gillian还在房间紧张的情况下，帮我解决了续住问题，非常感谢！', '["https://dimg04.c-ctrip.com/images/0232k12000cjk2t5g699A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i12000cjk53xs5990_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000cjk85v0EF5D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o12000cjkdi6e743B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000cjk7nq0FE51_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236012000cjkftpr9CD5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233n12000cjk78jlF854_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n12000cjkfvoy6A19_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233012000cjk6z4n8199_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-09', '花园大床房', '大床房', '情侣出游', 100, 4.61512051684126, 0, 0.0, 6, 1.9459101490553128, 9, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '酒店有文化沉淀，有独到设计，有中西交融，有优质服务，将花园特色融入每个角落，漂亮', '酒店有文化沉淀，有独到设计，有中西交融，有优质服务，将花园特色融入每个角落，漂亮大气。值得一提的是服务人员都热情、礼貌、细心，前台靓女Gillian还在房间紧张的情况下，帮我解决了续住问题，非常感谢！', '2023-11-09', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d4be3c98b0941765b0c', '酒店工作人员态度都非常好，尤其是前台小哥哥还帮忙升级了房型，孩子来广州参加比赛，休息的很好。酒店博物馆及小花园印象深刻。此次入住超值，下次来广州还会选择花园酒店。', '["https://dimg04.c-ctrip.com/images/0234k12000cr42x3pF132_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232u12000cr3xkpz4596_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-18', '红棉大床套房', '套房', '家庭亲子', 81, 4.406719247264253, 0, 0.0, 3, 1.3862943611198906, 7, '["前台服务", "整体满意度", "性价比"]'::jsonb, '前台服务', '整体满意度', '性价比', '未知酒店', '未知地点', '匿名', '酒店工作人员态度都非常好，尤其是前台小哥哥还帮忙升级了房型，孩子来广州参加比赛，', '酒店工作人员态度都非常好，尤其是前台小哥哥还帮忙升级了房型，孩子来广州参加比赛，休息的很好。酒店博物馆及小花园印象深刻。此次入住超值，下次来广州还会选择花园酒店。', '2023-12-18', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d4be3c98b0941765b0d', '大厅很气派，老牌酒店，卫生很好，周边热闹，吃饭什么都方便。离地铁站也近，地铁站就在酒店门口。有机会还会选择入住', '["https://dimg04.c-ctrip.com/images/0230912000d457ahaC733_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000d454drk57D6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233212000d457ejh205E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231p12000d456favA43B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-03', '花园大床房', '大床房', '家庭亲子', 55, 4.02535169073515, 0, 0.0, 94, 4.553876891600541, 6, '["交通便利性", "周边配套", "卫生状况"]'::jsonb, '交通便利性', '周边配套', '卫生状况', '未知酒店', '未知地点', '匿名', '大厅很气派，老牌酒店，卫生很好，周边热闹，吃饭什么都方便。离地铁站也近，地铁站就', '大厅很气派，老牌酒店，卫生很好，周边热闹，吃饭什么都方便。离地铁站也近，地铁站就在酒店门口。有机会还会选择入住', '2024-02-03', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d4be3c98b0941765b0e', '酒店看起来很大气，savanna小姐姐的服务超级好，长的很漂亮，也很可爱！太感谢savanna小姐姐了。下次入住还是找她帮忙办理！房间也很棒，装修等等也很有特色！抱着尝试的心态入住，没想到爱上了，又多住了几天！下次还一定来！', '["https://dimg04.c-ctrip.com/images/0236v12000cneo36tA742_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233u12000cneiewn349F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234t12000cneiafsEFA2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-28', '粤韵双床套房', '套房', '朋友出游', 112, 4.727387818712341, 0, 0.0, 5, 1.791759469228055, 7, '["前台服务", "整体满意度", "房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '酒店看起来很大气，savanna小姐姐的服务超级好，长的很漂亮，也很可爱！太感谢', '酒店看起来很大气，savanna小姐姐的服务超级好，长的很漂亮，也很可爱！太感谢savanna小姐姐了。下次入住还是找她帮忙办理！房间也很棒，装修等等也很有特色！抱着尝试的心态入住，没想到爱上了，又多住了几天！下次还一定来！', '2023-11-28', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d4be3c98b0941765b0f', '服务质量很高的一家老牌酒店。早餐很不错，瀑布餐厅很棒。床和枕头很舒服。恰逢周一，可惜这次没看到花园博物馆。', '["https://dimg04.c-ctrip.com/images/0235l12000d2o6s6tD29B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000d2o041k6FD0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000d2nurpq156A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-29', '花园双床房', '双床房', '家庭亲子', 53, 3.9889840465642745, 0, 0.0, 14, 2.70805020110221, 6, '["餐饮设施", "房间设施", "整体满意度"]'::jsonb, '餐饮设施', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '服务质量很高的一家老牌酒店。早餐很不错，瀑布餐厅很棒。床和枕头很舒服。恰逢周一，', '服务质量很高的一家老牌酒店。早餐很不错，瀑布餐厅很棒。床和枕头很舒服。恰逢周一，可惜这次没看到花园博物馆。', '2024-01-29', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d4be3c98b0941765b10', '酒店确实有点年代了，不过也恰好看到当年的情怀，红棉房感觉装修有点久远，设施一般般吧，位置确实很不错。也感谢酒店送了生日蛋糕，早餐环境很好（座位一般、人比较多要排队），总体说是不错的体验，性价比不算太好，不过老广东的过来住一下还是挺值得的。', '["https://dimg04.c-ctrip.com/images/0231112000cllxpb4D4A6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235712000cllxadwEB96_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231412000cllxqw4AAF9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233m12000clly5vr5790_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000clluxnj44DC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000cllxpb65F32_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-11-19', '红棉大床套房', '套房', '情侣出游', 119, 4.787491742782046, 0, 0.0, 14, 2.70805020110221, 7, '["性价比", "整体满意度", "房间设施"]'::jsonb, '性价比', '整体满意度', '房间设施', '未知酒店', '未知地点', '匿名', '酒店确实有点年代了，不过也恰好看到当年的情怀，红棉房感觉装修有点久远，设施一般般', '酒店确实有点年代了，不过也恰好看到当年的情怀，红棉房感觉装修有点久远，设施一般般吧，位置确实很不错。也感谢酒店送了生日蛋糕，早餐环境很好（座位一般、人比较多要排队），总体说是不错的体验，性价比不算太好，不过老广东的过来住一下还是挺值得的。', '2023-11-19', 4, '性价比');
