INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d58e3c98b0941765b1a', '花园酒店值得打卡，订的木棉双床，前台把房间升级到了粤韵，还送了康乃馨花，小小惊喜。酒店服务好，硬件好，景色美，文化底蕴深厚，就是早餐相对普通了', '["https://dimg04.c-ctrip.com/images/0230c12000cukqqgqE022_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000cukhaqe352D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f12000cuklajiAF17_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236m12000cukhpql5016_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231s12000cukh1dx2113_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-02', '红棉双床套房', '套房', '情侣出游', 71, 4.276666119016055, 0, 0.0, 5, 1.791759469228055, 8, '["整体满意度", "前台服务", "景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向', '未知酒店', '未知地点', '匿名', '花园酒店值得打卡，订的木棉双床，前台把房间升级到了粤韵，还送了康乃馨花，小小惊喜', '花园酒店值得打卡，订的木棉双床，前台把房间升级到了粤韵，还送了康乃馨花，小小惊喜。酒店服务好，硬件好，景色美，文化底蕴深厚，就是早餐相对普通了', '2024-01-02', 5, '整体满意度');
