INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d58e3c98b0941765b1c', '前台S小姐姐（忘了英文名了，只记得首字母是S）给免费升级到了套房，虽位于闹市，但房间很安静，干净整洁，书桌上放的旅游咨讯很有帮助。冲凉房的淋浴头用起来很舒服，床和被子睡着也很舒适，尤其是枕头，我是很挑枕头的，这个枕头一百分。早晨拉开窗帘，看见“小蛮腰”，美好的一天。', '["https://dimg04.c-ctrip.com/images/0236a12000clnp6xl7BF5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233a12000clnk5h0A959_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000clnlze7765E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234c12000clno2ybD50C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-19', '花园双床房', '双床房', '家庭亲子', 133, 4.897839799950911, 0, 0.0, 9, 2.302585092994046, 9, '["房间设施", "安静程度", "卫生状况"]'::jsonb, '房间设施', '安静程度', '卫生状况', '未知酒店', '未知地点', '匿名', '前台S小姐姐（忘了英文名了，只记得首字母是S）给免费升级到了套房，虽位于闹市，但', '前台S小姐姐（忘了英文名了，只记得首字母是S）给免费升级到了套房，虽位于闹市，但房间很安静，干净整洁，书桌上放的旅游咨讯很有帮助。冲凉房的淋浴头用起来很舒服，床和被子睡着也很舒适，尤其是枕头，我是很挑枕头的，这个枕头一百分。早晨拉开窗帘，看见“小蛮腰”，美好的一天。', '2023-11-19', 5, '房间设施');
