INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d63e3c98b0941765b21', '这次过年在广州花园酒店，很棒的一次旅行，服务态度非常好，什么是宾至如归，算是在这里体验到了', '["https://dimg04.c-ctrip.com/images/0230912000d6szjpq47AC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-12', '花园双床房', '双床房', '家庭亲子', 45, 3.828641396489095, 0, 0.0, 12, 2.5649493574615367, 6, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '这次过年在广州花园酒店，很棒的一次旅行，服务态度非常好，什么是宾至如归，算是在这', '这次过年在广州花园酒店，很棒的一次旅行，服务态度非常好，什么是宾至如归，算是在这里体验到了', '2024-02-12', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d63e3c98b0941765b22', '非常满意，出行之前看有些人说这个酒店太老了，推荐你们住什么四季，还有广州塔对面的那些酒店，其实没有很大用处，花园酒店毕竟是广州第一个国际酒店，不管是内饰还是整体都是很值得看一看，住一下，这次买了活动套餐。有行政走廊用餐，下午茶和晚餐小吃，在30楼，可以看风景喝点小酒，非常好，套餐还包括酒店人员带着介绍整个酒店的打卡点，可以让你完整的知道从酒店申请，到酒店部分风水细节，让你会有不一样的体验，没有这介绍可能很多细节都不会注意到，酒店整天服务很好，每一层会有专人在电梯口，早餐很丰富，很推荐住', '["https://dimg04.c-ctrip.com/images/0231412000clabutg5E01_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236812000cladvyx670D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233h12000cla8h8q8DC1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231c12000clafxip9664_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-17', '花园双床房', '双床房', '家庭亲子', 245, 5.5053315359323625, 0, 0.0, 5, 1.791759469228055, 9, '["整体满意度", "餐饮设施", "前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '非常满意，出行之前看有些人说这个酒店太老了，推荐你们住什么四季，还有广州塔对面的', '非常满意，出行之前看有些人说这个酒店太老了，推荐你们住什么四季，还有广州塔对面的那些酒店，其实没有很大用处，花园酒店毕竟是广州第一个国际酒店，不管是内饰还是整体都是很值得看一看，住一下，这次买了活动套餐。有行政走廊用餐，下午茶和晚餐小吃，在30楼，可以看风景喝点小酒，非常好，套餐还包括酒店人员带着介绍整个酒店的打卡点，可以让你完整的知道从酒店申请，到酒店部分风水细节，让你会有不一样的体验，没有这介绍可能很多细节都不会注意到，酒店整天服务很好，每一层会有专人在电梯口，早餐很丰富，很推荐住', '2023-11-17', 5, '整体满意度');
