INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d63e3c98b0941765b24', '房间干净整洁舒适', '["https://dimg04.c-ctrip.com/images/0230212000dsi0fwuF2BB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230i12000dshsf0o5781_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-26', '花园大床房', '大床房', '商务出差', 8, 2.19722457733622, 0, 0.0, 1, 0.6931471805599453, 4, '["卫生状况", "整体满意度"]'::jsonb, '卫生状况', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '房间干净整洁舒适', '房间干净整洁舒适', '2024-04-26', 5, '卫生状况');
