INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d63e3c98b0941765b26', '无论停车、服务、设施还是环境，各方面都OK的五星级酒店，送了花水果饮料，尤其是那个花园，早晨起来逛逛太美了，真是超级喜欢和享受的一天哦。', '["https://dimg04.c-ctrip.com/images/0234l12000culilcbE741_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231u12000culxrerD200_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000culo0laCBB8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000culz1daBA50_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-02', '花园双床房', '双床房', '情侣出游', 68, 4.23410650459726, 0, 0.0, 92, 4.532599493153256, 6, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '无论停车、服务、设施还是环境，各方面都OK的五星级酒店，送了花水果饮料，尤其是那', '无论停车、服务、设施还是环境，各方面都OK的五星级酒店，送了花水果饮料，尤其是那个花园，早晨起来逛逛太美了，真是超级喜欢和享受的一天哦。', '2024-01-02', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d63e3c98b0941765b27', '房间是发霉的，关于房间的其它就不想多说了！服务态度谈吐有点崇洋媚外的感觉，而且退房时的前台接待自我感觉莫名其妙的良好，一副不耐烦的样子！唯一值得表扬一点，地铁交通是便利的！', '["https://dimg04.c-ctrip.com/images/0236912000coeho8w5508_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000coebvmk36AC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236e12000coei3ap5DCA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236912000coed8t6547C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.7, 2, '2023-12-04', '花园双床房', '双床房', '家庭亲子', 86, 4.465908118654584, 9, 2.302585092994046, 9, 2.302585092994046, 7, '["房间设施", "前台服务", "交通便利性"]'::jsonb, '房间设施', '前台服务', '交通便利性', '未知酒店', '未知地点', '匿名', '房间是发霉的，关于房间的其它就不想多说了！服务态度谈吐有点崇洋媚外的感觉，而且退', '房间是发霉的，关于房间的其它就不想多说了！服务态度谈吐有点崇洋媚外的感觉，而且退房时的前台接待自我感觉莫名其妙的良好，一副不耐烦的样子！唯一值得表扬一点，地铁交通是便利的！', '2023-12-04', 2, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d63e3c98b0941765b28', '花园酒店名不虚传，宽敞的大堂，有瀑布的大花园，内容丰富的博物馆，无处不在的美丽鲜花，还有贴心的服务，让人宾至如归，下次再来??', '["https://dimg04.c-ctrip.com/images/0233912000cvrxj57ABC9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232s12000cvrxjskD92F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230w12000cvrxhc5C5AA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236u12000cvrxj5vC382_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-07', '红棉大床套房', '套房', '家庭亲子', 63, 4.158883083359672, 0, 0.0, 8, 2.19722457733622, 8, '["整体满意度", "公共设施", "前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务', '未知酒店', '未知地点', '匿名', '花园酒店名不虚传，宽敞的大堂，有瀑布的大花园，内容丰富的博物馆，无处不在的美丽鲜', '花园酒店名不虚传，宽敞的大堂，有瀑布的大花园，内容丰富的博物馆，无处不在的美丽鲜花，还有贴心的服务，让人宾至如归，下次再来??', '2024-01-07', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d63e3c98b0941765b29', '工作人员都很热情，Marry还帮我们布置了纪念日房间，服务态度非常好??
房间干净明亮，高楼层很安静
