INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d6ee3c98b0941765b2a', '携程活动时囤的券，非常划算。酒店景观很棒，入住时庆生，升级了房型。升级后的房型蛮大，做了生日布置，满意。checkin时等待时间有点长，还好我们有行政酒廊待遇，就先上去喝下午茶了。整体服务还不错，特别是行政酒廊的小姐姐，服务非常好，还记住我们喝的饮料。第二天恰逢周末，早餐大排长队，无奈只能打包回房间吃，这点看评论酒店一直有这个问题，希望能改善。', '["https://dimg04.c-ctrip.com/images/0236a12000cm6itmp1F11_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236q12000cm6f71u3824_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232g12000cm6cyo465E4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236y12000cm6b41v959A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-11-22', '花园双床房', '双床房', '家庭亲子', 173, 5.159055299214529, 0, 0.0, 6, 1.9459101490553128, 9, '["性价比", "景观/朝向", "退房/入住效率"]'::jsonb, '性价比', '景观/朝向', '退房/入住效率', '未知酒店', '未知地点', '匿名', '携程活动时囤的券，非常划算。酒店景观很棒，入住时庆生，升级了房型。升级后的房型蛮', '携程活动时囤的券，非常划算。酒店景观很棒，入住时庆生，升级了房型。升级后的房型蛮大，做了生日布置，满意。checkin时等待时间有点长，还好我们有行政酒廊待遇，就先上去喝下午茶了。整体服务还不错，特别是行政酒廊的小姐姐，服务非常好，还记住我们喝的饮料。第二天恰逢周末，早餐大排长队，无奈只能打包回房间吃，这点看评论酒店一直有这个问题，希望能改善。', '2023-11-22', 4, '性价比');
