INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d7ae3c98b0941765b35', '入住人很多，入住办了半个小时，大堂没有沙发，老人孩子就只能站在旁边等着，押金收的挺快，昨天一早退房就说可以了，押金原路返回，过了2天了，还没退，给前台打电话永远没人接，总之不适合家庭出游，这酒店只适合商务宴请接待外宾，带孩子老人出游慎选', '["https://dimg04.c-ctrip.com/images/0234e12000cjrx754B6B0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233s12000cjryu2b418A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000cjrvle2B4ED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-11-10', '花园大床房', '大床房', '家庭亲子', 118, 4.77912349311153, 1, 0.6931471805599453, 6, 1.9459101490553128, 8, '["退房/入住效率", "前台服务", "整体满意度"]'::jsonb, '退房/入住效率', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '入住人很多，入住办了半个小时，大堂没有沙发，老人孩子就只能站在旁边等着，押金收的', '入住人很多，入住办了半个小时，大堂没有沙发，老人孩子就只能站在旁边等着，押金收的挺快，昨天一早退房就说可以了，押金原路返回，过了2天了，还没退，给前台打电话永远没人接，总之不适合家庭出游，这酒店只适合商务宴请接待外宾，带孩子老人出游慎选', '2023-11-10', 4, '退房/入住效率');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d7ae3c98b0941765b36', '贝聿铭大师的杰作，虽然已经有40年历史，但仍没觉得过时。花园四季如春，锦鲤满池，环境优雅，个人感觉是广州最有味道的酒店。', '["https://dimg04.c-ctrip.com/images/0236812000cvr1d031698_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232n12000cvr1vgmA2D8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000cvqyr6n27CF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234g12000cvqz35k430A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234e12000cvqx05w2A07_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-07', '花园双床房', '双床房', '家庭亲子', 60, 4.110873864173311, 0, 0.0, 98, 4.59511985013459, 8, '["整体满意度", "景观/朝向"]'::jsonb, '整体满意度', '景观/朝向', NULL, '未知酒店', '未知地点', '匿名', '贝聿铭大师的杰作，虽然已经有40年历史，但仍没觉得过时。花园四季如春，锦鲤满池，', '贝聿铭大师的杰作，虽然已经有40年历史，但仍没觉得过时。花园四季如春，锦鲤满池，环境优雅，个人感觉是广州最有味道的酒店。', '2024-01-07', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d7ae3c98b0941765b37', '总体十分满意！基本每次出差都会选花园酒店落脚。地理位置优越，服务也比较好，酒店本身的厨房出菜品质就很好。美中不足酒店年头有点久了，有的房间是有点老旧的感觉…', '["https://dimg04.c-ctrip.com/images/0230x12000cu0plq7A807_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235012000cu0avs32657_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231e12000cu0giie1BF5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-12-30', '红棉大床套房', '套房', '商务出差', 78, 4.3694478524670215, 0, 0.0, 85, 4.454347296253507, 8, '["整体满意度", "交通便利性", "餐饮设施"]'::jsonb, '整体满意度', '交通便利性', '餐饮设施', '未知酒店', '未知地点', '匿名', '总体十分满意！基本每次出差都会选花园酒店落脚。地理位置优越，服务也比较好，酒店本', '总体十分满意！基本每次出差都会选花园酒店落脚。地理位置优越，服务也比较好，酒店本身的厨房出菜品质就很好。美中不足酒店年头有点久了，有的房间是有点老旧的感觉…', '2023-12-30', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d7ae3c98b0941765b38', '在携程上买了预售的红棉大床房加500餐饮额度的套餐，刚好来广州办事就预约了一个周六入住。最近好像广交会，入住的各国友人比较多，办入住的时候在前台等了很久，而且大厅也没有沙发让同伴坐一下的，这点体验不是很好，另外早餐也是在瀑布餐厅门口等了很久。酒店其他方面都还可以吧，硬件不错，床很舒服。', '["https://dimg04.c-ctrip.com/images/0235i12000cjc7l4n70B2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231m12000cjc3r8bDEA4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000cjc36ck4B15_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234112000cjc3fp03551_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230t12000cjbvbsb8C3F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231z12000cjc3phtDCFE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-11-08', '红棉大床套房', '套房', '朋友出游', 143, 4.969813299576001, 0, 0.0, 1, 0.6931471805599453, 7, '["前台服务", "退房/入住效率", "餐饮设施"]'::jsonb, '前台服务', '退房/入住效率', '餐饮设施', '未知酒店', '未知地点', '匿名', '在携程上买了预售的红棉大床房加500餐饮额度的套餐，刚好来广州办事就预约了一个周', '在携程上买了预售的红棉大床房加500餐饮额度的套餐，刚好来广州办事就预约了一个周六入住。最近好像广交会，入住的各国友人比较多，办入住的时候在前台等了很久，而且大厅也没有沙发让同伴坐一下的，这点体验不是很好，另外早餐也是在瀑布餐厅门口等了很久。酒店其他方面都还可以吧，硬件不错，床很舒服。', '2023-11-08', 4, '前台服务');
