INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d7ae3c98b0941765b3b', '著名的老酒店，春节?气氛浓郁，服务很好。餐厅价格好吃但很贵。房间地漏反臭', '["https://dimg04.c-ctrip.com/images/0234312000d9i2nzm4805_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000d9i1xxkAB77_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235012000d9htwh4EFD2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234w12000d9hp7ptA6C5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000d9i01xz53AE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000d9hsawk66F0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-02-21', '城央绿意双床房', '双床房', '独自旅行', 36, 3.610917912644224, 0, 0.0, 45, 3.828641396489095, 6, '["房间设施", "餐饮设施", "前台服务"]'::jsonb, '房间设施', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '著名的老酒店，春节?气氛浓郁，服务很好。餐厅价格好吃但很贵。房间地漏反臭', '著名的老酒店，春节?气氛浓郁，服务很好。餐厅价格好吃但很贵。房间地漏反臭', '2024-02-21', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d7ae3c98b0941765b3c', '虽然是老五星酒店，但整体服务、住宿环境都还是不错的。酒店环境是亮点，室外有假山、瀑布，有小桥流水，有锦鲤成群；室内有酒店历史陈列馆，有各种主题小馆。酒店地理位置也很好，出门就有地铁、公交。酒店床垫、隔音、空调都挺好的。稍有不足的是前台办理入住有点慢，部分员工服务意识还有待提升。', '["https://dimg04.c-ctrip.com/images/0232n12000d6cd9o28AA3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230o12000d6cqs85302C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236w12000d6cq5qkF451_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2024-02-11', '花园双床房', '双床房', '其他', 139, 4.941642422609304, 0, 0.0, 1, 0.6931471805599453, 9, '["整体满意度", "交通便利性", "房间设施"]'::jsonb, '整体满意度', '交通便利性', '房间设施', '未知酒店', '未知地点', '匿名', '虽然是老五星酒店，但整体服务、住宿环境都还是不错的。酒店环境是亮点，室外有假山、', '虽然是老五星酒店，但整体服务、住宿环境都还是不错的。酒店环境是亮点，室外有假山、瀑布，有小桥流水，有锦鲤成群；室内有酒店历史陈列馆，有各种主题小馆。酒店地理位置也很好，出门就有地铁、公交。酒店床垫、隔音、空调都挺好的。稍有不足的是前台办理入住有点慢，部分员工服务意识还有待提升。', '2024-02-11', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d7ae3c98b0941765b3d', '服务很专业，环境优美，后花园非常漂亮。', '["https://dimg04.c-ctrip.com/images/0230f224x8ubi89na6113_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-24', '花园大床房', '大床房', '朋友出游', 19, 2.995732273553991, 0, 0.0, 7, 2.079441541679836, 5, '["整体满意度", "公共设施"]'::jsonb, '整体满意度', '公共设施', NULL, '未知酒店', '未知地点', '匿名', '服务很专业，环境优美，后花园非常漂亮。', '服务很专业，环境优美，后花园非常漂亮。', '2024-03-24', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d85e3c98b0941765b3e', '到酒店发现酒店后面在施工，入住时，提出需要安静房间，前台给升级为粤韵房型。房间很卫生舒适，连洗漱用品都拼成了一幅画。酒店环境优美，特意去花园逛逛，很惬意。酒店里有博物馆，还在那里看见很有趣的玩具，给小朋友买了一个漂亮的拼车。在酒店遇到的每位服务人员都和善礼貌，会主动询问是否需要帮助。就是酒店的早餐稍显简单，味道一般。因为广交会，门口有舞狮祈福，舞狮班的人特别和善，可以帮助拍照合影。值得一住的酒店', '["https://dimg04.c-ctrip.com/images/0232212000citmh8sB859_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000citg6tc8C19_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233k12000citc2ss9119_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232i12000cithhqhC657_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-06', '红棉大床套房', '套房', '其他', 199, 5.298317366548036, 0, 0.0, 24, 3.218875824868201, 9, '["整体满意度", "前台服务", "安静程度"]'::jsonb, '整体满意度', '前台服务', '安静程度', '未知酒店', '未知地点', '匿名', '到酒店发现酒店后面在施工，入住时，提出需要安静房间，前台给升级为粤韵房型。房间很', '到酒店发现酒店后面在施工，入住时，提出需要安静房间，前台给升级为粤韵房型。房间很卫生舒适，连洗漱用品都拼成了一幅画。酒店环境优美，特意去花园逛逛，很惬意。酒店里有博物馆，还在那里看见很有趣的玩具，给小朋友买了一个漂亮的拼车。在酒店遇到的每位服务人员都和善礼貌，会主动询问是否需要帮助。就是酒店的早餐稍显简单，味道一般。因为广交会，门口有舞狮祈福，舞狮班的人特别和善，可以帮助拍照合影。值得一住的酒店', '2023-11-06', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d85e3c98b0941765b3f', '很贴心的酒店服务，下次出差还会选择出花园酒店', '["https://dimg04.c-ctrip.com/images/0231t12000di2mzj72B48_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236w12000di2nwct5F6D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-25', '红棉大床套房', '套房', '商务出差', 22, 3.1354942159291497, 0, 0.0, 4, 1.6094379124341005, 4, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '很贴心的酒店服务，下次出差还会选择出花园酒店', '很贴心的酒店服务，下次出差还会选择出花园酒店', '2024-03-25', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d85e3c98b0941765b40', '来广州住的第一个酒店，选择有很有历史底蕴的花园酒店，之前还担心这么“老”的酒店会不会有点陈旧，到了发现保养地还真的不错，前厅很气派，很有老牌酒店的韵味，国庆节入住，因为拖家带口，有老有小，选择付费升级了套房，第一眼的感觉很不错。酒店的服务很五星，有自己的博物馆，满满的历史感，还有邓爷题词的酒店名，户外游泳池已开放，国庆入住的几天，游泳的人也不多，可能都出去玩了，游泳池的服务到位。缺点的话，就是酒店确实年纪大了，有些隐蔽设施会有点问题，比如一间房的电话不能使用，另一间房的空调管堵塞，导致最后一天出现了漏水，湿了一片，不过响应及时，第一天的双床等了半天才打扫完，有点不爽，其他入住期间都很满意。', '["https://dimg04.c-ctrip.com/images/0230o12000cc8y9bv80A3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000cc8yvzoF309_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237412000cc8xl8c659C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000cc8yvzq71CF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000cc8u8xdD77D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235n12000cc8sjn892BB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000cc8ws6x1DAA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d12000cc8tcz68981_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233912000cc8vurlC95D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-06', '花园双床房', '双床房', '家庭亲子', 298, 5.700443573390687, 0, 0.0, 4, 1.6094379124341005, 9, '["房间设施", "整体满意度", "客房服务"]'::jsonb, '房间设施', '整体满意度', '客房服务', '未知酒店', '未知地点', '匿名', '来广州住的第一个酒店，选择有很有历史底蕴的花园酒店，之前还担心这么“老”的酒店会', '来广州住的第一个酒店，选择有很有历史底蕴的花园酒店，之前还担心这么“老”的酒店会不会有点陈旧，到了发现保养地还真的不错，前厅很气派，很有老牌酒店的韵味，国庆节入住，因为拖家带口，有老有小，选择付费升级了套房，第一眼的感觉很不错。酒店的服务很五星，有自己的博物馆，满满的历史感，还有邓爷题词的酒店名，户外游泳池已开放，国庆入住的几天，游泳的人也不多，可能都出去玩了，游泳池的服务到位。缺点的话，就是酒店确实年纪大了，有些隐蔽设施会有点问题，比如一间房的电话不能使用，另一间房的空调管堵塞，导致最后一天出现了漏水，湿了一片，不过响应及时，第一天的双床等了半天才打扫完，有点不爽，其他入住期间都很满意。', '2023-10-06', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d85e3c98b0941765b41', '不愧是老牌大酒店，装修大气上档次，房间干净整洁，床及床上用品非常的舒服，真的是一夜好眠，推荐大家一定要去尝尝他家的中餐菜品，绝了??！', '["https://dimg04.c-ctrip.com/images/0200812000dcmq9ibD3AA_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0231k12000dcmp3294F9D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232412000dcmon4h7CD1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233c12000dcmp32c5E83_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235412000dcmp32fB8EF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236w12000dcmp32jBCCB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232l12000dcmp14gD314_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235k12000dcmpalnE962_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235512000dcmp32tB312_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-05', '花园双床房', '双床房', '家庭亲子', 67, 4.219507705176107, 0, 0.0, 7, 2.079441541679836, 8, '["房间设施", "整体满意度", "卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '不愧是老牌大酒店，装修大气上档次，房间干净整洁，床及床上用品非常的舒服，真的是一', '不愧是老牌大酒店，装修大气上档次，房间干净整洁，床及床上用品非常的舒服，真的是一夜好眠，推荐大家一定要去尝尝他家的中餐菜品，绝了??！', '2024-03-05', 5, '房间设施');
