INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027d85e3c98b0941765b45', '朋友幸运Li，在酒店工作，见她推荐花园酒店赞不绝口，怎么也想住住看。
但过了两个月，竟然忘了评价。
白金五星名不虚传，广州花园酒店，是传闻中的天花板～
传奇酒店，华南地区唯一“白金五星”[强]，极尽奢华。
“几个米其林餐厅”和“花园博物馆”蕴含其中，拥有傲人的成绩和历史，比如：香港基本法的起草，亚运会的总部酒店，接待数位各国首相领导人等等；
??行政酒廊出花园便是锦鲤亭台瀑布，瀑布餐厅便是真正在造景瀑布旁边用餐，另外还有30楼旋转餐厅等共计9个餐厅酒吧等；
下午在锦鲤酒廊的Happy Hour其实和瀑布餐厅相连，也是边欣赏美景边用餐，晚上还是轻酒吧可小酌。
[玫瑰]或许因为年代有点久远，的确没有洲际瑰丽等那样的现代，但是花园的历史随着光阴反而越发有魅力。
在房间返修以后，大气依旧在，而大厅走廊各样的昂贵装饰和摆件，也及其奢华，看起来有老香港的感觉，但一切又很新。
总之就是那种，看上去浮夸奢侈，但其实蕴藏了文化很悠久的底蕴～', '["https://dimg04.c-ctrip.com/images/0235n12000cudth6p7F86_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b12000cudu0tw8E13_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235812000cudr36xE592_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000cudqof63965_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231612000cudqkbzF28C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234u12000cudp0hlA86E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231s12000cudv3ym87C2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234612000cudvusc934A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000cudttd5F536_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-01', '花园双床房', '双床房', '家庭亲子', 417, 6.035481432524756, 0, 0.0, 42, 3.7612001156935615, 9, '["整体满意度", "餐饮设施", "公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施', '未知酒店', '未知地点', '匿名', '朋友幸运Li，在酒店工作，见她推荐花园酒店赞不绝口，怎么也想住住看。', '朋友幸运Li，在酒店工作，见她推荐花园酒店赞不绝口，怎么也想住住看。
