INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027da1e3c98b0941765b53', '广州的老字号酒店，名不虚传，值得专门打卡，无论是吃饭还是住宿
位于市中心，楼下有地铁，出行便利。
房间翻新过，硬件设施很好，房间很大。特别喜欢那个大书桌，加班??绝配除了洗护用品不够高档，木有戴森，堪称完美
行政酒廊环境很好，食物简单，但是对付一口绰绰有余
酒店入住率相当高，但是服务，品质不打折。房间有酒店和周边介绍，感觉酒店就可以玩一整天
旁边在修地铁，白天是真的吵，晚上安静的', '["https://dimg04.c-ctrip.com/images/0230e12000cfio9kh09E1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232112000cfinwh1B25E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000cfio2bd165C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231t12000cfipg0lC745_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000cfiqjfkE103_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234212000cfis4rj5C05_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232512000cfisan54178_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000cfinm22B339_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-21', '红棉大床套房', '套房', '独自旅行', 196, 5.2832037287379885, 0, 0.0, 13, 2.6390573296152584, 8, '["整体满意度", "交通便利性", "房间设施"]'::jsonb, '整体满意度', '交通便利性', '房间设施', '未知酒店', '未知地点', '匿名', '广州的老字号酒店，名不虚传，值得专门打卡，无论是吃饭还是住宿', '广州的老字号酒店，名不虚传，值得专门打卡，无论是吃饭还是住宿
