INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027da1e3c98b0941765b57', '这次和家人来到广州游玩，入住了越秀区的广州花园酒店。团的是之前在携程订的套餐服务，有幸升级了套房。性价比上没得说，1600住了两晚。还有行政。李玉旋转餐厅的早餐。但是套房的缺点就是设施成就领域期的水忽冷忽热。正值楼下地铁施工，每天早上8点都会有。机器的声音伴随着闹钟声响虽然出门旅游不会睡懒觉，但是这个还是有一点美中不足。作为老牌酒店，他们的服务还是非常的不错，特别是在广交会期间。外国人虽然繁多，但是服务总体还是非常的热情，能够感受到五星级酒店的特殊。', '["https://dimg04.c-ctrip.com/images/0236912000cfpq051A9A1_R_150_150_R5_Q70_D.webp", "https://dimg04.c-ctrip.com/images/0232212000cfppthe1BDB_R_150_150_R5_Q70_D.webp", "https://dimg04.c-ctrip.com/images/0232c12000cfpomvyB81C_R_150_150_R5_Q70_D.webp"]'::jsonb, 4.7, 4, '2023-10-22', '花园大床房', '大床房', '朋友出游', 227, 5.429345628954441, 0, 0.0, 15, 2.772588722239781, 8, '["性价比", "房间设施", "安静程度"]'::jsonb, '性价比', '房间设施', '安静程度', '未知酒店', '未知地点', '匿名', '这次和家人来到广州游玩，入住了越秀区的广州花园酒店。团的是之前在携程订的套餐服务', '这次和家人来到广州游玩，入住了越秀区的广州花园酒店。团的是之前在携程订的套餐服务，有幸升级了套房。性价比上没得说，1600住了两晚。还有行政。李玉旋转餐厅的早餐。但是套房的缺点就是设施成就领域期的水忽冷忽热。正值楼下地铁施工，每天早上8点都会有。机器的声音伴随着闹钟声响虽然出门旅游不会睡懒觉，但是这个还是有一点美中不足。作为老牌酒店，他们的服务还是非常的不错，特别是在广交会期间。外国人虽然繁多，但是服务总体还是非常的热情，能够感受到五星级酒店的特殊。', '2023-10-22', 4, '性价比');
