INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dabe3c98b0941765b60', '这次选择了历史悠久的花园酒店 
1k+的2天1夜大床套餐真的很划算（含早+晚，叠叠高一份）check in的时候前台小姐姐还给宝宝送了冰箱贴 她好开心
??
本来我们套餐是花园大床 考虑到我们有宝宝 给我们升级到了红棉套房 比原来房间面积大了一倍 感谢酒店的贴心安排
房间里的缺点就是 老旧的味道有点点重 空调也是时不时会有很强的运转声音 其他都还阔以
枕头如果睡得不合适可以让服务员换的
??
选择这个酒店就是他们家好吃的特别多 荔湾亭和瀑布酒店我们都试了 真的不错 瀑布餐厅的自助晚餐我个人认为与其他酒店的自助晚餐都不太一样 菜式都比较有新意 味道也很不错 最近活动价388/位 推荐来试试 
荔湾亭的1蚊1碗豆腐花活动也是很惊艳 整体出品也在线 推荐
??
在花园酒店里面逛一天没有问题 还有博物馆可以参观（周一休馆）免费开放的
服务是不错的 工作人员都会耐心细致地回答我们提出的疑问', '["https://dimg04.c-ctrip.com/images/0232712000c8ygeki60A2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236j12000c8ycfubF6BF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231h12000c8y9vnw4FB4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000c8yhwi8C41E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000c8yeofl7B81_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235w12000c8y55gqA746_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235112000c8ybox7243C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235y12000c8yfk6e17DF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000c8ya08v6A94_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-09-26', '花园大床房', '大床房', '家庭亲子', 395, 5.981414211254481, 0, 0.0, 11, 2.4849066497880004, 9, '["性价比", "餐饮设施", "前台服务"]'::jsonb, '性价比', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '这次选择了历史悠久的花园酒店 ', '这次选择了历史悠久的花园酒店 
