INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dabe3c98b0941765b61', '酒店在老城区，外宾比较多。花园房型设施比较老旧，套房是新装修还可以。', '["https://dimg04.c-ctrip.com/images/0233p12000d6qc49e15DF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-02-12', '花园双床房', '双床房', '家庭亲子', 34, 3.555348061489413, 0, 0.0, 24, 3.218875824868201, 6, '["房间设施"]'::jsonb, '房间设施', NULL, NULL, '未知酒店', '未知地点', '匿名', '酒店在老城区，外宾比较多。花园房型设施比较老旧，套房是新装修还可以。', '酒店在老城区，外宾比较多。花园房型设施比较老旧，套房是新装修还可以。', '2024-02-12', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dabe3c98b0941765b62', '房间忘记拍摄了，非常不错床很舒服睡了好觉', '["https://dimg04.c-ctrip.com/images/0234e12000daukljxAA4C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000dauo4oiF4DE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-27', '花园双床房', '双床房', '商务出差', 20, 3.044522437723423, 0, 0.0, 27, 3.332204510175204, 4, '["房间设施", "整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '房间忘记拍摄了，非常不错床很舒服睡了好觉', '房间忘记拍摄了，非常不错床很舒服睡了好觉', '2024-02-27', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dabe3c98b0941765b63', '庆祝结婚纪念日，好多谢花园酒店为我们带来惊喜，不但布置了房间还送了一个漂亮的蛋糕，免费升级了房型，服务和环境非常nice，下次还会继续选择，感谢这次为我们服务的各位靓女们，非常感谢！??????????', '["https://dimg04.c-ctrip.com/images/0232212000ce0aofb268F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231b12000ce0ao2w3E4F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233212000ce0aknq02FA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233612000ce0aomz1FCB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000ce0ao475DD7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234412000ce0aozkD858_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236a12000ce0arpk0EFD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235712000ce0anqw5E98_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230h12000ce0at3l179C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-14', '红棉大床套房', '套房', '情侣出游', 101, 4.624972813284271, 0, 0.0, 2, 1.0986122886681098, 8, '["前台服务", "整体满意度", "客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务', '未知酒店', '未知地点', '匿名', '庆祝结婚纪念日，好多谢花园酒店为我们带来惊喜，不但布置了房间还送了一个漂亮的蛋糕', '庆祝结婚纪念日，好多谢花园酒店为我们带来惊喜，不但布置了房间还送了一个漂亮的蛋糕，免费升级了房型，服务和环境非常nice，下次还会继续选择，感谢这次为我们服务的各位靓女们，非常感谢！??????????', '2023-10-14', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dabe3c98b0941765b64', '花园作为老五星，不管是服务上还是设施上都应该有它的名字。
先说这次的不足：
①广交会期间，办理入住窗口仅开放两个，导致入住等待将近一个小时期间。办理入住是迎宾的第二道线，如果长时间焦灼等待，让本来就旅途疲惫的人打破第一印象。
②外宾与外地宾客的接待，服务上会有一定差异，可以理解是因为会议期间作为接待酒店，对外宾有相应的服务。但，是不是忽略了一些游客的感受
③临街地铁施工，非常吵。周末无休早8晚10，在办理入住时无人提示，导致好不容易办好入住，又需要调换房间。如实在是没有其他房间调换的宾客，也未提前准备耳塞。
再说下好的地方：
①服务：从迎宾至早上的贴心服务，礼宾部做到应该做的标准五星酒店应有的程度
②环境交通：相对交通便利，如果为了吃饭购物相对方便。
③卫生：卫生还是依旧很干净，部分配置相对老旧，但扛得住用
希望作为老五星，去其糟粕取其精华，越来越好', '["https://dimg04.c-ctrip.com/images/0233g12000ce8w41r8BE4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-15', '花园大床房', '大床房', '独自旅行', 381, 5.945420608606575, 0, 0.0, 2, 1.0986122886681098, 9, '["退房/入住效率", "安静程度", "整体满意度"]'::jsonb, '退房/入住效率', '安静程度', '整体满意度', '未知酒店', '未知地点', '匿名', '花园作为老五星，不管是服务上还是设施上都应该有它的名字。', '花园作为老五星，不管是服务上还是设施上都应该有它的名字。
