INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dc3e3c98b0941765b71', '每次到广州，心心念念就是花园酒店，第一批白金五星称号，全中国没几家，斥巨资、重服务，一进酒店大堂就能感受到富丽堂皇，金碧辉煌。一整面墙的红楼梦，古典、大气。
入住的时候，超级nice，因为带了小朋友，小朋友早班飞机很累，想提早入住，给了我们一间不错的房间，送了月饼送了早餐券送了很多欧舒丹洗漱用品，还有小玩具，也是这里有售卖的。
然后服务超级棒。
南航旗下，也会看到其他航空公司工作人员入住。', '["https://dimg04.c-ctrip.com/images/0234i12000cud57bi6563_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231q12000cud4oviF38B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230l12000cud3fw14F59_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232v12000cucyv1a9880_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234612000cud562l4EBF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235212000cud562nEEC7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000cud3il498D8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000cud087o4568_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000cud45573D0D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-01', '红棉双床套房', '套房', '家庭亲子', 196, 5.2832037287379885, 0, 0.0, 2, 1.0986122886681098, 9, '["前台服务", "整体满意度", "客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务', '未知酒店', '未知地点', '匿名', '每次到广州，心心念念就是花园酒店，第一批白金五星称号，全中国没几家，斥巨资、重服', '每次到广州，心心念念就是花园酒店，第一批白金五星称号，全中国没几家，斥巨资、重服务，一进酒店大堂就能感受到富丽堂皇，金碧辉煌。一整面墙的红楼梦，古典、大气。
入住的时候，超级nice，因为带了小朋友，小朋友早班飞机很累，想提早入住，给了我们一间不错的房间，送了月饼送了早餐券送了很多欧舒丹洗漱用品，还有小玩具，也是这里有售卖的。
然后服务超级棒。
