INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dc3e3c98b0941765b77', '感谢为我们升了房型，酒店非常漂亮，富丽堂皇的大堂，瀑布餐厅的景观，小桥流水，锦鲤，亭台楼阁都出乎意料；
