INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dc3e3c98b0941765b78', '房间很大，新装修的，很干净，服务也不错，本来订了红棉双床房，想换大床，前台小姐姐说大床房有点吵，直接给升级了，就是灯光还是传统老牌酒店的效果比较暗，如果有个白灯感觉更舒服一点，早餐餐厅的环境不错，选择不多，不过味道还挺好', '["https://dimg04.c-ctrip.com/images/0236p12000ccu5ch82E05_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236l12000ccu6l8c46CB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231i12000ccu747oCA44_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232d12000ccu6cdo9A4D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-08', '红棉双床套房', '套房', '家庭亲子', 110, 4.709530201312334, 0, 0.0, 4, 1.6094379124341005, 8, '["房间设施", "前台服务", "餐饮设施"]'::jsonb, '房间设施', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '房间很大，新装修的，很干净，服务也不错，本来订了红棉双床房，想换大床，前台小姐姐', '房间很大，新装修的，很干净，服务也不错，本来订了红棉双床房，想换大床，前台小姐姐说大床房有点吵，直接给升级了，就是灯光还是传统老牌酒店的效果比较暗，如果有个白灯感觉更舒服一点，早餐餐厅的环境不错，选择不多，不过味道还挺好', '2023-10-08', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dc3e3c98b0941765b79', '给男朋友庆生，check in的时候前台给升级了套房，并且客房在房间布置有一些花瓣和祝福，这让男朋友感到很惊喜和满意。晚餐是在瀑布餐厅吃的，环境OK，服务很好，服务员还端上生日蛋糕来给男朋友唱生日歌，美中不足的是自助餐的海鲜种类不是很丰富，晚上看瀑布的景不是很清晰', '["https://dimg04.c-ctrip.com/images/0234x2224wpiwfr4h8B1F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023472234csw2ixps4127_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234e2224wpiwge9uAD2F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234h2215gm5qe2jk7B32_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-08', '花园大床房', '大床房', '情侣出游', 132, 4.890349128221754, 0, 0.0, 2, 1.0986122886681098, 8, '["前台服务", "客房服务", "餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '给男朋友庆生，check in的时候前台给升级了套房，并且客房在房间布置有一些花', '给男朋友庆生，check in的时候前台给升级了套房，并且客房在房间布置有一些花瓣和祝福，这让男朋友感到很惊喜和满意。晚餐是在瀑布餐厅吃的，环境OK，服务很好，服务员还端上生日蛋糕来给男朋友唱生日歌，美中不足的是自助餐的海鲜种类不是很丰富，晚上看瀑布的景不是很清晰', '2023-10-08', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dcde3c98b0941765b7a', '国庆广州行，选择了花园酒店入住，酒店历史悠久，很有广州特色，每一位工作人员服务都非常好，入住1849房间，房间空间不大，床很舒适，客房服务也很细致入微。酒店处处是景，酒店里博物馆非常值得去看看，双瀑布花园很惊艳，很喜欢这里，酒店38周年了，服务绝对还是行业首屈一指??，来过你就能体会到，什么是用心的服务??有机会还会再来。', '["https://dimg04.c-ctrip.com/images/0231512000cbj7s298309_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000cbj7s2c17D9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000cbj56hkE144_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236012000cbj5swb1CF1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236k12000cbj6n5uA2B3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235w12000cbj55rw974F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000cbj6ni98565_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230812000cbj3tzaAD52_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000cbj6p1fB9A3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-03', '花园大床房', '大床房', '情侣出游', 162, 5.093750200806762, 0, 0.0, 20, 3.044522437723423, 9, '["整体满意度", "前台服务", "客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '国庆广州行，选择了花园酒店入住，酒店历史悠久，很有广州特色，每一位工作人员服务都', '国庆广州行，选择了花园酒店入住，酒店历史悠久，很有广州特色，每一位工作人员服务都非常好，入住1849房间，房间空间不大，床很舒适，客房服务也很细致入微。酒店处处是景，酒店里博物馆非常值得去看看，双瀑布花园很惊艳，很喜欢这里，酒店38周年了，服务绝对还是行业首屈一指??，来过你就能体会到，什么是用心的服务??有机会还会再来。', '2023-10-03', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dcde3c98b0941765b7b', '房间干净，床品舒服。大堂富丽豪华，电梯多。花园人工瀑布正对餐厅，别据一格。
