INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dcde3c98b0941765b7e', '酒店繁华朵朵！前台小哥态度诚恳、美女温柔体贴给康乃馨花束！瀑布餐厅的服务员们敬业、菜品味道不错！30楼行政廊眼镜美女小周善解人意、可爱体贴！客房服务大姐到位！花园酒店的二天舒心安逸！', '["https://dimg04.c-ctrip.com/images/0234w12000cyxsayb4777_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233k12000cyxia0f6B4E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231k12000cyxo8z5812A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234112000cyxru5x38E1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000cyxx0uq8E65_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000cyxvmos5FDD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000cyxu7kgEBD6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-18', '花园大床房', '大床房', '情侣出游', 91, 4.5217885770490405, 1, 0.6931471805599453, 60, 4.110873864173311, 7, '["前台服务", "餐饮设施", "客房服务"]'::jsonb, '前台服务', '餐饮设施', '客房服务', '未知酒店', '未知地点', '匿名', '酒店繁华朵朵！前台小哥态度诚恳、美女温柔体贴给康乃馨花束！瀑布餐厅的服务员们敬业', '酒店繁华朵朵！前台小哥态度诚恳、美女温柔体贴给康乃馨花束！瀑布餐厅的服务员们敬业、菜品味道不错！30楼行政廊眼镜美女小周善解人意、可爱体贴！客房服务大姐到位！花园酒店的二天舒心安逸！', '2024-01-18', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dcde3c98b0941765b7f', '酒店比较旧，设施都有些旧，热水水温不太稳定，下水也不利索了。
但是但是但是……非常喜欢这种有历史感酒店，老派豪华酒店代表了一个城市的兴衰史。服务上感觉到浓厚的酒店文化，前台服务生给人感觉非常舒服，硬生生靠服务和充满时代感的设计赢得了我的喜爱。酒店里的早茶、博物馆、内部花园是亮点。', '["https://dimg04.c-ctrip.com/images/0233d12000ccde6asCC45_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235x12000ccdfvpp85C0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000ccdgpqfA2A7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-06', '花园大床房', '大床房', '其他', 140, 4.948759890378168, 0, 0.0, 34, 3.555348061489413, 9, '["房间设施", "前台服务", "整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店比较旧，设施都有些旧，热水水温不太稳定，下水也不利索了。', '酒店比较旧，设施都有些旧，热水水温不太稳定，下水也不利索了。
但是但是但是……非常喜欢这种有历史感酒店，老派豪华酒店代表了一个城市的兴衰史。服务上感觉到浓厚的酒店文化，前台服务生给人感觉非常舒服，硬生生靠服务和充满时代感的设计赢得了我的喜爱。酒店里的早茶、博物馆、内部花园是亮点。', '2023-10-06', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dcde3c98b0941765b80', '这次在花园酒店的入住体验堪称完美！从踏入大堂的那一刻起，就被优雅的壁画景观和温馨的氛围所吸引。花园大使Anna热情主动，服务细致入微，礼宾Wayne提前联系询问需求，专业周到，还有非常可爱的前台小姐姐小鱼小谢~而且房间视野超赞！房内设施现代齐全，床品柔软舒适。早餐种类丰富，蛋糕点心和现磨咖啡都很精致。退房时还收到了小礼物，全程体验无可挑剔，下次来city必须二刷！', '["https://dimg04.c-ctrip.com/images/0236012000jir3jwzD270_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234b12000jiswbwx2EE3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000jir37aeC721_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-04-03', '红棉大床套房', '套房', '情侣出游', 183, 5.214935757608986, 0, 0.0, 14, 2.70805020110221, 9, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '这次在花园酒店的入住体验堪称完美！从踏入大堂的那一刻起，就被优雅的壁画景观和温馨', '这次在花园酒店的入住体验堪称完美！从踏入大堂的那一刻起，就被优雅的壁画景观和温馨的氛围所吸引。花园大使Anna热情主动，服务细致入微，礼宾Wayne提前联系询问需求，专业周到，还有非常可爱的前台小姐姐小鱼小谢~而且房间视野超赞！房内设施现代齐全，床品柔软舒适。早餐种类丰富，蛋糕点心和现磨咖啡都很精致。退房时还收到了小礼物，全程体验无可挑剔，下次来city必须二刷！', '2025-04-03', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dcde3c98b0941765b81', '这是第二次入住花园酒店，回想第一次入住是2016年的冬天，距离这次已经7年时间了，但是花园酒店给我的感觉还是非常大的惊喜。从进入酒店开始就有很多小姐姐微笑的询问需要什么帮助，前台给了20楼的房间，视野很开阔，我还买了酒店的礼品小羊羊。第二天起床品尝了二楼的米其林餐厅荔湾亭，坐到了花船，环境食物茶水都好评。三楼餐厅没有来得及去品尝，下次再有机会吧。酒店里有20多处打卡打卡点，我们几乎都去了，后花园的瀑布和锦鲤真的很美，孩子看到鱼非常高兴，在花园里转了好几圈。房间设施齐全，虽然酒店年代已久，但是住着仍然很舒适，周边车站地铁和商场饭店都很齐全。酒店门口打车真的太方便了。这次看到奠基是1980年….居然和我同岁，哈哈??，下次来广州还是会入住花园酒店！', '["https://dimg04.c-ctrip.com/images/0231c12000cdgm5cl5124_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233312000cdgrdis4F59_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232512000cdgmfeq58C9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000cdgjq7615D6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234x12000cdgr5afC155_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234g12000cdgmv9j1EB9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232812000cdgm5cnFADD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234w12000cdgpa9eAD5C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-11', '花园双床房', '双床房', '家庭亲子', 326, 5.7899601708972535, 0, 0.0, 60, 4.110873864173311, 9, '["整体满意度", "周边配套", "前台服务"]'::jsonb, '整体满意度', '周边配套', '前台服务', '未知酒店', '未知地点', '匿名', '这是第二次入住花园酒店，回想第一次入住是2016年的冬天，距离这次已经7年时间了', '这是第二次入住花园酒店，回想第一次入住是2016年的冬天，距离这次已经7年时间了，但是花园酒店给我的感觉还是非常大的惊喜。从进入酒店开始就有很多小姐姐微笑的询问需要什么帮助，前台给了20楼的房间，视野很开阔，我还买了酒店的礼品小羊羊。第二天起床品尝了二楼的米其林餐厅荔湾亭，坐到了花船，环境食物茶水都好评。三楼餐厅没有来得及去品尝，下次再有机会吧。酒店里有20多处打卡打卡点，我们几乎都去了，后花园的瀑布和锦鲤真的很美，孩子看到鱼非常高兴，在花园里转了好几圈。房间设施齐全，虽然酒店年代已久，但是住着仍然很舒适，周边车站地铁和商场饭店都很齐全。酒店门口打车真的太方便了。这次看到奠基是1980年….居然和我同岁，哈哈??，下次来广州还是会入住花园酒店！', '2023-10-11', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dcde3c98b0941765b82', '粤韵房非常不错，白天下面在修路是有点声音，在客厅能听到一点，但是房间基本听不到
设施：相对旧一点，属于有点年代的味道
卫生：可以
环境：酒店装修有种穿越的感觉，装修非常的气质奢华，老钱风。非常不错（瀑布，小桥，肥嘟嘟的锦鲤）
服务：反应挺快，毕竟是白金，这方面可以的
