INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dd8e3c98b0941765b8a', '老牌酒店，火车站附近，有特色，花园漂亮，好看，自助餐也ok，住宿和服务都很不错。之前在这里参加过宴会，印象深刻，所以选择了这里。有机会再订。', '["https://dimg04.c-ctrip.com/images/0231z12000ckxc5vkBF00_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232v12000ckxc5vmC716_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234u12000ckxdyyp512E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-11-16', '花园大床房', '大床房', '商务出差', 70, 4.262679877041316, 0, 0.0, 31, 3.4657359027997265, 6, '["周边配套", "整体满意度", "餐饮设施"]'::jsonb, '周边配套', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '老牌酒店，火车站附近，有特色，花园漂亮，好看，自助餐也ok，住宿和服务都很不错。', '老牌酒店，火车站附近，有特色，花园漂亮，好看，自助餐也ok，住宿和服务都很不错。之前在这里参加过宴会，印象深刻，所以选择了这里。有机会再订。', '2023-11-16', 4, '周边配套');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dd8e3c98b0941765b8b', '国庆期间住了两晚，优点：1.酒店外观大气，花园瀑布很特别，不愧为90年代白金五星级酒店。2.不管是大厅还是楼道电梯口，都有服务员主动招呼，礼貌周到。3.酒店三楼的博物馆很棒，了解酒店业历史，有收获。4.淋浴喷头出水大洗浴畅快。
缺点：1.酒店挨着建设路一头在施工，白天机器轰鸣声很响影响休息。2.客房设施陈旧，说2019年有装修，不管是柜子，洗脸池，还是卫生间，都显得很老旧。3.床垫偏软，楼层高度偏低有压抑感。4.房间下水道有异味，半夜被熏醒。5.大厅有点暗，可能是国庆，也可能是里面餐厅较多，来来往往人多有闹市感。
总体评价，外观和软件五星酒店，房间和设施经济型，性价比不高。', '["https://dimg04.c-ctrip.com/images/0231w12000ccghxos50F5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000ccgeivb5FBE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232212000ccgfexx2CF0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.7, 2, '2023-10-07', '花园双床房', '双床房', '家庭亲子', 290, 5.673323267171493, 6, 1.9459101490553128, 4, 1.6094379124341005, 9, '["房间设施", "安静程度", "性价比"]'::jsonb, '房间设施', '安静程度', '性价比', '未知酒店', '未知地点', '匿名', '国庆期间住了两晚，优点：1.酒店外观大气，花园瀑布很特别，不愧为90年代白金五星', '国庆期间住了两晚，优点：1.酒店外观大气，花园瀑布很特别，不愧为90年代白金五星级酒店。2.不管是大厅还是楼道电梯口，都有服务员主动招呼，礼貌周到。3.酒店三楼的博物馆很棒，了解酒店业历史，有收获。4.淋浴喷头出水大洗浴畅快。
缺点：1.酒店挨着建设路一头在施工，白天机器轰鸣声很响影响休息。2.客房设施陈旧，说2019年有装修，不管是柜子，洗脸池，还是卫生间，都显得很老旧。3.床垫偏软，楼层高度偏低有压抑感。4.房间下水道有异味，半夜被熏醒。5.大厅有点暗，可能是国庆，也可能是里面餐厅较多，来来往往人多有闹市感。
总体评价，外观和软件五星酒店，房间和设施经济型，性价比不高。', '2023-10-07', 2, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dd8e3c98b0941765b8c', '服务态度很好，提前电话确认出行人数和是否有特殊要求，安排好孩子的洗漱用品和拖鞋，入住期间卫生做的也很到位。距离各旅游景点都不远，地铁站也很近，对面的广州酒家早茶很不错，酒店唯一需要改进的是28层的早餐，味道太一般了。生日的这天酒店准备了生日蛋糕非常贴心和感动，推荐亲子休闲游的入住。', '["https://dimg04.c-ctrip.com/images/0233u12000cbxxmfj982A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235y12000cbxwjqm3FCD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236812000cbxzvv62034_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233y12000cbxw8g5BF6F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-05', '红棉大床套房', '套房', '家庭亲子', 141, 4.955827057601261, 0, 0.0, 10, 2.3978952727983707, 9, '["前台服务", "交通便利性", "周边配套"]'::jsonb, '前台服务', '交通便利性', '周边配套', '未知酒店', '未知地点', '匿名', '服务态度很好，提前电话确认出行人数和是否有特殊要求，安排好孩子的洗漱用品和拖鞋，', '服务态度很好，提前电话确认出行人数和是否有特殊要求，安排好孩子的洗漱用品和拖鞋，入住期间卫生做的也很到位。距离各旅游景点都不远，地铁站也很近，对面的广州酒家早茶很不错，酒店唯一需要改进的是28层的早餐，味道太一般了。生日的这天酒店准备了生日蛋糕非常贴心和感动，推荐亲子休闲游的入住。', '2023-10-05', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dd8e3c98b0941765b8d', '花园酒店不愧为广州市地标建筑，虽然节日期间客人暴多，但是整个大堂井然有序。接待员在了解我们想要加床就给我们升级到套间房，等我们入住时外加的床都已经铺好，且洗漱用品都变成了3位，可见酒店服务的细心周到。早餐人多，但是排队等位也很快，都有服务员引导，不会让人感觉乱糟糟的，也不会有人抢位置。', '["https://dimg04.c-ctrip.com/images/0232j12000cbjawpv91D1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234a12000cbje105EB43_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000cbjeto5AA25_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234z12000cbjfcbz56D9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234512000cbjhb3248E0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000cbjd9iv5DC7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232212000cbjevkx5191_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-03', '花园双床房', '双床房', '朋友出游', 143, 4.969813299576001, 1, 0.6931471805599453, 16, 2.833213344056216, 9, '["前台服务", "客房服务", "餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '花园酒店不愧为广州市地标建筑，虽然节日期间客人暴多，但是整个大堂井然有序。接待员', '花园酒店不愧为广州市地标建筑，虽然节日期间客人暴多，但是整个大堂井然有序。接待员在了解我们想要加床就给我们升级到套间房，等我们入住时外加的床都已经铺好，且洗漱用品都变成了3位，可见酒店服务的细心周到。早餐人多，但是排队等位也很快，都有服务员引导，不会让人感觉乱糟糟的，也不会有人抢位置。', '2023-10-03', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027de5e3c98b0941765b8e', '一天换三房，房间对铁轨施工，无语', '["https://dimg04.c-ctrip.com/images/0233212000dciyjgn0BFD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2024-03-05', '花园双床房', '双床房', '商务出差', 16, 2.833213344056216, 0, 0.0, 2, 1.0986122886681098, 5, '["安静程度", "客房服务"]'::jsonb, '安静程度', '客房服务', NULL, '未知酒店', '未知地点', '匿名', '一天换三房，房间对铁轨施工，无语', '一天换三房，房间对铁轨施工，无语', '2024-03-05', 3, '安静程度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027de5e3c98b0941765b8f', '一直拖着，现在才来点评。国庆节出行广州是临时起意，广州虽然去过多次，但是依然很喜欢。花园酒店是老五星酒店，有历史，有底蕴，是我喜欢的类型，又在市中心，做什么都方便。到店不仅送了生日蛋糕，还送了与博物馆联名的月饼，处处可见文化的味道。唯一有点遗憾的是国庆节的气温居然有35、36度，当然在酒店还是很舒服的，只想给个赞', '["https://dimg04.c-ctrip.com/images/0201r12000csbgtnn145E_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0235h12000csb8nt46839_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232w12000csb42xy1386_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231812000csb7msf4D71_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233212000csbfsb5813C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000csbf0hy8E6A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232w12000csbc5ugFF83_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-23', '花园双床房', '双床房', '家庭亲子', 157, 5.062595033026967, 0, 0.0, 4, 1.6094379124341005, 8, '["整体满意度", "周边配套", "前台服务"]'::jsonb, '整体满意度', '周边配套', '前台服务', '未知酒店', '未知地点', '匿名', '一直拖着，现在才来点评。国庆节出行广州是临时起意，广州虽然去过多次，但是依然很喜', '一直拖着，现在才来点评。国庆节出行广州是临时起意，广州虽然去过多次，但是依然很喜欢。花园酒店是老五星酒店，有历史，有底蕴，是我喜欢的类型，又在市中心，做什么都方便。到店不仅送了生日蛋糕，还送了与博物馆联名的月饼，处处可见文化的味道。唯一有点遗憾的是国庆节的气温居然有35、36度，当然在酒店还是很舒服的，只想给个赞', '2023-12-23', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027de5e3c98b0941765b90', '除了大堂像五星酒店，房间是超级小，连个四星的都不如，而且淋雨和浴缸在一起，要站在浴缸里才能淋浴。私密性超级差，关上洗澡间的门，厕所就没门了。床挨着洗手台，连个隔断都没有。还有我已经支付了房费，还收了我500元押金，今天都回来了，还没给我退款。这是啥操作？', '["https://dimg04.c-ctrip.com/images/0235g12000cb7n7za27D8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000cb7ejts40CC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.0, 3, '2023-10-02', '花园双床房', '双床房', '家庭亲子', 127, 4.852030263919617, 0, 0.0, 3, 1.3862943611198906, 9, '["房间设施", "退房/入住效率"]'::jsonb, '房间设施', '退房/入住效率', NULL, '未知酒店', '未知地点', '匿名', '除了大堂像五星酒店，房间是超级小，连个四星的都不如，而且淋雨和浴缸在一起，要站在', '除了大堂像五星酒店，房间是超级小，连个四星的都不如，而且淋雨和浴缸在一起，要站在浴缸里才能淋浴。私密性超级差，关上洗澡间的门，厕所就没门了。床挨着洗手台，连个隔断都没有。还有我已经支付了房费，还收了我500元押金，今天都回来了，还没给我退款。这是啥操作？', '2023-10-02', 3, '房间设施');
