INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027de5e3c98b0941765b93', '吹爆这家酒店的服务！
一到酒店门口，礼宾就冲过来帮我拿行李箱，还和我说登记后叫我找他们拿行李去房间；前台check in给升级了套房；到了楼层上，老妈拖着箱子拖不动，客房服务经理看到马上过来帮我们推到房间。到房间后，打电话问客房服务有没有宝宝拖鞋，五分钟后马上有阿姨送来宝宝拖鞋宝宝牙刷宝宝洗发水沐浴露。真的太棒了。
酒店虽然是老酒店，但是维护的很好，环境各方面都很好。
周边集吃住行一体，楼下就是地铁站，对面是什么商场。下次来还住这！', '["https://dimg04.c-ctrip.com/images/0234z12000dd39ygy784A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232u12000dd3ad7f47B0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-07', '花园大床房', '大床房', '家庭亲子', 218, 5.389071729816501, 0, 0.0, 7, 2.079441541679836, 9, '["前台服务", "客房服务", "交通便利性"]'::jsonb, '前台服务', '客房服务', '交通便利性', '未知酒店', '未知地点', '匿名', '吹爆这家酒店的服务！', '吹爆这家酒店的服务！
