INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027de5e3c98b0941765b94', '谢谢携程这次套餐活动很给力！
酒店住了2晚，有褒有贬，但瑕不掩瑜！
第一天check-in,前台 Gillian 很热情地送了3支康乃馨，感觉很温馨！很巧，check out 也是她！我要特别感谢3位不知名的工作人员，一位是前台帅帅的老外好像是明先生，29号当我外面回来时发现房卡开不了门了，刚到大厅他就问我有什么需要帮忙的吗，经核实确认我订了2晚的房间后主动给我延房以表歉意！另一位是30号下午5点的金牌讲解员，虽然只有我一个人听讲，他依然非常专业认真，非常nice!让我进一步了解了酒店！也能感受到他对酒店的热爱！另一位要感谢的是30号下午我在听讲解时主动帮我去拿袋子装外套的一位穿金色连衣裙的前台小姐姐！当然还有餐厅、客房的服务都非常好??
扣分的是：我到机场收到邮件发现发票只开了一晚，打电话过去说马上补开，至今未收到！', '["https://dimg04.c-ctrip.com/images/0231a12000d3xhvipDEC3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236z12000d3xorp141CF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000d3xzhi534E0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235d12000d3xqzap3E3D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234312000d3y0edgDEAC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-02-02', '红棉大床套房', '套房', '商务出差', 364, 5.899897353582492, 0, 0.0, 21, 3.091042453358316, 8, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '谢谢携程这次套餐活动很给力！', '谢谢携程这次套餐活动很给力！
酒店住了2晚，有褒有贬，但瑕不掩瑜！
第一天check-in,前台 Gillian 很热情地送了3支康乃馨，感觉很温馨！很巧，check out 也是她！我要特别感谢3位不知名的工作人员，一位是前台帅帅的老外好像是明先生，29号当我外面回来时发现房卡开不了门了，刚到大厅他就问我有什么需要帮忙的吗，经核实确认我订了2晚的房间后主动给我延房以表歉意！另一位是30号下午5点的金牌讲解员，虽然只有我一个人听讲，他依然非常专业认真，非常nice!让我进一步了解了酒店！也能感受到他对酒店的热爱！另一位要感谢的是30号下午我在听讲解时主动帮我去拿袋子装外套的一位穿金色连衣裙的前台小姐姐！当然还有餐厅、客房的服务都非常好??
扣分的是：我到机场收到邮件发现发票只开了一晚，打电话过去说马上补开，至今未收到！', '2024-02-02', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027de5e3c98b0941765b95', '女儿特别满意，尤其是露天游泳池，有特饮赠送，水质水温都很好。玩得不肯走。
房间设施标准很高，有咖啡机。装修时间长了，家具和地板有年代感，但卫生很好。没有浴缸是个瑕疵。洗浴用品是进口的，品质不错。总在外面玩，没看电视。不评论。
瀑布餐厅环境不错，早餐食物出品不错。口味中规中矩。
就是办理入住，拿到房卡时间超出预期，节日期间可以理解。期间有表演，小朋友还收到了礼物。', '["https://dimg04.c-ctrip.com/images/0230t12000cb5cl1n0975_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c12000cb5jg0v3446_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235z12000cb5gyme5C9B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-10-02', '花园双床房', '双床房', '家庭亲子', 182, 5.209486152841421, 0, 0.0, 10, 2.3978952727983707, 8, '["公共设施", "房间设施", "退房/入住效率"]'::jsonb, '公共设施', '房间设施', '退房/入住效率', '未知酒店', '未知地点', '匿名', '女儿特别满意，尤其是露天游泳池，有特饮赠送，水质水温都很好。玩得不肯走。', '女儿特别满意，尤其是露天游泳池，有特饮赠送，水质水温都很好。玩得不肯走。
