INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027de5e3c98b0941765b96', '订了二间二晚房无烟房！酒店大堂很气派公共区域宽敞大气：还有酒店?博物馆?瀑布，?入住时前台接待说给一间安静房一间吵的（下面在施工）我说我睡眠不好要静的：，她说那要停一段时间！结果等了很晚给进房！晚上睡时一阵一阵香烟味狐臭味通过排风送入房，打电话给?前台说要叫工程人员进门看，我说巳经睡了（其实是酒店陈旧）第二天一大早?下面施工开始吵（说了要安静房）马上去前台说了情况要求换房！结果等到下午3点换到上面－层还是这种情况的房间…无语。                            房间很?紧凑洗漱台紧挨着床不到半步。                                酒店进出方便，旁边5号线！', '["https://dimg04.c-ctrip.com/images/0236312000cbeojhg8C1E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.2, 1, '2023-10-03', '花园双床房', '双床房', '家庭亲子', 306, 5.726847747587197, 2, 1.0986122886681098, 6, 1.9459101490553128, 8, '["安静程度", "前台服务", "房间设施"]'::jsonb, '安静程度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '订了二间二晚房无烟房！酒店大堂很气派公共区域宽敞大气：还有酒店?博物馆?瀑布，?', '订了二间二晚房无烟房！酒店大堂很气派公共区域宽敞大气：还有酒店?博物馆?瀑布，?入住时前台接待说给一间安静房一间吵的（下面在施工）我说我睡眠不好要静的：，她说那要停一段时间！结果等了很晚给进房！晚上睡时一阵一阵香烟味狐臭味通过排风送入房，打电话给?前台说要叫工程人员进门看，我说巳经睡了（其实是酒店陈旧）第二天一大早?下面施工开始吵（说了要安静房）马上去前台说了情况要求换房！结果等到下午3点换到上面－层还是这种情况的房间…无语。                            房间很?紧凑洗漱台紧挨着床不到半步。                                酒店进出方便，旁边5号线！', '2023-10-03', 1, '安静程度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027de5e3c98b0941765b97', '由于带着小朋友入住 双床不能拼 给换了大床酒店免费给加了一张小床 服务十分之贴心周到 美中不足的就是周边的施工就算是放假期间还是早上七点就开工 给酒店的服务增加了不少难度 但也丝毫不影响我们全家对酒店的服务打好评', '["https://dimg04.c-ctrip.com/images/0234b12000cbkwmooCA63_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233j12000cbkvjqk2B17_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235q12000cbl0abb5A28_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-04', '红棉双床套房', '套房', '家庭亲子', 106, 4.672828834461906, 0, 0.0, 6, 1.9459101490553128, 8, '["客房服务", "安静程度", "整体满意度"]'::jsonb, '客房服务', '安静程度', '整体满意度', '未知酒店', '未知地点', '匿名', '由于带着小朋友入住 双床不能拼 给换了大床酒店免费给加了一张小床 服务十分之贴心', '由于带着小朋友入住 双床不能拼 给换了大床酒店免费给加了一张小床 服务十分之贴心周到 美中不足的就是周边的施工就算是放假期间还是早上七点就开工 给酒店的服务增加了不少难度 但也丝毫不影响我们全家对酒店的服务打好评', '2023-10-04', 5, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027df0e3c98b0941765b98', '国庆中秋双节出行，不仅免费升级成了套房，还送了两盒非常精美的月饼。
客房服务可以使用微信小程序，因为带了宝宝饮用水消耗特别大，点了送水服务后很快就送来了。
酒店的几个餐厅也非常nice，瀑布餐厅非常火爆。早晚都需要排队，但酒店工作人员安排得非常合理贴心，酒店环境也非常舒适，等待的过程并不会有不适的感觉；荔湾亭的菜品则是异常精致，口味也恰到好处~所有餐厅都有宝宝椅与宝宝餐具，非常贴心', '["https://dimg04.c-ctrip.com/images/0230c12000cc08qsb907E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-05', '红棉大床套房', '套房', '家庭亲子', 192, 5.262690188904886, 0, 0.0, 2, 1.0986122886681098, 9, '["客房服务", "餐饮设施", "整体满意度"]'::jsonb, '客房服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '国庆中秋双节出行，不仅免费升级成了套房，还送了两盒非常精美的月饼。', '国庆中秋双节出行，不仅免费升级成了套房，还送了两盒非常精美的月饼。
客房服务可以使用微信小程序，因为带了宝宝饮用水消耗特别大，点了送水服务后很快就送来了。
酒店的几个餐厅也非常nice，瀑布餐厅非常火爆。早晚都需要排队，但酒店工作人员安排得非常合理贴心，酒店环境也非常舒适，等待的过程并不会有不适的感觉；荔湾亭的菜品则是异常精致，口味也恰到好处~所有餐厅都有宝宝椅与宝宝餐具，非常贴心', '2023-10-05', 5, '客房服务');
