INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027df0e3c98b0941765b9d', '办入住送了一盒月饼，办退房又送了一盒月饼，小举动让这个异乡的中秋也是仪式感满满。一开始安排的房间对着施工工地，和前台沟通后爽快的换到了另一边。唯一一点小遗憾，办理入住排队很长，金卡会员的专门通道也没有开启，只能老老实实排了将近半小时。', '["https://dimg04.c-ctrip.com/images/0237412000cb4da3oF766_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-10-02', '花园大床房', '大床房', '家庭亲子', 117, 4.770684624465665, 0, 0.0, 12, 2.5649493574615367, 8, '["前台服务", "退房/入住效率", "整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度', '未知酒店', '未知地点', '匿名', '办入住送了一盒月饼，办退房又送了一盒月饼，小举动让这个异乡的中秋也是仪式感满满。', '办入住送了一盒月饼，办退房又送了一盒月饼，小举动让这个异乡的中秋也是仪式感满满。一开始安排的房间对着施工工地，和前台沟通后爽快的换到了另一边。唯一一点小遗憾，办理入住排队很长，金卡会员的专门通道也没有开启，只能老老实实排了将近半小时。', '2023-10-02', 4, '前台服务');
