INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027df0e3c98b0941765b9f', '对于这样五星的酒店来说我只想说没有下一次了，卫生环境差到极致，设施老旧，卫生间的浴缸根本不人性化，跨进跨出安全哪来？还有绝对没有隐私可言。隔音效果极差。我明明可以免升房型的话缺被告知房间满，但是愿意接受补差价的就可以升，这是什么服务。小孩牙刷和拖鞋需要每天打电话去要。感受太差。', '["https://dimg04.c-ctrip.com/images/0236o12000cbh8lvr2996_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230712000cbh5pbrF474_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230a12000cbh6kiiEF22_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232g12000cbhdihj8F45_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.5, 1, '2023-10-03', '花园双床房', '双床房', '家庭亲子', 139, 4.941642422609304, 2, 1.0986122886681098, 5, 1.791759469228055, 8, '["卫生状况", "房间设施", "安静程度"]'::jsonb, '卫生状况', '房间设施', '安静程度', '未知酒店', '未知地点', '匿名', '对于这样五星的酒店来说我只想说没有下一次了，卫生环境差到极致，设施老旧，卫生间的', '对于这样五星的酒店来说我只想说没有下一次了，卫生环境差到极致，设施老旧，卫生间的浴缸根本不人性化，跨进跨出安全哪来？还有绝对没有隐私可言。隔音效果极差。我明明可以免升房型的话缺被告知房间满，但是愿意接受补差价的就可以升，这是什么服务。小孩牙刷和拖鞋需要每天打电话去要。感受太差。', '2023-10-03', 1, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027df0e3c98b0941765ba0', '房间满意，免费升级的套房豪华舒适。早餐可以在一楼吃也可以在30楼的旋转餐厅吃，周到的服务真的有宾至如归的感觉', '["https://dimg04.c-ctrip.com/images/0234h12000cpqb67r4EBC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236v12000cpqa2zqECD9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231v12000cpqb68gBB15_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-11', '花园大床房', '大床房', '商务出差', 54, 4.007333185232471, 0, 0.0, 15, 2.772588722239781, 8, '["整体满意度", "餐饮设施", "前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '房间满意，免费升级的套房豪华舒适。早餐可以在一楼吃也可以在30楼的旋转餐厅吃，周', '房间满意，免费升级的套房豪华舒适。早餐可以在一楼吃也可以在30楼的旋转餐厅吃，周到的服务真的有宾至如归的感觉', '2023-12-11', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027df0e3c98b0941765ba1', '2025 年的第一次出行选择了广州，也是第一次来广州，不只是因为天气温暖宜人，更是因为广州有着国内最早的五星酒店。
对比之后订了广州花园酒店，体验贝律铭设计的酒店装修风格，酒店果然如其名，花园里瀑布鲜花绿草坪，五彩斑斓的锦鲤在池中畅游，酒店大堂装饰金碧辉煌，还有花园博物馆的展品，都是别具特色。此外，酒店的服务规范温馨，前台办理入住的美女 Rebecca 周到细致，还赠送了三只粉色康乃馨，入住后服务人员也十分有礼貌， 归属国内仅有的三家白金五星级酒店之榜的确恰如其分。', '["https://dimg04.c-ctrip.com/images/0230r12000i7ww745715E_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0236p12000i7wwvaj2FAB_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0237312000i7wx55k5C15_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0230y12000i7wsuoaA7A6_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0235912000i7wwzen60AA_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0235k12000i7wvcfb2FDB_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2025-02-01', '红棉大床套房', '套房', '家庭亲子', 235, 5.4638318050256105, 0, 0.0, 1, 0.6931471805599453, 9, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '2025 年的第一次出行选择了广州，也是第一次来广州，不只是因为天气温暖宜人，更', '2025 年的第一次出行选择了广州，也是第一次来广州，不只是因为天气温暖宜人，更是因为广州有着国内最早的五星酒店。
对比之后订了广州花园酒店，体验贝律铭设计的酒店装修风格，酒店果然如其名，花园里瀑布鲜花绿草坪，五彩斑斓的锦鲤在池中畅游，酒店大堂装饰金碧辉煌，还有花园博物馆的展品，都是别具特色。此外，酒店的服务规范温馨，前台办理入住的美女 Rebecca 周到细致，还赠送了三只粉色康乃馨，入住后服务人员也十分有礼貌， 归属国内仅有的三家白金五星级酒店之榜的确恰如其分。', '2025-02-01', 5, '整体满意度');
