INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dfae3c98b0941765ba3', '特别舒适这次给升级房间 22层小朱服务也很好', '["https://dimg04.c-ctrip.com/images/0237412000d8eu30qA19E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236712000d8f7kpl7040_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-18', '花园双床房', '双床房', '家庭亲子', 22, 3.1354942159291497, 2, 1.0986122886681098, 20, 3.044522437723423, 5, '["整体满意度", "前台服务"]'::jsonb, '整体满意度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '特别舒适这次给升级房间 22层小朱服务也很好', '特别舒适这次给升级房间 22层小朱服务也很好', '2024-02-18', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dfae3c98b0941765ba4', '超级赞的酒店！
设施：硬件很好，设施齐全。去之前看评论说室外泳池没开就没带泳衣，没想到住的两天都开放的，而且看起来很大很干净，没有体验到有点可惜。
服务：超级棒！工作人员很热情，客房服务响应及时。
环境：大堂超级大，但是有条有序。地理位置很方便，出门步行两分钟就能到达地铁站。环境更加没话说了，花园式的酒店，拥有双瀑布，使酒店显得更加豪华。
最后下飞机收到酒店的短信，提醒我有东西遗忘，联系后立马给我快递了出来，超级贴心有没有！100分！', '["https://dimg04.c-ctrip.com/images/0235v12000ccksq8r902D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233612000ccktzlsA3DA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000cckwel6ED38_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236512000cckthh82CD2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000cckrowz03F4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235x12000cckv5nxF45C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233j12000cckx8uo7442_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-07', '花园双床房', '双床房', '家庭亲子', 219, 5.393627546352362, 0, 0.0, 13, 2.6390573296152584, 9, '["公共设施", "前台服务", "交通便利性"]'::jsonb, '公共设施', '前台服务', '交通便利性', '未知酒店', '未知地点', '匿名', '超级赞的酒店！', '超级赞的酒店！
设施：硬件很好，设施齐全。去之前看评论说室外泳池没开就没带泳衣，没想到住的两天都开放的，而且看起来很大很干净，没有体验到有点可惜。
服务：超级棒！工作人员很热情，客房服务响应及时。
环境：大堂超级大，但是有条有序。地理位置很方便，出门步行两分钟就能到达地铁站。环境更加没话说了，花园式的酒店，拥有双瀑布，使酒店显得更加豪华。
最后下飞机收到酒店的短信，提醒我有东西遗忘，联系后立马给我快递了出来，超级贴心有没有！100分！', '2023-10-07', 5, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027dfae3c98b0941765ba5', '服务真的很好，入住送月饼，户外泳池游泳送饮料，每一层电梯厅都有服务人员，有问必答。花园很美，鱼很肥，酒店也很美，各处的设计用尽心思。瀑布早餐和30楼旋转早餐都不错，5星标准。唯一美中不足是房间的格局尤其是卫生间的隔断设计不太合理，灯光系统最好能全面分开。隔壁马路在施工，法定节假日7:30就开工，建议尽量避开21-34这些房间号。
