INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e0be3c98b0941765bad', '太惊喜了！
中秋节前一天入住，前台妹妹直接送了一盒月饼，还有康乃馨。
房间虽然比较老了，但很干净也很大。送的欢迎点心也是很应景的流心月饼，好好吃！客房真的是手写的欢迎函，很有心！
酒店的小花园和博物馆都很有意思。
晚餐在酒店的桃园馆订了套餐，非常惊喜，有创意，味道也是好吃的！
早餐可以在瀑布餐厅吃，但是太多人啦，于是去了旋转餐厅。煮河粉的时候真的给我了好多牛腩让我实现牛腩自由。
每个工作人员的服务意识都很强。', '["https://dimg04.c-ctrip.com/images/0230112000cdiaych5CF9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237112000cdias74EE04_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236m12000cdia0wn01E1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i12000cdi5vza4AC1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237312000cdidxit7058_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235212000cdi6mm1C694_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-12', '红棉大床套房', '套房', '朋友出游', 206, 5.332718793265369, 0, 0.0, 40, 3.713572066704308, 9, '["前台服务", "客房服务", "餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '太惊喜了！', '太惊喜了！
