INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e0be3c98b0941765bb5', '酒店各种人员都态度超好，外籍员工是最热情的，很喜欢。', '["https://dimg04.c-ctrip.com/images/0235m12000d2j7ruc99D5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000d2j20obB54A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237012000d2j8nxhA97C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-29', '花园双床房', '双床房', '家庭亲子', 26, 3.295836866004329, 0, 0.0, 3, 1.3862943611198906, 5, '["前台服务"]'::jsonb, '前台服务', NULL, NULL, '未知酒店', '未知地点', '匿名', '酒店各种人员都态度超好，外籍员工是最热情的，很喜欢。', '酒店各种人员都态度超好，外籍员工是最热情的，很喜欢。', '2024-01-29', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e16e3c98b0941765bb6', '第四次入住这家酒店，非常的不错', '["https://dimg04.c-ctrip.com/images/0236d12000d89wwaq746B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-17', '花园大床房', '大床房', '情侣出游', 15, 2.772588722239781, 0, 0.0, 2, 1.0986122886681098, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '第四次入住这家酒店，非常的不错', '第四次入住这家酒店，非常的不错', '2024-02-17', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e16e3c98b0941765bb7', '酒店很棒，服务也很棒，很多外宾、很多空姐空少都入住这家酒店，看到每位工作人员都能游刃有余的与外宾们沟通办理业务，大气高水准。房间里有两个洗漱台和两台电视，真是太方便了，还配备了胶囊咖啡机，入住时按人数赠送了酒吧体验券，可惜带着娃不方便，没能体验到，酒店里的花园和博物馆深得娃的喜爱，退房时还送了小礼品，开心。早餐在一楼的瀑布餐厅或二楼荔湾亭，一楼大多是外宾，西式早餐居多，二楼有中式早餐，一楼排队人太多了，工作人员引导至二楼用餐，餐食品种不算多，将就随便填些肚子，中午去顺德再吃丰盛点吧。对了，晚餐在荔湾亭，叉烧真是太好吃了，粥也很美味，地道的粤菜很棒，酒店博物馆里有不少收获，带娃参观酒店也算是不错的行程，千万别错过。', '["https://dimg04.c-ctrip.com/images/0234p12000btyg4vw063B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234412000btyd65v1522_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234j12000btygq5jE3FF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000btydn8v2C8B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000btyem3e62D6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230p12000btyb44u8712_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232l12000btygncpA41A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232n12000bty9zsr52FC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237412000btygrhwC9BB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-05', '花园大床房', '大床房', '家庭亲子', 310, 5.739792912179234, 4, 1.6094379124341005, 23, 3.1780538303479458, 9, '["房间设施", "整体满意度", "餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店很棒，服务也很棒，很多外宾、很多空姐空少都入住这家酒店，看到每位工作人员都能', '酒店很棒，服务也很棒，很多外宾、很多空姐空少都入住这家酒店，看到每位工作人员都能游刃有余的与外宾们沟通办理业务，大气高水准。房间里有两个洗漱台和两台电视，真是太方便了，还配备了胶囊咖啡机，入住时按人数赠送了酒吧体验券，可惜带着娃不方便，没能体验到，酒店里的花园和博物馆深得娃的喜爱，退房时还送了小礼品，开心。早餐在一楼的瀑布餐厅或二楼荔湾亭，一楼大多是外宾，西式早餐居多，二楼有中式早餐，一楼排队人太多了，工作人员引导至二楼用餐，餐食品种不算多，将就随便填些肚子，中午去顺德再吃丰盛点吧。对了，晚餐在荔湾亭，叉烧真是太好吃了，粥也很美味，地道的粤菜很棒，酒店博物馆里有不少收获，带娃参观酒店也算是不错的行程，千万别错过。', '2023-08-05', 5, '房间设施');
