INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e16e3c98b0941765bb9', '没住过服务这么好的酒店！！！每个服务人员，都非常贴心。包括每天打扫的阿姨！请重点表扬这几天打扫2049房间的阿姨，谢谢！几乎每天都会换床品，把房间打扫得干干净净。本来只打算住两天，没想到不知不觉，陆陆续续住了一个星期。不知道为什么会有人吐槽，酒店设施差？？明明就是要什么有什么，有健身房，游泳池，甚至有发廊，博物馆，还有四五个特色餐厅。基本上不出门都能品尝到广州的各式美食。总之有各种各样舒服且完善的服务。房间内风景也很不错，各种设施虽然不算很新，但至少是齐全便利的。这可是开了几十年的酒店啊，有一些设施比较老旧也正常吧（反正我觉得不老旧）。就是一个实打实的五星级酒店啊！如果我不是没那么奢侈（有钱），我可以在花园酒店住上一年哈哈哈哈哈哈。广州这个城市，有花园酒店真是太好了。中秋节还送了贺卡和下午茶（月饼）。最后，再次感谢服务过我的所有花园工作人员！下次还会继续选择住花园酒店！我爱花园！', '["https://dimg04.c-ctrip.com/images/0206312000c9w88zhBC42_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0201712000c9w9s973271_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0203112000c9w53bb5821_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0206a12000c9wix05EFEC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0206d12000c9wmza8886A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0201212000c9w7hioA694_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-28', '花园大床房', '大床房', '独自旅行', 395, 5.981414211254481, 0, 0.0, 4, 1.6094379124341005, 9, '["客房服务", "整体满意度", "公共设施"]'::jsonb, '客房服务', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '没住过服务这么好的酒店！！！每个服务人员，都非常贴心。包括每天打扫的阿姨！请重点', '没住过服务这么好的酒店！！！每个服务人员，都非常贴心。包括每天打扫的阿姨！请重点表扬这几天打扫2049房间的阿姨，谢谢！几乎每天都会换床品，把房间打扫得干干净净。本来只打算住两天，没想到不知不觉，陆陆续续住了一个星期。不知道为什么会有人吐槽，酒店设施差？？明明就是要什么有什么，有健身房，游泳池，甚至有发廊，博物馆，还有四五个特色餐厅。基本上不出门都能品尝到广州的各式美食。总之有各种各样舒服且完善的服务。房间内风景也很不错，各种设施虽然不算很新，但至少是齐全便利的。这可是开了几十年的酒店啊，有一些设施比较老旧也正常吧（反正我觉得不老旧）。就是一个实打实的五星级酒店啊！如果我不是没那么奢侈（有钱），我可以在花园酒店住上一年哈哈哈哈哈哈。广州这个城市，有花园酒店真是太好了。中秋节还送了贺卡和下午茶（月饼）。最后，再次感谢服务过我的所有花园工作人员！下次还会继续选择住花园酒店！我爱花园！', '2023-09-28', 5, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68027e16e3c98b0941765bba', '服务：非常惊喜的一次入住，名不虚传，酒店岭南风味十足，前台BETTY服务贴心，美中不足的是因为入住游客太多排队时间久，酒廊水果空了补充不及时。
设施：新装修客房很不错。房间空调温度难调，感觉清洗没有很勤。
环境：整个在花园中感觉，有设计美感。
卫生：客房、公区整体都很不错。
